﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿﻿// ========================================
// ⚠️ 警告：Math.random 已被重写！⚠️
// ========================================
// 原生 Math.random 已被自定义版本替换
// 
// 【可用的随机函数】
// - Math.random()        → 气运偏移后的随机数（游戏核心逻辑使用）
// - Math.randomNeutral() → 原生随机数（中性场景使用，如名称生成、日志文本等）
// - Math.randomOriginal  → 原生随机数函数引用（同 randomNeutral）
//
// 【气运偏移公式】
// 新随机数 = 原随机数 × 系数
// 系数 = 1 / (1 + 气运值 / 100)，范围 [0, 1]
// 气运越大，系数越小，随机数越倾向于小值（利于玩家）
//
// 【性能优化】
// 系数采用缓存机制，只在气运值变化时重新计算
// Math.random() 调用只做一次乘法，性能接近原生
//
// 【期望计算偏移】
// 对于概率判定 Math.random() < p，偏移后实际概率 = min(1, p / 系数)
// 使用 getQiYunProbability(p, qiYunValue) 获取偏移后的概率用于期望计算
//
// 【设置位置】
// 返虚路层数即为气运值，通过返虚路挑战提升
// ========================================
const _originalMathRandom = Math.random.bind(Math);
let _qiYunCoefficient = 1;

/**
 * 更新气运偏移系数（高性能缓存方案）
 * 只在返虚路层数变化时调用一次，之后所有 Math.random() 调用只做一次乘法
 * @param {number} [qiYunValue] - 气运值，不传则从返虚路层数获取
 */
function updateQiYunCoefficient(qiYunValue) {
    const qiYun = Number(qiYunValue ?? getFanXuLuFloor()) || 0;
    _qiYunCoefficient = 1 / (1 + qiYun / 100);
}

/**
 * 获取气运偏移系数（从缓存读取，无计算开销）
 * @returns {number} 当前缓存的气运偏移系数
 */
function getQiYunCoefficient() {
    return _qiYunCoefficient;
}

/**
 * 获取气运偏移后的概率
 * 用于期望计算，不影响随机性能
 * @param {number} p - 原始概率（0-1之间）
 * @param {number} [qiYunValue] - 气运值，不传则使用缓存系数
 * @returns {number} 偏移后的概率
 */
function getQiYunProbability(p, qiYunValue) {
    const coef = qiYunValue !== undefined 
        ? 1 / (1 + Number(qiYunValue) / 100)
        : _qiYunCoefficient;
    if (coef <= 0) return 1;
    return Math.min(1, p / coef);
}

Math.randomOriginal = _originalMathRandom;
Math.randomNeutral = _originalMathRandom;

/**
 * 高性能气运偏移随机数
 * 只做一次乘法，无函数嵌套、无分支判断
 * @returns {number} 气运偏移后的随机数 [0, 1)
 */
Math.random = function() {
    return _originalMathRandom() * _qiYunCoefficient;
};

// 高精度数学计算模块

// ========================================
// 使用 math.js 的 evaluate 函数进行高精度计算
// 避免原生 Number 类型的精度溢出问题
// ========================================

/**
 * 高精度计算函数
 * 使用 math.eval 计算表达式字符串，避免原生 Number 类型的精度溢出问题
 * @param {string} expr - 数学表达式字符串
 * @returns {string|number} 计算结果
 */
function $eval(expr) {
    return window.evalExpr ? window.evalExpr(expr) : eval(expr);
}

/**
 * 生成指定范围内的随机整数（受气运影响）
 * @param {number} min - 最小值（包含）
 * @param {number} max - 最大值（包含）
 * @returns {number} 范围内的随机整数
 */
function randomStep(min, max) {
    return Math.floor(Math.random() * (max - min + 1)) + min;
}

