/**
 * 高精度加法
 * @param {number|string} a - 加数
 * @param {number|string} b - 加数
 * @returns {string} 计算结果（字符串）
 */
function $addBig(a, b) {
    return $evalBig(`${a} + ${b}`);
}

/**
 * 高精度减法
 * @param {number|string} a - 被减数
 * @param {number|string} b - 减数
 * @returns {string} 计算结果（字符串）
 */
function $subBig(a, b) {
    return $evalBig(`${a} - ${b}`);
}

/**
 * 高精度乘法
 * @param {number|string} a - 乘数
 * @param {number|string} b - 乘数
 * @returns {string} 计算结果（字符串）
 */
function $mulBig(a, b) {
    return $evalBig(`${a} * ${b}`);
}

/**
 * 高精度除法
 * @param {number|string} a - 被除数
 * @param {number|string} b - 除数
 * @returns {string} 计算结果（字符串）
 */
function $divBig(a, b) {
    return $evalBig(`${a} / ${b}`);
}

/**
 * 高精度取模
 * @param {number|string} a - 被除数
 * @param {number|string} b - 除数
 * @returns {string} 计算结果（字符串）
 */
function $modBig(a, b) {
    return $evalBig(`${a} % ${b}`);
}

/**
 * 高精度取整
 * @param {number|string} a - 数值
 * @returns {string} 取整后的结果（字符串）
 */
function $truncBig(a) {
    return $evalBig(`trunc(${a})`);
}

/**
 * 高精度绝对值
 * @param {number|string} a - 数值
 * @returns {string} 绝对值（字符串）
 */
function $absBig(a) {
    return $evalBig(`abs(${a})`);
}

/**
 * 高精度四舍五入
 * @param {number|string} a - 数值
 * @returns {string} 四舍五入后的结果（字符串）
 */
function $roundBig(a) {
    return $evalBig(`round(${a})`);
}

/**
 * 高精度相等比较
 * @param {number|string} a - 数值a
 * @param {number|string} b - 数值b
 * @returns {boolean} a == b
 */
function $eqBig(a, b) {
    return $compareBig(a, b, '==');
}

/**
 * 高精度不等比较
 * @param {number|string} a - 数值a
 * @param {number|string} b - 数值b
 * @returns {boolean} a != b
 */
function $neqBig(a, b) {
    return $compareBig(a, b, '!=');
}

/**
 * 高精度通用比较函数
 * @param {number|string} a - 数值a
 * @param {number|string} b - 数值b
 * @param {string} op - 比较运算符（==, !=, >, <, >=, <=）
 * @returns {boolean} 比较结果
 */
function $compareBig(a, b, op) {
    if (a === null || a === undefined) a = 0;
    if (b === null || b === undefined) b = 0;
    try {
        const aStr = String(a);
        const bStr = String(b);
        const result = $evalBig(`${aStr} ${op} ${bStr}`);
        return result === 'true';
    } catch (e) {
        return false;
    }
}

/**
 * 高精度大于等于比较（调试版本）
 * @param {number|string} a - 数值a
 * @param {number|string} b - 数值b
 * @returns {Object} {a, b, result, bool} 包含详细调试信息
 */
function $gteBigDebug(a, b) {
    const aStr = String(a);
    const bStr = String(b);
    const result = $evalBig(`${aStr} >= ${bStr}`);
    const bool = result === 'true';
    if (!bool && result !== 'false') {
        console.warn('$gteBigDebug: unexpected result', { a: aStr, b: bStr, result, type: typeof result });
    }
    return { a: aStr, b: bStr, result, bool };
}

/**
 * 高精度大于等于比较
 * @param {number|string} a - 数值a
 * @param {number|string} b - 数值b
 * @returns {boolean} a >= b
 */
function $gteBig(a, b) {
    const aStr = String(a);
    const bStr = String(b);
    const result = $evalBig(`${aStr} >= ${bStr}`);
    return result === 'true';
}
/**
 * 高精度大于比较
 * @param {number|string} a - 数值a
 * @param {number|string} b - 数值b
 * @returns {boolean} a > b
 */
function $gtBig(a, b) { return $compareBig(a, b, '>'); }
/**
 * 高精度小于等于比较
 * @param {number|string} a - 数值a
 * @param {number|string} b - 数值b
 * @returns {boolean} a <= b
 */
function $lteBig(a, b) { return $compareBig(a, b, '<='); }
/**
 * 高精度小于比较
 * @param {number|string} a - 数值a
 * @param {number|string} b - 数值b
 * @returns {boolean} a < b
 */
function $ltBig(a, b) { return $compareBig(a, b, '<'); }







// 解析科学计数法字符串，返回尾数和指数的拆分对象
// 非科学计数法或无效输入返回null
/**
 * 解析科学计数法字符串
 * 将科学计数法拆分为尾数和指数
 * @param {number|string} str - 科学计数法字符串
 * @returns {Object|null} {mantissa, exp, mantissaStr, expStr} 或 null（非科学计数法）
 */
function parseScientificNotation(str) {
    if (str === null || str === undefined) return null;
    const s = String(str);
    if (s === 'NaN' || s === 'Infinity' || s === '-Infinity') return null;
    const match = s.match(/^(-?\d*\.?\d+)[eE]([+-]?\d+)$/);
    if (match) {
        return { mantissa: parseFloat(match[1]), exp: parseInt(match[2]), mantissaStr: match[1], expStr: match[2] };
    }
    return null;
}

/**
 * 高精度数字格式化
 * 支持科学计数法、超大数和小数的友好显示
 * 绝对值<=99999显示原值，超出则转为科学计数法（5位有效数字）
 * @param {number|string} num - 数值
 * @returns {string} 格式化后的字符串
 */
function formatPrecision(num) {
    if (num === null || num === undefined) return '0';
    const numStr = String(num);
    if (numStr === 'NaN' || numStr === 'Infinity' || numStr === '-Infinity') return numStr;

    const parsed = parseScientificNotation(numStr);
    if (parsed) {
        const value = parseFloat(numStr);
        if (Math.abs(value) <= 99999 && value !== 0) {
            return value.toFixed(2).replace(/\.?0+$/, '');
        }
        let exp = parsed.expStr;
        if (exp.startsWith('+')) exp = exp.substring(1);
        const mantissaStr = parsed.mantissa.toPrecision(5);
        return mantissaStr + 'e' + exp;
    }
    
    if (numStr.length > 15) {
        const absNum = window._nativeMath.abs(parseFloat(numStr));
        if (absNum <= 99999) {
            const val = parseFloat(numStr);
            return val.toFixed(2).replace(/\.?0+$/, '');
        }
        const firstDigits = numStr.replace('.', '').slice(0, 5);
        const exp = numStr.replace('.', '').length - numStr.indexOf('.');
        const mantissa = parseFloat(firstDigits) / 10000;
        return mantissa.toPrecision(5) + 'e' + exp;
    }
    
    const absNum = window._nativeMath.abs(parseFloat(numStr));
    if (absNum === 0) return '0';
    if (absNum >= 1e10 || absNum < 1e-5) {
        const exp = parseFloat(numStr).toExponential(4);
        return exp.replace(/e\+/, 'e');
    }
    const val = parseFloat(numStr);
    const rounded = Math.round(val * 10000) / 10000;
    if (Math.abs(val - rounded) < 0.00001) {
        return String(rounded);
    }
    return val.toFixed(4).replace(/\.?0+$/, '');
}

