const pillInfo = [
    { type: 'attack', name: '天元丹', effect: '攻击', value: 1, isPercent: false },
    { type: 'health', name: '淬体丹', effect: '生命', value: 10, isPercent: false },
    { type: 'defense', name: '固灵丹', effect: '防御', value: 1, isPercent: false },
    { type: 'critDamage', name: '暴神丹', effect: '暴伤', value: 30, isPercent: true },
    { type: 'critRate', name: '灵犀丹', effect: '暴击率', value: 1, isPercent: true },
    { type: 'breakthrough', name: '破境丹', effect: '突破成功率', value: 0.01, isPercent: true, multiply100: true }
];

const PILL_FULL_BONUS_MULTIPLIER = 6.81;

// 显示丹药详情弹窗，列出各品阶已服用数量、总加成和下一颗效果
// 同品阶丹药存在递减效应（每颗乘0.9，最低0.1倍）
function showPillDetail(pillType) {
    const pill = pillInfo.find(p => p.type === pillType);
    if (!pill) return;
    const firstCharPills = getFirstCharacterPills();
    const consumed = firstCharPills ? (firstCharPills[pill.type] || { total: 0, maxGrade: 0 }) : { total: 0, maxGrade: 0 };
    
    const total = consumed.total || 0;
    const maxGrade = consumed.maxGrade || 0;
    
    // 基础加成系数 = 0.1 * 服用次数
    const baseBonus = 0.1 * total;
    // 足额加成系数 = min(服用次数, 最高阶 * 20)
    const fullBonus = Math.min(total, maxGrade * PILL_FULL_BONUS_MULTIPLIER);
    const totalEffect = baseBonus + fullBonus;
    
    // 实际加成 = 系数 * value
    const actualBase = baseBonus * pill.value;
    const actualFull = fullBonus * pill.value;
    const actualTotal = totalEffect * pill.value;
    
    // 下颗加成：基础0.1 + 如果还在足额范围内则+1
    const nextBase = 0.1 * pill.value;
    const nextFull = (total < maxGrade * PILL_FULL_BONUS_MULTIPLIER) ? pill.value : 0;
    const nextEffect = nextBase + nextFull;

    let baseDisplay = actualBase.toFixed(1);
    let fullDisplay = actualFull.toFixed(0);
    let effectDisplay = actualTotal.toFixed(2);
    let nextDisplay = nextEffect.toFixed(2);
    if (pill.isPercent) {
        if (pill.multiply100) {
            baseDisplay = (actualBase * 100).toFixed(1) + '%';
            fullDisplay = (actualFull * 100).toFixed(0) + '%';
            effectDisplay = (actualTotal * 100).toFixed(1) + '%';
            nextDisplay = (nextEffect * 100).toFixed(1) + '%';
        } else {
            baseDisplay = actualBase.toFixed(1) + '%';
            fullDisplay = actualFull.toFixed(0) + '%';
            effectDisplay = actualTotal.toFixed(1) + '%';
            nextDisplay = nextEffect.toFixed(1) + '%';
        }
    }

    let detailHtml = `<span style="color:#ff0;">【 ${pill.name} 详情 】</span><br><br>`;
    detailHtml += `<span style="color:var(--text-color,#fff);">已服用: ${total} 颗</span><br>`;
    detailHtml += `<span style="color:var(--text-color,#fff);">最高阶位: ${maxGrade} 阶</span><br>`;
    detailHtml += `<span style="color:var(--text-color,#fff);">基础加成: ${baseDisplay}</span><br>`;
    detailHtml += `<span style="color:var(--text-color,#fff);">足额加成: ${fullDisplay}</span><br>`;
    detailHtml += `<span style="color:var(--text-color,#fff);">总加成: ${effectDisplay}</span><br>`;
    detailHtml += `<span style="color:var(--text-color,#fff);">下颗加成: +${nextDisplay}</span><br>`;

    showModal(detailHtml);
}

// 显示寰纪凝光详情弹窗
function showHuangjiDetail() {
    const huangjiCount = getFirstCharacterHuangjiCount();
    const divisor = 1 + huangjiCount;
    
    let detailHtml = `<span style="color:#ff0;">【 寰纪凝光 详情 】</span><br><br>`;
    detailHtml += `<span style="color:var(--text-color,#fff);">已服用: ${huangjiCount} 个</span><br>`;
    detailHtml += `<span style="color:var(--text-color,#fff);">消耗倍率: ÷ ${divisor}</span><br>`;
    detailHtml += `<span style="color:var(--text-color,#fff);">效果: 修炼和法则领悟消耗 ÷ (1 + 总数)</span><br>`;
    detailHtml += `<span style="color:var(--text-color,#fff);">说明: 所有角色共享</span><br>`;

    showModal(detailHtml);
}

// ========================================
// UI边框工具函数
// ========================================
// 动态计算边框宽度
// 根据容器实际宽度自适应字符数
function getBoxWidth() {
    const terminal = document.querySelector('.terminal');
    if (!terminal) return 20;
    
    const containerWidth = terminal.clientWidth - 20;
    const testElement = document.createElement('span');
    testElement.style.fontFamily = 'monospace';
    testElement.style.fontSize = '19px';
    testElement.style.visibility = 'hidden';
    testElement.textContent = '─'.repeat(50);
    document.body.appendChild(testElement);
    const charWidth = testElement.getBoundingClientRect().width / 50;
    document.body.removeChild(testElement);
    
    const maxChars = $floor(containerWidth / charWidth);
    return $max(20, $min(maxChars, 50));
}

// 内层边框宽度
// 返回比外层少2个字符
function getInnerBoxWidth() {
    return getBoxWidth() - 2;
}

// 动态生成外层边框
// 使用Unicode制表符创建美观的边框样式
function generateBox() {
    const width = getBoxWidth();
    return {
        top: '┌' + '─'.repeat(width) + '┐',      // 顶部边框：┌──────┐
        bottom: '└' + '─'.repeat(width) + '┘',   // 底部边框：└──────┘
        line: ''                                   // 中间行（预留）
    };
}

// 生成内层边框
// 用于嵌套显示的内部边框
function generateInnerBox() {
    const width = getInnerBoxWidth();
    return {
        top: '┌' + '─'.repeat(width) + '┐',      // 顶部边框
        bottom: '└' + '─'.repeat(width) + '┘',   // 底部边框
        left: '│',                                 // 左侧边框
        right: '│'                                 // 右侧边框
    };
}

// 更新HTML中的固定边框宽度
function updateHtmlBoxWidth() {
    const width = getBoxWidth();
    const boxChars = '─'.repeat(width);
    const top = '┌' + boxChars + '┐';
    const bottom = '└' + boxChars + '┘';
    
    document.querySelectorAll('.text-line').forEach(el => {
        const text = el.textContent;
        if (text.startsWith('┌') && text.endsWith('┐')) {
            el.textContent = top;
        } else if (text.startsWith('└') && text.endsWith('┘')) {
            el.textContent = bottom;
        }
    });
}

// 初始化边框对象（全局变量）
let box = generateBox();
let innerBox = generateInnerBox();

// ========================================
// 修炼系统核心函数
// ========================================
// 计算升级/突破所需灵气
// 寰纪凝光效果：修炼灵力需求 ÷ (1 + 个数)
function getRequiredCultivation(innerLevel) {
    const levelStr = String(innerLevel - 1);
    let cost;
    if ($gteBig(levelStr, '1e100')) {
        cost = $evalBig(`${levelStr} * 100`);
    } else {
        cost = $evalBig(`floor(100 * 1.3^${levelStr})`);
    }
    const huangjiCount = getFirstCharacterHuangjiCount();
    if (huangjiCount > 0) {
        cost = $evalBig(`${cost} / ${1 + huangjiCount}`);
    }
    return cost;
}

// 计算玩家属性（核心属性计算函数）
// 综合考虑：修炼等级、境界、法宝、丹药、法则领悟度
// calculateCultivationStats 缓存机制
const cultivationStatsCache = {
    key: null,
    result: null,
    valid: false
};

function getCultivationStatsCacheKey() {
    const firstCharPills = getFirstCharacterPills();
    const pillKey = JSON.stringify(firstCharPills || {});
    const mainBoundHerb = isCurrentCharMain() ? player.boundHerb : getFirstCharacterBoundHerb();
    return [
        player.innerLevel,
        player.realmIndex,
        player.laws.life,
        player.laws.strength,
        player.laws.order,
        player.laws.fate,
        player.laws.destruction,
        player.weapon.attackLevel,
        player.weapon.powerLevel,
        player.weapon.lawLevels.life,
        player.weapon.lawLevels.strength,
        player.weapon.lawLevels.order,
        player.weapon.lawLevels.fate,
        player.weapon.lawLevels.destruction,
        player.weapon.critRateLevel,
        player.weapon.critDamageLevel,
        player.benZhi,
        player.maxVoidVictoryLevel,
        player.boundHerb ? player.boundHerb.grade : 0,
        mainBoundHerb ? mainBoundHerb.grade : 0,
        pillKey
    ].join('|');
}

function calculateCultivationStats() {
    const cacheKey = getCultivationStatsCacheKey();
    if (cultivationStatsCache.valid && cultivationStatsCache.key === cacheKey) {
        const cached = cultivationStatsCache.result;
        player.maxHp = cached.maxHp;
        player.attack = cached.attack;
        player.defense = cached.defense;
        player.speed = cached.speed;
        player.criticalRate = cached.criticalRate;
        player.criticalDamage = cached.criticalDamage;
        player.power = cached.power;
        player.pillBreakthroughBonus = cached.pillBreakthroughBonus;
        return;
    }

    const innerLevel = player.innerLevel;
    const realmIndex = player.realmIndex;
    const weapon = player.weapon;

    const pillBonus = { attack: 0, health: 0, defense: 0, critDamage: 0, critRate: 0, breakthrough: 0 };
    const pillTypes = ['attack', 'health', 'defense', 'critDamage', 'critRate', 'breakthrough'];
    const firstCharPills = getFirstCharacterPills();

    pillTypes.forEach(type => {
        const consumed = firstCharPills ? (firstCharPills[type] || { total: 0, maxGrade: 0 }) : { total: 0, maxGrade: 0 };
        const total = consumed.total || 0;
        const maxGrade = consumed.maxGrade || 0;
        
        // 加成 = 0.1 * 服用次数 + min(服用次数, 最高服用的单位阶数 * 20)
        const totalBonus = 0.1 * total + Math.min(total, maxGrade * PILL_FULL_BONUS_MULTIPLIER);

        if (type === 'attack') pillBonus.attack = Number($floor(totalBonus * 1));
        if (type === 'health') pillBonus.health = Number($floor(totalBonus * 10));
        if (type === 'defense') pillBonus.defense = Number($floor(totalBonus * 1));
        if (type === 'critDamage') pillBonus.critDamage = totalBonus * 30;
        if (type === 'critRate') pillBonus.critRate = totalBonus * 1;
        if (type === 'breakthrough') pillBonus.breakthrough = totalBonus * 0.01;
    });

    const lawAwareness = {
        hp: $evalBig(`${player.laws.life} + ${weapon.lawLevels.life * 0.1}`),
        attack: $evalBig(`${player.laws.strength} + ${weapon.lawLevels.strength * 0.1}`),
        defense: $evalBig(`${player.laws.order} + ${weapon.lawLevels.order * 0.1}`),
        criticalRate: $evalBig(`${player.laws.fate} + ${weapon.lawLevels.fate * 0.1 + weapon.critRateLevel * 0.2}`),
        criticalDamage: $evalBig(`${player.laws.destruction} + ${weapon.lawLevels.destruction * 0.1}`)
    };

    const baseHp = 100 + innerLevel * 10 + pillBonus.health;
    const baseAttack = 10 + innerLevel * 1 + weapon.attackLevel * 1 + pillBonus.attack;
    const baseDefense = 5 + innerLevel * 0.5 + pillBonus.defense;
    const baseSpeed = 10 + innerLevel * 1;

    const mainBoundHerb = isCurrentCharMain() ? player.boundHerb : getFirstCharacterBoundHerb();
    const boundHerbBonus = mainBoundHerb ? mainBoundHerb.grade * 0.1 : 0;
    const power = (1 + innerLevel * 0.1) + weapon.powerLevel * 0.01 + boundHerbBonus;

    function calcAttribute(base, power, awareness) {
        const B = 28.79251121;
        const x = $addBig(String(power), $evalBig(`${awareness} / 10`));
        let exponent;
        if ($gteBig(x, String(B))) {
            exponent = $evalBig(`100 ^ (${x} - 7.940124601966075)`);
        } else {
            exponent = $evalBig(`max(1.2 ^ ${x}, (0.5 * ${x}) ^ (1.25 * ${x}))`);
        }
        const result = $evalBig(`floor(${base} * ${exponent})`);
        return result;
    }

    const benYuanHp = getBenYuanHpPower();
    const benYuanAtk = getBenYuanPower();
    const benYuanDef = getBenYuanDefPower();
    const benZhi = String(player.benZhi || '0');
    const benZhiAdjusted = $evalBig(`${benZhi} ^ 0.8`);
    const lgBenZhi = $log10($addBig(benZhiAdjusted, '1'));
    const benZhiBonus = $evalBig(`(1 + ${lgBenZhi} / (375 * 1.147)) ^ ${player.maxVoidVictoryLevel}`);
    const calcMaxHp = calcAttribute(baseHp, power, lawAwareness.hp);
    const calcAtk = calcAttribute(baseAttack, power, lawAwareness.attack);
    const calcDef = calcAttribute(baseDefense, power, lawAwareness.defense);

    player.maxHp = $evalBig(`${calcMaxHp} * ${benYuanHp} * ${benZhiBonus}`);
    player.attack = $evalBig(`${calcAtk} * ${benYuanAtk} * ${benZhiBonus}`);
    player.defense = $evalBig(`${calcDef} * ${benYuanDef} * ${benZhiBonus}`);
    player.speed = '100';

    const fateLevel = player.laws.fate || 1;
    const lgFate = $log10(String(fateLevel));
    player.criticalRate = $evalBig(`(${fateLevel} * ${lgFate}) / 2 + ${pillBonus.critRate + weapon.critRateLevel * 0.2}`);

    const destructionLevel = player.laws.destruction || 1;
    const lgDestruction = $log10(String(destructionLevel));
    player.criticalDamage = $evalBig(`(${destructionLevel} * ${lgDestruction}) * 20 + ${weapon.critDamageLevel * 10 + pillBonus.critDamage}`);
    player.power = power;
    player.pillBreakthroughBonus = pillBonus.breakthrough;

    cultivationStatsCache.result = {
        maxHp: player.maxHp,
        attack: player.attack,
        defense: player.defense,
        speed: player.speed,
        criticalRate: player.criticalRate,
        criticalDamage: player.criticalDamage,
        power: player.power,
        pillBreakthroughBonus: player.pillBreakthroughBonus
    };
    cultivationStatsCache.key = cacheKey;
    cultivationStatsCache.valid = true;
}

// ========================================
// 法则系统配置
// ========================================
// 法则配置表：定义五种法则及其效果
// 法则是修仙者领悟天地规则的能力，每种法则对应不同的属性加成
const laws = {
    life: { name: "生命法则", desc: "生命上限", key: "hp" },
    strength: { name: "力量法则", desc: "攻击", key: "attack" },
    order: { name: "秩序法则", desc: "防御", key: "defense" },
    fate: { name: "命运法则", desc: "暴击概率", key: "criticalRate" },
    destruction: { name: "毁灭法则", desc: "暴击伤害", key: "criticalDamage" }
};

// 计算法则碎片升级消耗
// 等级<1e100时: 10 * 1.25^等级；超过1e100时: 等级 * 10
// 寰纪凝光效果：消耗 ÷ (1 + 个数)
function getLawFragmentCost(level) {
    const levelStr = String(level);
    let cost;
    if ($gteBig(levelStr, '1e100')) {
        cost = $evalBig(`${levelStr} * 10`);
    } else {
        cost = $evalBig(`10 * 1.25^${levelStr}`);
    }
    const huangjiCount = getFirstCharacterHuangjiCount();
    if (huangjiCount > 0) {
        cost = $evalBig(`${cost} / ${1 + huangjiCount}`);
    }
    return cost;
}

// 升级法则领悟等级
// 消耗法则碎片提升法则等级
// 根据模式选择升级方式
function upgradeLaw(lawKey, silent = false) {
    const currentAwareness = String(player.laws[lawKey] || '0');

    if (player.lawAutoMax === 'instant') {
        // 直接升满模式：一次性计算
        const currentLevel = parseFloat(currentAwareness);
        
        // 寰纪凝光系数：消耗 ÷ (1 + 个数)，相当于资源 × (1 + 个数)
        const huangjiCount = getFirstCharacterHuangjiCount();
        const resourceMultiplier = 1 + huangjiCount;
        const effectiveResource = $evalBig(`${player.lawFragments} * ${resourceMultiplier}`);
        
        const { maxLevel, totalCost } = findMaxUpgradeLevelAndCost(currentLevel, effectiveResource, 10, 1.25);
        
        if (maxLevel <= currentLevel) {
            return;
        }
        
        // 实际消耗需要除以系数
        const actualCost = $evalBig(`${totalCost} / ${resourceMultiplier}`);
        player.lawFragments = $subBig(player.lawFragments, actualCost);
        player.laws[lawKey] = String(maxLevel);
        calculateCultivationStats();
        updateLawUI();
        updateStatusUI();
    } else if (player.lawAutoMax === 'gradual') {
        // 逐渐升级模式：循环升级
        const cost = getLawFragmentCost(currentAwareness);
        
        if ($gteBig(player.lawFragments, cost)) {
            player.lawFragments = $subBig(player.lawFragments, cost);
            player.laws[lawKey] = $addBig(currentAwareness, '1');
            calculateCultivationStats();
            updateLawUI();
            updateStatusUI();
            setTimeout(() => upgradeLaw(lawKey), 10);
        }
    } else {
        // 关闭模式：单次升级
        const cost = getLawFragmentCost(currentAwareness);
        
        if ($gteBig(player.lawFragments, cost)) {
            player.lawFragments = $subBig(player.lawFragments, cost);
            player.laws[lawKey] = $addBig(currentAwareness, '1');
            calculateCultivationStats();
            updateLawUI();
            updateStatusUI();
        } else {
            if (!silent) showResourceShortageModal('法则碎片', cost, player.lawFragments);
        }
    }
}

// 切换法则自动升级开关：off -> instant -> gradual -> off
function toggleLawAutoMax() {
    if (player.lawAutoMax === 'off') {
        player.lawAutoMax = 'instant';
    } else if (player.lawAutoMax === 'instant') {
        player.lawAutoMax = 'gradual';
    } else {
        player.lawAutoMax = 'off';
    }
    updateLawUI();
}

// 显示法则自动加点选择弹窗
function showLawAutoAddPointsModal() {
    const lawOptions = [
        { key: 'life', name: '生命法则', desc: '生命上限+20/级' },
        { key: 'strength', name: '力量法则', desc: '攻击力+2/级' },
        { key: 'order', name: '秩序法则', desc: '防御力+1/级' },
        { key: 'fate', name: '命运法则', desc: '暴击概率+1%/级' },
        { key: 'destruction', name: '毁灭法则', desc: '暴击伤害+5/级' }
    ];
    
    let checkboxesHtml = '';
    for (const opt of lawOptions) {
        const checked = player.lawAutoAddPointsList.includes(opt.key) ? 'checked' : '';
        checkboxesHtml += `
            <div style="display:flex;align-items:center;margin:8px 0;">
                <input type="checkbox" id="lawAuto_${opt.key}" ${checked} style="width:18px;height:18px;cursor:pointer;">
                <label for="lawAuto_${opt.key}" style="margin-left:8px;cursor:pointer;flex:1;">
                    <span style="color:#ff0;">${opt.name}</span>
                    <span style="color:#888;font-size:12px;">(${opt.desc})</span>
                </label>
            </div>
        `;
    }
    
    const modalHtml = `
        <div style="color:#ff0;font-size:16px;margin-bottom:15px;">法则自动加点设置</div>
        <div style="color:#888;font-size:12px;margin-bottom:10px;">选择要自动加点的法则属性，每3秒随机选择一个进行升级</div>
        ${checkboxesHtml}
        <div style="margin-top:20px;display:flex;gap:10px;justify-content:center;">
            <button onclick="saveLawAutoAddPointsSettings()" class="sbtn" style="padding:8px 20px;">确定</button>
            <button onclick="closeModal()" class="sbtn" style="padding:8px 20px;">取消</button>
        </div>
    `;
    
    showModal(modalHtml, true);
}

// 保存法则自动加点设置
function saveLawAutoAddPointsSettings() {
    const lawKeys = ['life', 'strength', 'order', 'fate', 'destruction'];
    player.lawAutoAddPointsList = [];
    
    for (const key of lawKeys) {
        const checkbox = document.getElementById(`lawAuto_${key}`);
        if (checkbox && checkbox.checked) {
            player.lawAutoAddPointsList.push(key);
        }
    }
    
    player.lawAutoAddPoints = player.lawAutoAddPointsList.length > 0;
    closeModal();
    updateLawUI();
    saveGameData();
}

// 执行法则自动加点（每10秒调用一次）
function executeLawAutoAddPoints() {
    if (!player.lawAutoAddPoints || player.lawAutoAddPointsList.length === 0) return;
    
    const list = player.lawAutoAddPointsList;
    const randomIndex = Math.floor(Math.random() * list.length);
    const selectedLaw = list[randomIndex];
    
    upgradeLaw(selectedLaw, true);
}

// 计算法则系统提供的属性加成
// 每个法则根据领悟等级(awareness/10取整)提供对应属性加成
function calculateLawStats() {
    let lawBonus = {
        hp: '0',
        attack: '0',
        defense: '0',
        criticalRate: '0',
        criticalDamage: '0',
        speed: '0'
    };
    
    for (let key in player.laws) {
        const awareness = String(player.laws[key] || 0);
        const level = $evalBig(`floor(${awareness} / 10)`);
        
        switch(key) {
            case 'life':
                lawBonus.hp = $addBig(lawBonus.hp, $evalBig(`${level} * 20`));
                break;
            case 'strength':
                lawBonus.attack = $addBig(lawBonus.attack, $evalBig(`${level} * 2`));
                break;
            case 'order':
                lawBonus.defense = $addBig(lawBonus.defense, level);
                break;
            case 'fate':
                lawBonus.criticalRate = $addBig(lawBonus.criticalRate, level);
                break;
            case 'destruction':
                lawBonus.criticalDamage = $addBig(lawBonus.criticalDamage, $evalBig(`${level} * 5`));
                break;
        }
    }
    
    return lawBonus;
}

