    alchemyAutoMaxGrade: 10,      // 全自动炼丹最高阶位
    alchemyAutoMaxCount: 10,     // 全自动炼丹最大数量
    alchemyAutoCraftedCount: 0,   // 全自动炼丹已炼制数量
