// ========================================
// 清除玩家数据到空白未登录状态
// ========================================
function clearPlayerData() {
    if (battleState.attackScheduler) {
        clearTimeout(battleState.attackScheduler);
        battleState.attackScheduler = null;
    }
    
    if (window.worldExpStuckChecker) {
        Scheduler.remove('worldExpStuckChecker');
        window.worldExpStuckChecker = null;
    }
    
    battleState.inBattle = false;
    battleState.battleEnding = false;
    battleState.paused = false;
    battleState.currentMap = 1;
    battleState.currentMonster = null;
    battleState.monsterHp = 0;
    battleState.monsterMaxHp = 0;
    battleState.battleLog = [];
    battleState.battleLogHidden = false;
    battleState.playerNextAttackTime = 0;
    battleState.monsterNextAttackTime = 0;
    battleState.originalMaxHp = null;
    battleState.lastActionTime = 0;
    battleState.lastLogTime = 0;
    battleState.monsterSkills = [];
    battleState.monsterSkillStates = {
        youLiangXiaZiActive: false,
        huiGuangFanZhaoUsed: false,
        huiGuangFanZhaoActive: false,
        huiGuangFanZhaoEndTime: 0,
        shuSiYiBoUsed: false
    };
    battleState.hitTarget = null;
    battleState.lastBattleMonster = null;
    battleState.lastBattlePlayerHp = null;
    battleState.lastBattlePlayerMaxHp = null;
    battleState.lastBattleMonsterHp = null;
    battleState.phase = 0;
    battleState.turn = 0;
    battleState.enemies = [];
    battleState.player = null;
    
    window.worldExpState = null;
    window.worldExpInBackground = false;
    window.worldExpOriginalBattleContent = null;
    window.worldExpBattleSpeed = 0;
    window.worldExpBattleMax = false;
    window.worldExpBattleGeneration = 0;
    window.worldExpLogScrollTop = undefined;
    window.worldExpContentScrollTop = undefined;
    window.worldExpLastHeartbeat = 0;
    window.worldExpLastKillCount = 0;
    window.worldExpLastEnemyCount = 0;
    window.pendingWorldExpState = null;
    window._needReloadPageAfterImport = false;
    window._isImportingFile = false;
    
    player = { ...defaultPlayer };
    player.lastSaveTime = Date.now();
}

// ========================================
// 保存游戏数据到本地存储
// ========================================
function saveGameData() {
    player.lastSaveTime = Date.now();
    
    if (window.worldExpState && !window.worldExpState.battleEnded) {
        const state = window.worldExpState;
        player.worldExpState = {
            enemyCount: state.enemyCount,
            killCount: state.killCount || 0,
            playerDeathCount: state.playerDeathCount || 0,
            worldName: state.worldName
        };
        const battleData = {
            deadPlayerKills: state.deadPlayerKills || [],
            deadEnemyKills: state.deadEnemyKills || []
        };
        localStorage.setItem('worldExpBattleData', JSON.stringify(battleData));
    } else if (window.worldExpState && window.worldExpState.battleEnded) {
        delete player.worldExpState;
        localStorage.removeItem('worldExpBattleData');
    }
    
    // 自动模式状态不存入存档，刷新后自动关闭
    const savedVoidAutoBattle = player.voidAutoBattle;
    const savedVoidAutoPhase = player.voidAutoPhase;
    const savedVoidAutoInitDepth = player.voidAutoInitDepth;
    const savedVoidAutoInitLeft = player.voidAutoInitLeft;
    const savedVoidAutoInitRight = player.voidAutoInitRight;
    const savedVoidAutoMaxSuccessDepth = player.voidAutoMaxSuccessDepth;
    const savedVoidAutoPrevMonsterHp = player.voidAutoPrevMonsterHp;
    const savedVoidAutoInstakillAttackCount = player.voidAutoInstakillAttackCount;
    
    player.voidAutoBattle = 'off';
    player.voidAutoPhase = 'init';
    player.voidAutoInitDepth = 0;
    player.voidAutoInitLeft = 0;
    player.voidAutoInitRight = 0;
    player.voidAutoMaxSuccessDepth = 0;
    player.voidAutoPrevMonsterHp = 0;
    player.voidAutoInstakillAttackCount = 0;
    
    // 化身不应有 huangjiCount 属性，保存前删除
    const charList = getCharacterList();
    const mainChar = charList[0];
    const currentCharId = getCurrentCharId();
    if (mainChar && mainChar.id !== currentCharId && player.huangjiCount !== undefined) {
        delete player.huangjiCount;
    }
    
    const saveData = JSON.stringify(player);
    localStorage.setItem(getCharacterSaveKey(currentCharId), saveData);
    
    // 恢复自动模式状态到内存中
    player.voidAutoBattle = savedVoidAutoBattle;
    player.voidAutoPhase = savedVoidAutoPhase;
    player.voidAutoInitDepth = savedVoidAutoInitDepth;
    player.voidAutoInitLeft = savedVoidAutoInitLeft;
    player.voidAutoInitRight = savedVoidAutoInitRight;
    player.voidAutoMaxSuccessDepth = savedVoidAutoMaxSuccessDepth;
    player.voidAutoPrevMonsterHp = savedVoidAutoPrevMonsterHp;
    player.voidAutoInstakillAttackCount = savedVoidAutoInstakillAttackCount;
}

// ========================================
// 加载游戏数据
// ========================================
// 从本地存储加载游戏数据
// 包含存档兼容性处理，确保旧存档可以正常使用

// 存档数据迁移函数，处理旧版本存档的兼容性
// 包括：神通数据补全、法则碎片对象转数值、废弃time法则清理、武器新字段默认值、作弊模块兼容、本源/道兵兼容性
function migrateSaveData(merged) {
//    if (merged.qiYun === undefined || merged.qiYun === null) {
//        merged.qiYun = 1;
//    }
    
    try {
        if (!merged.divineAbilities) {
            merged.divineAbilities = { ...defaultPlayer.divineAbilities };
        } else {
            Object.keys(defaultPlayer.divineAbilities).forEach(key => {
                if (!merged.divineAbilities[key]) {
                    merged.divineAbilities[key] = { ...defaultPlayer.divineAbilities[key] };
                } else if (typeof merged.divineAbilities[key].level === 'undefined') {
                    merged.divineAbilities[key].level = 0;
                }
                if (!merged.divineAbilities[key].name) {
                    merged.divineAbilities[key].name = defaultPlayer.divineAbilities[key].name;
                }
            });
        }
    } catch (e) {
        merged.divineAbilities = { ...defaultPlayer.divineAbilities };
    }

    try {
        if (typeof merged.lawFragments === 'object' && merged.lawFragments !== null) {
            let totalFragments = 0;
            Object.values(merged.lawFragments).forEach(val => {
                totalFragments += (typeof val === 'number' ? val : 0);
            });
            merged.lawFragments = String(totalFragments);
        } else {
            merged.lawFragments = String(merged.lawFragments || 0);
        }
    } catch (e) {
        merged.lawFragments = '0';
    }

    try {
        if (merged.laws && merged.laws.time !== undefined) {
            delete merged.laws.time;
        }
    } catch (e) {
        merged.laws = { ...defaultPlayer.laws };
    }

    try {
        if (!merged.weapon) {
            merged.weapon = { ...defaultPlayer.weapon };
        } else {
            if (merged.weapon.attackLevel === undefined) merged.weapon.attackLevel = 0;
            if (merged.weapon.critDamageLevel === undefined) merged.weapon.critDamageLevel = 0;
            if (merged.weapon.critRateLevel === undefined) merged.weapon.critRateLevel = 0;
            if (!merged.weapon.weaponName) merged.weapon.weaponName = "青木剑";
            if (!merged.weapon.bookName) merged.weapon.bookName = "青木长生经";
        }
    } catch (e) {
        merged.weapon = { ...defaultPlayer.weapon };
    }

    try {
        if (!merged.cheat) {
            merged.cheat = { offlineMultiplier: 1 };
        }
        if (merged.cheat.offlineMultiplier === undefined) {
            merged.cheat.offlineMultiplier = 1;
        }
        if (merged.showCheatModule === undefined) {
            merged.showCheatModule = false;
        }
    } catch (e) {
        merged.cheat = { offlineMultiplier: 1 };
        merged.showCheatModule = false;
    }

    try {
        if (typeof merged.benYuan === 'object' && merged.benYuan !== null) {
            let total = 0;
            for (const key in merged.benYuan) {
                total += merged.benYuan[key];
            }
            merged.benYuan = total;
        }
        if (merged.daoBing !== undefined) {
            merged.benYuan = merged.daoBing;
            delete merged.daoBing;
        }
        if (merged.benYuan === undefined || merged.benYuan === null || merged.benYuan === '') {
            merged.benYuan = 0;
        } else if (typeof merged.benYuan === 'string') {
            // 字符串类型保持不变（高精度大数）
        } else if (typeof merged.benYuan !== 'number' || isNaN(merged.benYuan)) {
            merged.benYuan = 0;
        }
        if (merged.benZhi === undefined || merged.benZhi === null || merged.benZhi === '') {
            merged.benZhi = 0;
        } else if (typeof merged.benZhi === 'string') {
            // 字符串类型保持不变（高精度大数）
        } else if (typeof merged.benZhi !== 'number' || isNaN(merged.benZhi) || merged.benZhi < 0) {
            merged.benZhi = 0;
        }
    } catch (e) {
        merged.benYuan = 0;
        merged.benZhi = 0;
    }

    // lawAutoMax 兼容性处理：true/false -> 'off'/'instant'/'gradual'
    if (merged.lawAutoMax === true) {
        merged.lawAutoMax = 'instant';
    } else if (merged.lawAutoMax === false || merged.lawAutoMax === undefined) {
        merged.lawAutoMax = 'off';
    }

    // treasureAutoMax 兼容性处理：true/false -> 'off'/'instant'/'gradual'
    if (merged.treasureAutoMax === true) {
        merged.treasureAutoMax = 'instant';
    } else if (merged.treasureAutoMax === false || merged.treasureAutoMax === undefined) {
        merged.treasureAutoMax = 'off';
    }
    
    // 自动加点变量兼容性处理
    if (merged.lawAutoAddPoints === undefined) {
        merged.lawAutoAddPoints = false;
    }
    if (merged.lawAutoAddPointsList === undefined) {
        merged.lawAutoAddPointsList = [];
    }
    if (merged.treasureAutoAddPoints === undefined) {
        merged.treasureAutoAddPoints = false;
    }
    if (merged.treasureAutoAddPointsList === undefined) {
        merged.treasureAutoAddPointsList = [];
    }
    if (merged.autoUpgrade === undefined) {
        merged.autoUpgrade = false;
    }
    if (merged.autoWorldExp === undefined) {
        merged.autoWorldExp = false;
    }
    merged.autoWorldExp = false;
    if (merged.autoWorldExpBackDepth === undefined) {
        merged.autoWorldExpBackDepth = 0;
    }
    if (merged.autoWorldExpPhase === undefined) {
        merged.autoWorldExpPhase = 'idle';
    }
    merged.autoWorldExpPhase = 'idle';
    if (merged.autoSelectHighestHerb === undefined) {
        merged.autoSelectHighestHerb = false;
    }
}

// 从本地存储加载游戏数据
// 解析存档并与默认数据合并，处理各种兼容性问题后初始化游戏
function loadGameData() {
    let charId = getCurrentCharId();
    let saveKey = getCharacterSaveKey(charId);
    let saveData = localStorage.getItem(saveKey);
    let isOldSaveMigrated = false;

    // 兼容旧版存档：如果新key没有数据，尝试旧key
    if (!saveData) {
        saveData = localStorage.getItem('wenziguaji_save');
        if (saveData) {
            // 迁移旧存档到新系统
            localStorage.setItem(saveKey, saveData);
            isOldSaveMigrated = true;
        }
    }

    // 确保当前角色在角色列表中
    const list = getCharacterList();
    if (!list.find(c => c && c.id === charId)) {
        // 确定槽位索引
        let slotIndex = 0;
        if (charId === 'char_1') slotIndex = 0;
        else if (charId === 'char_2') slotIndex = 1;
        else if (charId === 'char_3') slotIndex = 2;
        else if (charId === 'char_4') slotIndex = 3;
        
        if (saveData) {
            try {
                const data = JSON.parse(saveData);
                list[slotIndex] = { id: charId, name: data.name || '角色名称' };
            } catch (e) {
                list[slotIndex] = { id: charId, name: '角色名称' };
            }
        } else {
            list[slotIndex] = { id: charId, name: '角色名称' };
        }
        saveCharacterList(list);
    }
    
    if (saveData) {
        try {
            const loaded = JSON.parse(saveData);  // 解析存档数据
            
            // 合并默认数据，确保新增字段存在（兼容旧版本存档）
            const merged = { ...defaultPlayer, ...loaded };
            
            // ========================================
            // 灵石仙石向下取整（兼容旧存档）
            // ========================================
            if (merged.spiritStone) {
                merged.spiritStone = $floor(String(merged.spiritStone));
            }
            if (merged.immortalStone) {
                merged.immortalStone = $floor(String(merged.immortalStone));
            }

            // ========================================
            // 环境灵气溢出修复（兼容旧存档）
            // ========================================
            if (merged.vein === 'Infinity' || merged.vein === Infinity || merged.vein === null || merged.vein === undefined) {
                merged.vein = '0';
            }

            // ========================================
            // 神通数据兼容性处理
            // ========================================
            // 深度合并 divineAbilities，确保每个神通都有默认值
            if (loaded.divineAbilities) {
                merged.divineAbilities = {
                    ...defaultPlayer.divineAbilities,
                    ...loaded.divineAbilities
                };
                // 确保每个神通都有完整的结构
                Object.keys(defaultPlayer.divineAbilities).forEach(key => {
                    if (!merged.divineAbilities[key]) {
                        // 如果神通不存在，使用默认值
                        merged.divineAbilities[key] = { ...defaultPlayer.divineAbilities[key] };
                    } else if (typeof merged.divineAbilities[key].level === 'undefined') {
                        // 如果等级未定义，设为0
                        merged.divineAbilities[key].level = 0;
                    }
                    if (!merged.divineAbilities[key].name) {
                        // 如果名称未定义，使用默认名称
                        merged.divineAbilities[key].name = defaultPlayer.divineAbilities[key].name;
                    }
                });
            }
            
            // ========================================
            // 灵田数据兼容性处理
            // ========================================
            // 为旧存档中的灵田灵药添加 growth 字段
            if (merged.spiritField) {
                merged.spiritField.forEach(item => {
                    if (item) {
                        if (item.growth === undefined) {
                            if (item.plantTime) {
                                const fieldSpeedBonus = $pow('0.96', $subBig('0', String(merged.spiritFieldLevel || 0)));
                                const elapsed = $evalBig(`(Date.now() - ${item.plantTime}) * ${fieldSpeedBonus} / 1000`);
                                item.growth = elapsed;
                            } else {
                                item.growth = 0;
                            }
                        }
                        delete item.plantTime;
                    }
                });
                
                if (!merged.spiritFieldGroundPower) {
                    merged.spiritFieldGroundPower = [0, 0, 0, 0, 0, 0, 0, 0, 0];
                }
            }
            
            // ========================================
            // 丹炉数据兼容性处理
            // ========================================
            // 兼容旧存档的丹炉数据
            if (!merged.alchemyFurnace) {
                merged.alchemyFurnace = [null, null, null, null, null, null, null, null, null];
            }
            if (merged.alchemyFurnaceLevel === undefined) {
                merged.alchemyFurnaceLevel = 1;
            }
            if (!merged.consumedPills) {
                // 初始化丹药服用记录
                merged.consumedPills = {
                    attack: { total: 0, maxGrade: 0 },
                    health: { total: 0, maxGrade: 0 },
                    defense: { total: 0, maxGrade: 0 },
                    critDamage: { total: 0, maxGrade: 0 },
                    critRate: { total: 0, maxGrade: 0 },
                    breakthrough: { total: 0, maxGrade: 0 }
                };
            }
            // 兼容旧版本数据结构
            const pillTypes = ['attack', 'health', 'defense', 'critDamage', 'critRate', 'breakthrough'];
            pillTypes.forEach(type => {
                if (!merged.consumedPills[type]) {
                    merged.consumedPills[type] = { total: 0, maxGrade: 0 };
                } else if (typeof merged.consumedPills[type].total !== 'number') {
                    // 旧版本结构转换
                    const oldData = merged.consumedPills[type];
                    let total = 0;
                    let maxGrade = 0;
                    for (const grade in oldData) {
                        if (oldData[grade] > 0) {
                            total += oldData[grade];
                            maxGrade = Math.max(maxGrade, parseInt(grade));
                        }
                    }
                    merged.consumedPills[type] = { total, maxGrade };
                }
            });
            if (merged.alchemyTargetPill === undefined) {
                merged.alchemyTargetPill = null;
            }
            
            // ========================================
            // 本源/道兵兼容性处理
            // daoBing 是旧版本字段名，benYuan 是新版本
            // ========================================
            // 先处理 benYuan 为对象格式的旧存档（计算总数）
            if (typeof merged.benYuan === 'object' && merged.benYuan !== null) {
                let total = 0;
                for (const key in merged.benYuan) {
                    total += merged.benYuan[key];
                }
                merged.benYuan = total;
            }
            // daoBing 是更旧的字段名，优先从 daoBing 迁移
            if (loaded.daoBing !== undefined) {
                merged.benYuan = loaded.daoBing;
                delete merged.daoBing;
            }
            // 确保 benYuan 是有效数值（支持字符串类型的大数）
            if (merged.benYuan === undefined || merged.benYuan === null || merged.benYuan === '') {
                merged.benYuan = 0;
            } else if (typeof merged.benYuan === 'string') {
                // 字符串类型保持不变（高精度大数）
            } else if (typeof merged.benYuan !== 'number' || isNaN(merged.benYuan)) {
                merged.benYuan = 0;
            }
            // 确保 benZhi 是有效数值（支持字符串类型的大数）
            if (merged.benZhi === undefined || merged.benZhi === null || merged.benZhi === '') {
                merged.benZhi = 0;
            } else if (typeof merged.benZhi === 'string') {
                // 字符串类型保持不变（高精度大数）
            } else if (typeof merged.benZhi !== 'number' || isNaN(merged.benZhi) || merged.benZhi < 0) {
                merged.benZhi = 0;
            }

            // ========================================
            // 其他字段兼容性处理
            // ========================================
            // 虚空系统兼容性
            if (merged.voidDepth === undefined) {
                merged.voidDepth = 1;           // 虚空深度默认为1
            }
            if (merged.voidAutoBattle === undefined || typeof merged.voidAutoBattle === 'boolean') {
                merged.voidAutoBattle = merged.voidAutoBattle === true ? 'deepen' : 'off';
            }
            if (merged.voidAutoPrevMonsterHp === undefined) {
                merged.voidAutoPrevMonsterHp = 0;
            }
            if (merged.voidAutoInstakillAttackCount === undefined) {
                merged.voidAutoInstakillAttackCount = 0;
            }
            if (merged.voidAutoPhase === undefined) {
                merged.voidAutoPhase = 'init';
            }
            if (merged.voidAutoInitDepth === undefined) {
                merged.voidAutoInitDepth = 0;
            }
            if (merged.voidAutoInitLeft === undefined) {
                merged.voidAutoInitLeft = 0;
            }
            if (merged.voidAutoInitRight === undefined) {
                merged.voidAutoInitRight = 0;
            }
            if (merged.voidAutoMaxSuccessDepth === undefined) {
                merged.voidAutoMaxSuccessDepth = 0;
            }
            if (merged.maxVoidVictoryLevel === undefined) {
                merged.maxVoidVictoryLevel = 0;  // 无尽虚空最高深度默认为0
            }
            
            // ========================================
            // 寰纪凝光合并处理（化身合并到本体）
            // ========================================
            // 只在本体加载时执行一次合并，遍历所有角色存档
            const charList = getCharacterList();
            const mainChar = charList[0];
            if (mainChar && mainChar.id === charId) {
                // 当前是本体，遍历所有化身合并 huangjiCount
                const mainOriginalCount = merged.huangjiCount || 0;
                let totalCount = mainOriginalCount;
                for (let i = 1; i < charList.length; i++) {
                    const otherChar = charList[i];
                    if (!otherChar || !otherChar.id) continue;
                    const otherSaveKey = getCharacterSaveKey(otherChar.id);
                    const otherDataStr = localStorage.getItem(otherSaveKey);
                    if (otherDataStr) {
                        try {
                            const otherData = JSON.parse(otherDataStr);
                            if (otherData.huangjiCount !== undefined && otherData.huangjiCount > 0) {
                                totalCount += otherData.huangjiCount;
                            }
                            // 删除化身的 huangjiCount 属性
                            delete otherData.huangjiCount;
                            localStorage.setItem(otherSaveKey, JSON.stringify(otherData));
                        } catch (e) {
                            // 忽略错误
                        }
                    }
                }
                merged.huangjiCount = totalCount;
                // 立即更新本体的 localStorage，确保 UI 能读取到正确值
                const mainSaveKey = getCharacterSaveKey(charId);
                const mainDataStr = localStorage.getItem(mainSaveKey);
                if (mainDataStr) {
                    try {
                        const mainData = JSON.parse(mainDataStr);
                        mainData.huangjiCount = totalCount;
                        localStorage.setItem(mainSaveKey, JSON.stringify(mainData));
                    } catch (e) {
                        // 忽略错误
                    }
                }
                // 立即更新本体的 localStorage，确保 UI 能读取到正确值
            } else if (mainChar && mainChar.id !== charId) {
                // 当前是化身，删除 huangjiCount 属性（已合并到本体）
                delete merged.huangjiCount;
            }
            
            if (merged.realDianHuaTime === undefined && merged.dianHuaTime) {
                merged.realDianHuaTime = merged.dianHuaTime;  // 兼容旧存档，将dianHuaTime作为realDianHuaTime
            }
            // 灵田和背包系统兼容性
            if (merged.spiritFieldLevel === undefined) {
                merged.spiritFieldLevel = 0;    // 灵田等级默认为0
            }
            if (merged.highestHerbGrade === undefined) {
                merged.highestHerbGrade = 1;    // 历史最高灵药等阶默认为1
            }
            if (merged.bagLevel === undefined) {
                merged.bagLevel = 0;            // 背包等级默认为0
            }
            if (merged.bagAutoSort === undefined) {
                merged.bagAutoSort = false;     // 背包自动整理默认关闭
            }
            if (merged.autoAddAuxiliary === undefined) {
                merged.autoAddAuxiliary = false; // 自动添加辅助材料默认关闭
            }

            // ========================================
            // 背包物品 grade 类型统一（兼容旧存档）
            // ========================================
            // 将 bag 中的 grade 统一转换为数字类型
            if (merged.bag && Array.isArray(merged.bag)) {
                merged.bag.forEach(item => {
                    if (item && item.grade !== undefined) {
                        item.grade = Number(item.grade);
                    }
                });
            }
            // 将 neitiandiPending.herbs 中的 grade 统一转换为数字类型
            if (merged.neitiandiPending && merged.neitiandiPending.herbs && Array.isArray(merged.neitiandiPending.herbs)) {
                merged.neitiandiPending.herbs.forEach(item => {
                    if (item && item.grade !== undefined) {
                        item.grade = Number(item.grade);
                    }
                });
            }
            
            // ========================================
            // 数据修复处理
            // ========================================
            // 修复旧存档的破境丹加成（旧版本数值过大，需要除以100）
            if (merged.pillBreakthroughBonus !== undefined && merged.pillBreakthroughBonus > 0.1) {
                merged.pillBreakthroughBonus = merged.pillBreakthroughBonus / 100;
            }
            
            // 兼容旧存档的lawFragments格式（从对象转为数值）
            // 旧版本法则碎片按类型分开存储，新版本合并为单一数值
            if (typeof merged.lawFragments === 'object' && merged.lawFragments !== null) {
                let totalFragments = 0;
                Object.values(merged.lawFragments).forEach(val => {
                    totalFragments += (typeof val === 'number' ? val : 0);
                });
                merged.lawFragments = String(totalFragments);  // 合并所有类型的法则碎片
            } else {
                merged.lawFragments = String(merged.lawFragments || 0);
            }
            
            // 移除已废弃的time法则（旧版本存在，新版本已移除）
            if (merged.laws && merged.laws.time !== undefined) {
                delete merged.laws.time;
            }
            
            // ========================================
            // 法宝系统兼容性处理
            // ========================================
            // 兼容旧存档的weapon新字段
            if (merged.weapon) {
                if (merged.weapon.attackLevel === undefined) merged.weapon.attackLevel = 0;
                if (merged.weapon.critDamageLevel === undefined) merged.weapon.critDamageLevel = 0;
                if (merged.weapon.critRateLevel === undefined) merged.weapon.critRateLevel = 0;
                if (!merged.weapon.weaponName) merged.weapon.weaponName = "青木剑";
                if (!merged.weapon.bookName) merged.weapon.bookName = "青木长生经";
            }
            
            // ========================================
            // 作弊模块兼容性处理（共享设置）
            // ========================================
            // 兼容旧存档的cheat对象和showCheatModule
            if (!merged.cheat) {
                merged.cheat = { offlineMultiplier: 1 };
            }
            if (merged.cheat.offlineMultiplier === undefined) {
                merged.cheat.offlineMultiplier = 1;
            }
            if (merged.showCheatModule === undefined) {
                merged.showCheatModule = false;
            }
            
            // ========================================
            // 世界探索次数兼容性处理
            // ========================================
            if (merged.worldExploreCount === undefined) {
                merged.worldExploreCount = 10;
            }
            if (merged.lastWorldExploreResetDate === undefined) {
                merged.lastWorldExploreResetDate = null;
            }

            // ========================================
            // 数值属性类型统一（确保字符串类型）
            // ========================================
            // 将数值属性统一转换为字符串类型，避免类型混乱
            const stringProps = ['hp', 'maxHp', 'attack', 'defense', 'speed', 'criticalRate', 'criticalDamage', 'benYuan', 'benZhi'];
            stringProps.forEach(prop => {
                if (merged[prop] !== undefined && merged[prop] !== null) {
                    merged[prop] = String(merged[prop]);
                } else {
                    merged[prop] = defaultPlayer[prop] || '0';
                }
            });

            checkCultivationUpgrade(merged);
            merged.id = charId;

            // 初始化气运值（返虚路层数）
            // fanXuLuFloor 存储在主角色上
            {
                const charList = getCharacterList();
                const mainChar = charList[0];
                if (mainChar) {
                    if (mainChar.id === charId && merged.fanXuLuFloor !== undefined) {
                        // 当前是主角色，直接读取
                        currentFanxuFloor = merged.fanXuLuFloor;
                    } else if (mainChar.id !== charId) {
                        // 当前是化身，从主角色存档中读取
                        const mainSaveKey = getCharacterSaveKey(mainChar.id);
                        const mainDataStr = localStorage.getItem(mainSaveKey);
                        if (mainDataStr) {
                            try {
                                const mainData = JSON.parse(mainDataStr);
                                if (mainData.fanXuLuFloor !== undefined) {
                                    currentFanxuFloor = mainData.fanXuLuFloor;
                                }
                            } catch (e) {}
                        }
                    }
                }
            }
            // 加载存档后更新气运系数缓存
            updateQiYunCoefficient();

            // 注意：不要在这里更新 lastSaveTime，否则会导致离线时间变成0
            // 离线结算会在 processAllCharactersOfflineRewards 中更新 lastSaveTime
            // 自动炼丹状态也在离线结算中重置
            return merged;
        } catch (e) {
            // 存档解析失败，返回默认数据
            console.error('加载存档失败:', e);
            return { ...defaultPlayer };
        }
    }
    
    return { ...defaultPlayer, id: charId };
}

