// ========================================
// 离线结算系统
// ========================================
// 处理当前角色的离线收益
function processAllCharactersOfflineRewards() {
    const currentCharId = getCurrentCharId();
    const now = Date.now();

    const saveKey = getCharacterSaveKey(currentCharId);
    const charDataStr = localStorage.getItem(saveKey);
    if (!charDataStr) return;

    try {
        const charData = JSON.parse(charDataStr);

        // 重置自动炼丹状态，防止异常退出后保持运行状态
        charData.alchemyAutoMode = 'off';
        charData.alchemyAutoCraftedCount = 0;

        const lastSave = charData.lastSaveTime || now;
        const offlineSeconds = $floor((now - lastSave) / 1000);

        if (offlineSeconds < 5) return;

        const result = processOfflineRewards(charData, true);

        if (result && result.rewards && result.rewards.length > 0) {
            const offlineRewards = [{
                name: charData.name || '当前角色',
                messages: result.rewards,
                offlineSeconds: result.effectiveOfflineSeconds,
                battleStats: result.battleStats,
                autoCollectNeitiandi: result.autoCollectNeitiandi
            }];
            showAllCharactersOfflineModal(offlineRewards);
        }

        charData.lastSaveTime = now;
        localStorage.setItem(saveKey, JSON.stringify(charData));
        
        if (typeof player !== 'undefined') {
            Object.assign(player, charData);
        }
    } catch (e) {
        console.error('处理离线收益异常:', e);
    }
}

// 计算单个角色的离线收益（简化版，已废弃，保留备用）
function calculateOfflineRewards(playerData, offlineSeconds) {
    const messages = [];
    const now = Date.now();
    const lastSave = playerData.lastSaveTime || now;
    const intervalMs = now - lastSave;
    const intervals = $floor(intervalMs / 1000);

    if (intervals <= 0) return { messages };

    // 灵田收益
    if (playerData.veggies) {
        const spiritVeggieCount = playerData.veggies.filter(v => v.type === 'spiritVeggie').length;
        if (spiritVeggieCount > 0 && playerData.vein !== '0') {
            const veinNum = toNumber(playerData.vein);
            if (veinNum > 0) {
                const spiritVeggieRate = $mul($pow(1.5, spiritVeggieCount), 0.1);
                const spiritVeggieGain = $floor($mul($mul($mul(veinNum, spiritVeggieRate), spiritVeggieCount), intervals));
                if (toNumber(spiritVeggieGain) > 0) {
                    playerData.vein = $sub(playerData.vein, spiritVeggieGain);
                    playerData.vein = String(Math.max(0, toNumber(playerData.vein)));
                    messages.push(`灵田产出: +${formatNumber(spiritVeggieGain)} 灵气`);
                }
            }
        }
    }

    // 洞府灵气收益
    if (playerData.dongfuSpiritPerSec && toNumber(playerData.dongfuSpiritPerSec) > 0) {
        const spiritGain = $floor($mul(playerData.dongfuSpiritPerSec, intervals));
        if (toNumber(spiritGain) > 0) {
            playerData.vein = $add(playerData.vein, spiritGain);
            messages.push(`洞府修炼: +${formatNumber(spiritGain)} 灵气`);
        }
    }

    // 修炼收益
    if (playerData.cultivationBase && toNumber(playerData.cultivationBase) > 0) {
        const cultivationGain = $floor($mul(playerData.cultivationBase, intervals));
        if (toNumber(cultivationGain) > 0) {
            const prevCultivation = playerData.cultivation;
            playerData.cultivation = $add(playerData.cultivation, cultivationGain);
            messages.push(`修炼: +${formatNumber(cultivationGain)} 灵力`);
        }
    }

    // 离线时间格式化
    const hours = Math.floor(offlineSeconds / 3600);
    const minutes = Math.floor((offlineSeconds % 3600) / 60);
    const offlineText = hours > 0 ? `${hours}小时${minutes}分钟` : `${minutes}分钟`;

    return { messages, offlineText };
}

// 关闭离线弹窗并重新加载当前角色数据
function reloadCurrentCharacterData() {
    const charId = getCurrentCharId();
    const saveKey = getCharacterSaveKey(charId);
    const charDataStr = localStorage.getItem(saveKey);
    
    if (charDataStr) {
        try {
            const charData = JSON.parse(charDataStr);
            Object.assign(player, charData);
            
            calculateCultivationStats();
            updateplayernameUI();
            updateStatusUI();
            updateBattleUI();
            updateCultivationUI();
            updateWeaponUI();
            updateBagUI();
            updateEquipmentUI();
        } catch (e) {
            console.error('重新加载角色数据失败:', e);
        }
    }
}

// 显示当前角色离线收益弹窗
function showAllCharactersOfflineModal(allRewards) {
    const charReward = allRewards[0];
    let html = '<div style="width:80vw;height:80vh;display:flex;flex-direction:column;">';
    html += '<div style="text-align:center;margin-bottom:15px;"><span style="color:#ff0;font-size:18px;">【 离线收益报告 】</span></div>';
    html += `<div style="text-align:center;margin-bottom:15px;"><button onclick="closeModal();location.reload();" class="sbtn-gr">确定</button></div>`;
    
    html += '<div style="flex:1;overflow-y:auto;padding-right:5px;">';
    html += `<div style="text-align:center;color:#888;margin-bottom:15px;padding:10px;background:rgba(0,0,0,0.3);border-radius:8px;">离线时间: <span style="color:#4fc3f7;">${formatOfflineTime(charReward.offlineSeconds || 0)}</span></div>`;
    
    // 显示内天地自动领取状态
    if (charReward.autoCollectNeitiandi) {
        html += `<div style="text-align:center;color:#4a6;margin-bottom:15px;padding:10px;background:rgba(0,0,0,0.3);border-radius:8px;">内天地自动领取: <span style="color:#4fc3f7;">已开启</span></div>`;
    }
    
    const spiritRewards = charReward.messages.filter(r => r.includes('仙脉') || r.includes('环境灵气') || r.includes('灵力'));
    const voidRewards = charReward.messages.filter(r => r.includes('内天地'));
    const battleRewards = charReward.messages.filter(r => (r.includes('战斗') || r.includes('天材') || r.includes('法则') || r.includes('仙石') || r.includes('灵石') || r.includes('灵药')) && !r.includes('仙脉') && !r.includes('内天地'));
    const otherRewards = charReward.messages.filter(r => !spiritRewards.includes(r) && !voidRewards.includes(r) && !battleRewards.includes(r));
    
    if (spiritRewards.length > 0) {
        html += `<div style="margin-bottom:20px;padding:15px;border:1px solid #444;border-radius:8px;">`;
        html += `<div style="margin-bottom:12px;font-weight:bold;">✨ 产出</div>`;
        spiritRewards.forEach(msg => {
            html += `<div style="margin:6px 0;">• ${msg}</div>`;
        });
        html += `</div>`;
    }
    
    if (voidRewards.length > 0) {
        html += `<div style="margin-bottom:20px;padding:15px;border:1px solid #444;border-radius:8px;">`;
        html += `<div style="margin-bottom:12px;font-weight:bold;">🌌 内天地</div>`;
        voidRewards.forEach(msg => {
            html += `<div style="margin:6px 0;">• ${msg}</div>`;
        });
        html += `</div>`;
    }
    
    if (battleRewards.length > 0) {
        html += `<div style="margin-bottom:20px;padding:15px;border:1px solid #444;border-radius:8px;">`;
        html += `<div style="margin-bottom:12px;font-weight:bold;">⚔️ 战斗掉落</div>`;
        battleRewards.forEach(msg => {
            const herbIcon = msg.includes('灵药') ? '🌿 ' : '';
            html += `<div style="margin:6px 0;">• ${herbIcon}${msg}</div>`;
        });
        if (charReward.battleStats) {
            html += `<div style="margin-top:12px;padding-top:12px;border-top:1px solid #444;">`;
            html += `<div style="margin-bottom:8px;font-weight:bold;color:#f0f;">【 战斗结算 】</div>`;
            html += `<div style="margin:4px 0;">• 预估战斗 ${charReward.battleStats.battleCount} 场</div>`;
            html += `<div style="margin:4px 0;">• 平均怪物等级: ${charReward.battleStats.avgLevel}</div>`;
            html += `<div style="margin:4px 0;">• 平均战斗时间: ${charReward.battleStats.avgDuration}秒</div>`;
            html += `</div>`;
        }
        html += `</div>`;
    }
    
    if (otherRewards.length > 0) {
        html += `<div style="margin-bottom:20px;padding:15px;border:1px solid #444;border-radius:8px;">`;
        html += `<div style="margin-bottom:12px;font-weight:bold;">📦 其他</div>`;
        otherRewards.forEach(msg => {
            html += `<div style="margin:6px 0;">• ${msg}</div>`;
        });
        html += `</div>`;
    }
    
    if (charReward.messages.length === 0) {
        html += `<div style="text-align:center;color:#666;padding:30px;">无离线收益</div>`;
    }
    html += '</div>';
    html += '</div>';
    showModal(html, true);
}

// 离线结算
// 计算玩家离线期间的各种收益（修炼、灵田、战斗等）
// 参数: playerData - 玩家数据, returnOnly - 是否只返回结果不显示弹窗, forceOfflineSeconds - 强制指定的离线秒数（用于时间结晶等）
function processOfflineRewards(playerData, returnOnly = false, forceOfflineSeconds = null) {
    const now = Date.now();
    const lastSave = playerData.lastSaveTime || now;
    const actualOfflineSeconds = $floor((now - lastSave) / 1000);
    
    // 如果强制指定了离线时间，使用指定时间；否则使用实际离线时间
    const offlineSeconds = forceOfflineSeconds !== null ? forceOfflineSeconds : actualOfflineSeconds;

    // 离线时间少于5秒不结算（强制指定时间除外）
    if (forceOfflineSeconds === null && offlineSeconds < 5) return returnOnly ? { rewards: [], effectiveOfflineSeconds: 0 } : undefined;
    
    // ========================================
    // 离线时间计算
    // ========================================
    // 最大计算30天，防止数值溢出
    const maxOfflineSeconds = 30 * 24 * 60 * 60; // 30天 = 2592000秒
    const offlineMult = playerData.cheat?.offlineMultiplier || 1;  // 离线收益倍率
    const effectiveOfflineSeconds = forceOfflineSeconds !== null ? offlineSeconds : $min(offlineSeconds * offlineMult, maxOfflineSeconds);
    
    const offlineHours = effectiveOfflineSeconds / 3600;
    const offlineMinutes = effectiveOfflineSeconds / 60;
    
    let rewards = [];
    
    const oldVein = playerData.vein;
    const offlineCultivation = $evalBig(`floor(${calculateOfflineCultivation(playerData, effectiveOfflineSeconds)})`);
    const veinChange = $subBig(playerData.vein, oldVein);
    if ($gteBig(offlineCultivation, '1')) {
        const prevCultivation = playerData.cultivation;
        playerData.cultivation = $addBig(playerData.cultivation, offlineCultivation);
        rewards.push(`灵力 +${formatNumber(offlineCultivation)}`);
    }
    if (!$lteBig(veinChange, '0')) {
        rewards.push(`环境灵气 +${formatNumber(veinChange)}`);
    } else if ($gteBig(veinChange, '0')) {
        rewards.push(`环境灵气 ${formatNumber(veinChange)}`);
    }
    
    // 离线结算后检查升级状态
    checkCultivationUpgrade(playerData);
    
    // ========================================
    // 灵田系统离线结算
    // ========================================
    // 灵田灵药成长离线结算
    const herbResult = processOfflineHerbGrowth(playerData, effectiveOfflineSeconds);
    if (herbResult.totalUpgrades > 0) {
        let herbText = `灵药升阶 x${herbResult.totalUpgrades}`;
        if (herbResult.upgradedItems.length > 0) {
            herbText += ` (${herbResult.upgradedItems.map(i => `${i.name}${i.grade}阶`).join(', ')})`;
        }
        rewards.push(herbText);
    }
    
    // ========================================
    // 仙脉离线结算
    // ========================================
    const offlineSpiritStones = $evalBig(`floor(${calculateOfflineSpiritStones(playerData)})`);
    if ($gteBig(offlineSpiritStones, '1')) {
        playerData.spiritStone = $addBig(playerData.spiritStone, offlineSpiritStones);
        rewards.push(`仙脉产灵石 +${formatNumber(offlineSpiritStones)}`);
    }
    
    // ========================================
    // 战斗系统离线结算
    // ========================================
    // 根据战斗历史计算掉落
    if (playerData.battleHistory && playerData.battleHistory.length > 0) {
        const battleRewards = calculateOfflineBattleRewards(playerData, effectiveOfflineSeconds);
        if (battleRewards.items.length > 0) {
            battleRewards.items.forEach(item => {
                const existingItem = playerData.bag.find(bagItem => 
                    bagItem.name === item.name && bagItem.grade === item.grade
                );
                if (existingItem) {
                    existingItem.count = $addBig(existingItem.count, item.count);
                } else {
                    playerData.bag.push(item);
                }
                
                if (item.grade > playerData.highestHerbGrade) {
                    playerData.highestHerbGrade = item.grade;
                }
            });
            // 生成灵药掉落统计文本
            let herbText = `灵药 x${battleRewards.totalCount}`;
            const herbCounts = {};
            battleRewards.items.forEach(item => {
                const key = `${item.name}${item.grade}阶`;
                const count = typeof item.count === 'string' ? $evalBig(item.count) : item.count;
                herbCounts[key] = (herbCounts[key] || 0) + count;
            });
            const herbDetails = Object.entries(herbCounts).map(([name, count]) => `${name}x${formatLawLevel(count)}`);
            if (herbDetails.length > 0) {
                herbText += ` (${herbDetails.join(', ')})`;
            }
            rewards.push(herbText);
        }
        // 灵石奖励
        playerData.spiritStone = $addBig(playerData.spiritStone, String(battleRewards.spiritStones));
        if ($gtBig(battleRewards.spiritStones, 0)) {
            rewards.push(`灵石 +${formatNumber(battleRewards.spiritStones)}`);
        }
        playerData.immortalStone = $addBig(playerData.immortalStone, String(battleRewards.immortalStones));
        if ($gtBig(battleRewards.immortalStones, 0)) {
            rewards.push(`仙石 +${formatNumber(battleRewards.immortalStones)}`);
        }
        playerData.treasure = $addBig(playerData.treasure, String(battleRewards.treasure));
        if ($gtBig(battleRewards.treasure, 0)) {
            rewards.push(`天材地宝 +${formatNumber(battleRewards.treasure)}`);
        }
        // 法则碎片奖励
        if (battleRewards.lawFragments > 0) {
            playerData.lawFragments = $addBig(playerData.lawFragments, battleRewards.lawFragments);
            rewards.push(`法则碎片 +${formatNumber(battleRewards.lawFragments)}`);
        }
        // 时间结晶奖励
        if (battleRewards.timeCrystals > 0) {
            const existingCrystal = playerData.bag.find(item => item.name === '时间结晶' && item.grade === 1);
            if (existingCrystal) {
                existingCrystal.count = $addBig(existingCrystal.count, String(battleRewards.timeCrystals));
            } else {
                playerData.bag.push({ name: '时间结晶', grade: 1, count: String(battleRewards.timeCrystals) });
            }
            rewards.push(`时间结晶 +${battleRewards.timeCrystals}`);
        }
    }

    // ========================================
    // 内天地离线收益结算
    // ========================================
    // 注意：本源是全局共享资源，存储在主角存档中，需要从主角获取
    const offlineBenYuan = getFirstCharacterBenYuan();
    if (offlineBenYuan && $gtBig(String(offlineBenYuan), '0') && playerData.realmIndex >= 4) {
        const monsterLevel = playerData.maxVoidVictoryLevel + 500;
        const count = String(offlineBenYuan);
        const shengLingCount = String(playerData.shengLing || 0);
        const lgVal = $log10($addBig(shengLingCount, '10'));
        const lgCubed = $pow(lgVal, '3');
        const multiplier = $evalBig(`${lgCubed} / 3.3333`);

        const offlineMinutes = $floor(effectiveOfflineSeconds / 60);
        const incomeCycles = offlineMinutes;

        if (incomeCycles > 0) {
            const stoneBase = calcStoneBase(monsterLevel);
            const qiYun = getFanXuLuFloor() || 0;


            const probSpirit = getQiYunProbability(0.01, qiYun);
            const probImmortal = getQiYunProbability(0.0002, qiYun);
            const probLaw = getQiYunProbability(0.05, qiYun);
            const probHerb = getQiYunProbability(0.01, qiYun);
            const spiritStoneIncome = $floor($evalBig(`${stoneBase} * ${probSpirit} * ${multiplier} * ${incomeCycles}`));
            const immortalStoneIncome = $floor($evalBig(`${stoneBase} * ${probImmortal} * ${multiplier} * ${incomeCycles}`));
            const treasureIncome = $floor($evalBig(`${$pow(1.0339, monsterLevel)} * 10 * ${multiplier} * ${incomeCycles}`));
            const lawFragmentsIncome = $floor($evalBig(`${$pow(1.0339, monsterLevel)} * 5 * ${probLaw} * ${multiplier} * ${incomeCycles}`));

            if ($gtBig(spiritStoneIncome, '0')) {
                playerData.spiritStone = $addBig(playerData.spiritStone, spiritStoneIncome);
                rewards.push(`内天地灵石 +${formatNumber(spiritStoneIncome)}`);
            }
            if ($gtBig(immortalStoneIncome, '0')) {
                playerData.immortalStone = $addBig(playerData.immortalStone, immortalStoneIncome);
                rewards.push(`内天地仙石 +${formatNumber(immortalStoneIncome)}`);
            }
            if ($gtBig(treasureIncome, '0')) {
                playerData.treasure = $addBig(playerData.treasure, treasureIncome);
                rewards.push(`内天地天材地宝 +${formatNumber(treasureIncome)}`);
            }
            if ($gtBig(lawFragmentsIncome, '0')) {
                playerData.lawFragments = $addBig(playerData.lawFragments, lawFragmentsIncome);
                rewards.push(`内天地法则碎片 +${formatNumber(lawFragmentsIncome)}`);
            }

            const herbCount = $floor($evalBig(`${multiplier} * ${probHerb} * ${incomeCycles}`));
            if (herbCount > 0) {
                const herbGrades = calcHerbGrades(monsterLevel, herbCount, 2);
                const immortalHerbs = ['虚无空冥草', '先天一炁芝', '鸿蒙初形花', '混元真质蕊', '两仪混沌莲'];
                const herbNames = Array.from({ length: herbCount }, () => immortalHerbs[Math.floor(Math.randomNeutral() * immortalHerbs.length)]);
                const herbCounts = {};

                Object.entries(herbGrades).forEach(([grade, count]) => {
                    const gradeNum = Number(grade);
                    for (let i = 0; i < count; i++) {
                        const herbName = herbNames.pop();
                        const key = `${herbName}${gradeNum}阶`;
                        herbCounts[key] = (herbCounts[key] || 0) + 1;
                        const existingItem = playerData.neitiandiPending.herbs.find(item => item.name === herbName && item.grade === gradeNum);
                        if (existingItem) {
                            existingItem.count = $addBig(existingItem.count, '1');
                        } else {
                            playerData.neitiandiPending.herbs.push({ name: herbName, grade: gradeNum, count: '1' });
                        }
                        if (gradeNum > playerData.highestHerbGrade) {
                            playerData.highestHerbGrade = gradeNum;
                        }
                    }
                });
                Object.entries(herbCounts).forEach(([key, cnt]) => {
                    rewards.push(`内天地灵药 ${key} x${formatLawLevel(cnt)}`);
                });
            }
            
            // 灵族离线收益
            const shengLingIncome = $evalBig(`${count} / 1440 * ${incomeCycles}`);
            if ($gtBig(shengLingIncome, '0')) {
                const currentShengLing = String(playerData.shengLing || '0');
                const maxShengLing = count;
                const canAdd = $subBig(maxShengLing, currentShengLing);
                const actualIncome = $gtBig(canAdd, '0') ? $min(shengLingIncome, canAdd) : '0';
                if ($gtBig(actualIncome, '0')) {
                    playerData.shengLing = $addBig(currentShengLing, actualIncome);
                    rewards.push(`灵族 +${formatNumber($floor(actualIncome))}`);
                }
            }
        }
    }

    // ========================================
    // 自动领取内天地收益（开启时）
    // ========================================
    if (playerData.autoCollectNeitiandi) {
        const pending = playerData.neitiandiPending;
        if (pending) {
            // 领取灵石
            if ($gtBig(pending.spiritStone, '0')) {
                playerData.spiritStone = $addBig(playerData.spiritStone, pending.spiritStone);
                pending.spiritStone = '0';
            }

            // 领取仙石
            if ($gtBig(pending.immortalStone, '0')) {
                playerData.immortalStone = $addBig(playerData.immortalStone, pending.immortalStone);
                pending.immortalStone = '0';
            }

            // 领取天材地宝
            if ($gtBig(pending.treasure, '0')) {
                playerData.treasure = $addBig(playerData.treasure, pending.treasure);
                pending.treasure = '0';
            }

            // 领取法则碎片
            if ($gtBig(pending.lawFragments, '0')) {
                playerData.lawFragments = $addBig(playerData.lawFragments, pending.lawFragments);
                pending.lawFragments = '0';
            }

            // 领取灵药
            if (pending.herbs && pending.herbs.length > 0) {
                pending.herbs.forEach(herb => {
                    const existingItem = playerData.bag.find(item => item.name === herb.name && item.grade === herb.grade);
                    if (existingItem) {
                        existingItem.count = $addBig(existingItem.count, herb.count);
                    } else {
                        playerData.bag.push({ name: herb.name, grade: herb.grade, count: herb.count });
                    }
                    if (herb.grade > playerData.highestHerbGrade) {
                        playerData.highestHerbGrade = herb.grade;
                    }
                });
                pending.herbs = [];
            }

            pending.lastCollectTime = Date.now();
        }
    }
    
    // ========================================
    // 战斗统计信息（排除世界攻略模式，只统计胜利的战斗）
    // ========================================
    const history = playerData.battleHistory ? playerData.battleHistory.filter(h => !h.isWorldExp && h.win !== false).slice(-10) : [];
    let battleStats = null;
    if (history.length > 0) {
        const avgLevel = parseFloat($evalBig(`${history.reduce((sum, h) => $addBig(String(sum), String(h.level)), '0')} / ${history.length}`)).toFixed(1);
        const avgDuration = Math.max(1, parseFloat($evalBig(`${history.reduce((sum, h) => $addBig(String(sum), String(h.duration)), '0')} / ${history.length}`))).toFixed(1);
        const battleCount = $floor($evalBig(`${effectiveOfflineSeconds} / ${avgDuration}`));
        battleStats = {
            battleCount: formatNumber(battleCount),
            avgLevel: formatNumber($floor(avgLevel)),
            avgDuration: avgDuration
        };
    }
    
    // ========================================
    // 显示离线奖励弹窗或返回结果
    // ========================================
    if (returnOnly) {
        if (typeof MetaSystems !== 'undefined' && effectiveOfflineSeconds >= 3600) {
            MetaSystems.onOfflineReturn(effectiveOfflineSeconds);
        }
        return { rewards, effectiveOfflineSeconds, battleStats, autoCollectNeitiandi: playerData.autoCollectNeitiandi };
    }
    
    if (typeof MetaSystems !== 'undefined' && effectiveOfflineSeconds >= 3600) {
        MetaSystems.onOfflineReturn(effectiveOfflineSeconds);
    }
    
    // 显示离线奖励
    if (rewards.length > 0) {
        // 分类奖励：产出类和战斗掉落类
        const spiritRewards = rewards.filter(r => r.includes('仙脉') || r.includes('环境灵气') || r.includes('灵力') || r.includes('灵药') || r.includes('灵族'));
        const voidRewards = rewards.filter(r => r.includes('内天地'));
        const battleRewards = rewards.filter(r => (r.includes('战斗') || r.includes('天材') || r.includes('法则') || r.includes('仙石') || r.includes('灵石') || r.includes('灵药')) && !r.includes('仙脉') && !r.includes('内天地'));
        
        // 延迟500ms显示弹窗，确保游戏界面已加载
        setTimeout(() => {
            let content = `<span style="color:#ff0;">【 离线奖励 】</span><br><br>
                <button onclick="closeModal();location.reload();" class="sbtn" style="background:#11D65D">领取</button>
                <br><br>
                离线时间: ${formatOfflineTime(effectiveOfflineSeconds)}<br><br>`;
            
            // 显示产出类奖励
            if (spiritRewards.length > 0) {
                content += `<span style="color:#afa;">【 产出 】</span><br>• ${spiritRewards.join('<br>• ')}<br><br>`;
            }
            
            // 显示内天地类奖励
            if (voidRewards.length > 0) {
                content += `<span style="color:#faf;">【 内天地 】</span><br>• ${voidRewards.join('<br>• ')}<br><br>`;
            }
            
            // 显示战斗掉落类奖励
            if (battleRewards.length > 0) {
                content += `<span style="color:#afa;">【 战斗掉落 】</span><br>• ${battleRewards.join('<br>• ')}<br>`;
            }
            
            // 显示战斗统计
            if (battleStats) {
                content += `<br>【 战斗结算 】<br>• 预估战斗 ${battleStats.battleCount} 场<br>• 平均怪物等级: ${battleStats.avgLevel}<br>• 平均战斗时间: ${battleStats.avgDuration}秒`;
            }
            
            showModal(content, true);
        }, 500);
    }
}

// ========================================
// 离线灵力计算函数
// ========================================
// 计算离线灵力增长（考虑环境灵气）
// 灵力增长受聚灵阵等级、灵药位阶、灵脉产出、内天地修炼速度加成等因素影响
function calculateOfflineCultivation(playerData, offlineSeconds) {
    // ========================================
    // 灵压计算
    // ========================================
    // 灵压 = 1.07^聚灵阵等级 * 1.05^灵药位阶和
    // 灵压决定每秒吸收的灵气量
    let nodeBonus = 0;
    playerData.arrayNodes.forEach(node => {
        nodeBonus += node.grade;  // 累加所有阵法节点的灵药阶位
    });
    const spiritPressure = $evalBig(`${$pow('1.07', String(playerData.gatheringArrayLevel))} * ${$pow('1.05', String(nodeBonus))}`);

    // ========================================
    // 内天地修炼速度加成
    // 任何时候：1 + lg(本源 + 1)
    // 化神后：额外加上生灵加成
    // 注意：本源存储在本体角色中，需要从本体角色获取
    const benYuanCount = Number($floor(getFirstCharacterBenYuan() || 0));
    const shengLingCount = Number($floor(playerData.shengLing || 0));
    const lgBonus = $addBig('1', $log10($addBig(String(benYuanCount), '1')));
    let neitiandiSpeedBonus = lgBonus;
    if (playerData.realmIndex >= 4 && shengLingCount > 0) {
        const boundHerb = getFirstCharacterBoundHerb();
        const boundHerbGrade = boundHerb?.grade || 0;
        const exponent = calcNeitiandiLevel(boundHerbGrade);
        const logArg = $evalBig(`500 + ${shengLingCount}`);
        const logValue = $evalBig(`${$log10(logArg)} / ${$log10('500')}`);
        const baseBonus = $addBig('1', $evalBig(`0.0135039 * (1 - 1 / (${logValue} ^ 11 + 1))`));
        const complexBonus = $pow(baseBonus, String(exponent));
        neitiandiSpeedBonus = $addBig(lgBonus, complexBonus);
    }

    const absorbPerSecond = $evalBig(`${spiritPressure} * ${neitiandiSpeedBonus}`);  // 每秒吸收灵气量（含修炼速度加成）

    // ========================================
    // 灵田加成计算
    // ========================================
    // 每个格子：1.05^阶位 - 1，9个格子相加后加1
    let fieldMultiplier = '1';
    playerData.spiritField.forEach(item => {
        if (item && item.grade > 0) {
            const slotBonus = $subBig($pow('1.05', String(item.grade)), '1');
            fieldMultiplier = $addBig(fieldMultiplier, slotBonus);
        }
    });

    // ========================================
    // 灵脉产出计算
    // ========================================
    // 灵脉产出环境灵气：使用等比数列求和公式（考虑0.99995衰减和灵田加成）
    // 每10秒产出：veinStone * 0.2 * 加成 / 6，每10秒衰减：0.99995
    // 公式：veinStone * 0.2 * 加成 / 6 * (1 - 0.99995^周期数) / (1 - 0.99995)
    const offlineCycles = $floor(offlineSeconds / 10);
    let veinProduction = '0';
    if ($gteBig(playerData.veinStone, '0.001') && offlineCycles > 0) {
        veinProduction = $evalBig(`${playerData.veinStone} * 0.2 * ${fieldMultiplier} / 6 * (1 - 0.99995 ^ ${offlineCycles}) / (1 - 0.99995)`);
    }

    const totalCultivation = $evalBig(`${absorbPerSecond} * ${offlineSeconds}`);
    const requiredVein = String(totalCultivation);

    const totalVein = $addBig(playerData.vein, veinProduction);

    if ($gteBig(totalVein, requiredVein)) {
        playerData.vein = $subBig(totalVein, requiredVein);
    } else {
        playerData.vein = '0';
    }

    if ($gteBig(playerData.veinStone, '0.001') && offlineCycles > 0) {
        playerData.veinStone = $evalBig(`${playerData.veinStone} * 0.99995 ^ ${offlineCycles}`);
    }

    return $gteBig(totalVein, requiredVein) ? totalCultivation : totalVein;
}

// ========================================
// 离线灵石产出计算
// ========================================
// 计算仙脉离线灵石产出
// 仙脉(immortalVeinStone)产出灵石，每10秒: immortalVeinStone * 0.01 / 6
function calculateOfflineSpiritStones(playerData) {
    const offlineSeconds = (Date.now() - playerData.lastSaveTime) / 1000;
    const offlineMult = playerData.cheat?.offlineMultiplier || 1;
    const effectiveOfflineCycles = $floor(offlineSeconds * offlineMult / 10);
    if (effectiveOfflineCycles <= 0) return '0';
    
    const immortalVeinStone = playerData.immortalVeinStone || '0';
    const production = $evalBig(`${immortalVeinStone} * 0.01 / 6 * ${effectiveOfflineCycles}`);
    return production;
}

// ========================================
// 离线战斗奖励计算
// ========================================
// 计算离线战斗奖励
// 根据战斗历史模拟离线期间的战斗掉落
function calculateOfflineBattleRewards(playerData, offlineSeconds) {
    const history = playerData.battleHistory.filter(h => !h.isWorldExp).slice(-10);
    if (history.length === 0) return { items: [], spiritStones: 0, totalCount: 0, immortalStones: 0, treasure: 0, lawFragments: 0, battleCount: 0, avgLevel: 0, timeCrystals: 0 };
    
    // ========================================
    // 战斗统计计算
    // ========================================
    // 计算平均等级和平均耗时
    const avgLevel = history.reduce((sum, h) => sum + Number(h.level), 0) / history.length;
    const avgDuration = Math.max(1, history.reduce((sum, h) => sum + Number(h.duration), 0) / history.length);
    
    // 计算离线期间可以打多少场战斗
    const battleCount = parseFloat($floor(offlineSeconds / avgDuration));
    
    // ========================================
    // 掉落计算（使用数学期望，受气运影响）
    // ========================================
    const items = [];           // 掉落物品列表
    let totalCount = 0;         // 物品总数量
    let spiritStones = 0;       // 灵石掉落
    let immortalStones = 0;     // 仙石掉落
    let treasure = 0;           // 天材地宝掉落
    let lawFragments = 0;       // 法则碎片掉落
    let timeCrystals = 0;       // 时间结晶掉落（仅世界攻略）
    
    const monsterLevel = avgLevel;
    const qiYun = getFanXuLuFloor() || 0;


    const probSpirit = getQiYunProbability(0.01, qiYun);
    const probImmortal = getQiYunProbability(0.0002, qiYun);
    const probLaw = getQiYunProbability(0.05, qiYun);
    const probHerb = getQiYunProbability(0.01, qiYun);

    // 灵石掉落：气运偏移概率(1%)，新公式 1.03^x / min(128, 1.03^x / 1.02^x)
    const spiritStoneBase = calcStoneBase(monsterLevel);
    spiritStones = $floor($evalBig(`${battleCount} * ${probSpirit} * ${spiritStoneBase}`));

    // 仙石掉落：气运偏移概率(0.02%)，新公式 1.03^x / min(128, 1.03^x / 1.02^x)
    immortalStones = $floor($evalBig(`${battleCount} * ${probImmortal} * ${spiritStoneBase}`));
    
    // 天材地宝掉落：100%概率（每场战斗必得）
    treasure = $floor($evalBig(`${battleCount} * ${$pow(1.0339, monsterLevel)} * 10`));
    
    // 法则碎片掉落：气运偏移概率(5%)，数学期望 = battleCount * probLaw * 1.0339^等级 * 5
    lawFragments = $floor($evalBig(`${battleCount} * ${probLaw} * ${$pow(1.0339, monsterLevel)} * 5`));
    
    // 时间结晶：普通战斗每6000场获得1个（受气运影响）
    timeCrystals = calcTimeCrystalsExpectation(battleCount, 6000, qiYun);
    
    // 灵药掉落：数量用数学期望，批量计算阶位
    const herbCount = $floor($evalBig(`${battleCount} * ${probHerb}`));

    if (herbCount > 0) {
        const herbGrades = calcHerbGrades(monsterLevel, herbCount);
        const immortalHerbs = ['虚无空冥草', '先天一炁芝', '鸿蒙初形花', '混元真质蕊', '两仪混沌莲'];
        const herbNames = Array.from({ length: herbCount }, () => immortalHerbs[Math.floor(Math.randomNeutral() * immortalHerbs.length)]);

        Object.entries(herbGrades).forEach(([grade, count]) => {
            const gradeNum = Number(grade);
            for (let i = 0; i < count; i++) {
                const herbName = herbNames.pop();
                const existingItem = items.find(item => item.name === herbName && item.grade === gradeNum);
                if (existingItem) {
                    existingItem.count = $addBig(existingItem.count, '1');
                } else {
                    items.push({ name: herbName, grade: gradeNum, count: '1' });
                }
                totalCount++;
            }
        });
    }
    
    return { items, spiritStones, immortalStones, treasure, lawFragments, totalCount, battleCount, avgLevel, timeCrystals };
}

// ========================================
// 工具函数
// ========================================
// 格式化离线时间
// 将秒数转换为易读的时间格式（小时分钟秒）
function formatOfflineTime(seconds) {
    const hours = $floor($evalBig(`${seconds} / 3600`));
    const minutes = $floor($evalBig(`(${seconds} % 3600) / 60`));
    const secs = $evalBig(`${seconds} % 60`);
    
    if ($gteBig(hours, '1')) {
        return `${formatNumber(hours)}小时${formatNumber(minutes)}分${formatNumber(secs)}秒`;
    } else if ($gteBig(minutes, '1')) {
        return `${formatNumber(minutes)}分${formatNumber(secs)}秒`;
    } else {
        return `${formatNumber(secs)}秒`;
    }
}

// ========================================
// Base64编码/解码工具
// ========================================
// UTF-8字符串转Base64
// 用于存档导出时的编码
function utf8ToBase64(str) {
    try {
        return btoa(encodeURIComponent(str).replace(/%([0-9A-F]{2})/g, (_, p1) => {
            return String.fromCharCode(parseInt(p1, 16));
        }));
    } catch (e) {
        console.error('Base64编码失败:', e);
        return null;
    }
}

// Base64转UTF-8字符串
// 用于存档导入时的解码
function base64ToUtf8(base64) {
    try {
        const binary = atob(base64);
        const bytes = new Uint8Array(binary.length);
        for (let i = 0; i < binary.length; i++) {
            bytes[i] = binary.charCodeAt(i);
        }
        return decodeURIComponent(Array.from(bytes).map(b => '%' + ('00' + b.toString(16)).slice(-2)).join(''));
    } catch (e) {
        console.error('Base64解码失败:', e);
        return null;
    }
}

// ========================================
// 存档导出系统
// ========================================
// 导出存档（Base64编码）
// 将所有游戏数据编码为可分享的存档码
function exportSaveData() {
    const charList = getCharacterList();
    const allCharData = [];

    for (const char of charList) {
        if (!char) continue;
        const saveKey = getCharacterSaveKey(char.id);
        const charDataStr = localStorage.getItem(saveKey);
        if (charDataStr) {
            try {
                const charData = JSON.parse(charDataStr);
                allCharData.push({
                    id: char.id,
                    name: char.name,
                    data: charData
                });
            } catch (e) {}
        }
    }

    if (allCharData.length === 0) {
        showModal(`<span style="color:#ff0;">【 系统提示 】</span><br><br>
            <span style="color:#f66;">没有可导出的角色数据！</span>
            <br><br>
            <button onclick="closeModal()" class="sbtn">确定</button>
        `, true);
        return;
    }

    const exportData = {
        version: 1,
        characters: allCharData,
        exportTime: Date.now()
    };

    const saveData = JSON.stringify(exportData);
    const base64Data = utf8ToBase64(saveData);

    if (!base64Data) {
        showModal(`<span style="color:#ff0;">【 系统提示 】</span><br><br>
            <span style="color:#f66;">存档导出失败！</span>
            <br><br>
            <button onclick="closeModal()" class="sbtn">确定</button>
        `, true);
        return;
    }

    let buttons = `<button onclick="copySaveCode()" class="sbtn">复制存档码</button>`;
    buttons += `<button onclick="exportSaveToFile()" class="sbtn">导出到文件</button>`;

    showModal(`<span style="color:#ff0;">【 导出存档 】</span><br><br>
        <div style="color:#888;font-size:12px;margin-bottom:10px;">共 ${allCharData.length} 个角色</div>
        <textarea id="export-code" class="stxt" readonly>${base64Data}</textarea><br><br>
        ${buttons}
        <button onclick="closeModal()" class="sbtn">关闭</button>
    `, true);
}

// 导出存档到文件（明文JSON格式）
function exportSaveToFile() {
    const charList = getCharacterList();
    const allCharData = [];

    for (const char of charList) {
        if (!char) continue;
        const saveKey = getCharacterSaveKey(char.id);
        const charDataStr = localStorage.getItem(saveKey);
        if (charDataStr) {
            try {
                const charData = JSON.parse(charDataStr);
                allCharData.push({
                    id: char.id,
                    name: char.name,
                    data: charData
                });
            } catch (e) {}
        }
    }

    if (allCharData.length === 0) {
        showModal(`<span style="color:#ff0;">【 系统提示 】</span><br><br>
            <span style="color:#f66;">没有可导出的角色数据！</span>
            <br><br>
            <button onclick="closeModal()" class="sbtn">确定</button>
        `, true);
        return;
    }

    const exportData = {
        version: 1,
        characters: allCharData,
        exportTime: Date.now()
    };

    const saveData = JSON.stringify(exportData, null, 2);
    const fileName = '修仙挂机存档_' + Date.now() + '.txt';

    if (typeof AndroidInterface !== 'undefined' && AndroidInterface.downloadFile) {
        try {
            AndroidInterface.downloadFile(saveData, fileName, 'text/plain');
            return;
        } catch (e) {}
    }

    try {
        const blob = new Blob([saveData], { type: 'text/plain;charset=utf-8' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = fileName;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        URL.revokeObjectURL(url);
    } catch (e) {
        showModal(`<span style="color:#ff0;">【 系统提示 】</span><br><br>
            <span style="color:#f66;">导出失败: ${e.message}</span>
            <br><br>
            <button onclick="closeModal()" class="sbtn">确定</button>
        `, true);
    }
}

