// ========================================
// 存档导入系统
// ========================================
// 导入存档
// 显示输入框让玩家粘贴存档码或从文件导入
function importSaveData() {
    let importButtons = `<button onclick="confirmImportSave()" class="sbtn">确认导入</button>`;
    
    // 添加从文件导入按钮
    importButtons += `<button onclick="importSaveFromFile()" class="sbtn">从文件导入</button>`;
    
    showModal(`<span style="color:#ff0;">【 导入存档 】</span><br><br>
        <textarea id="import-code" class="stxt" placeholder="请粘贴存档码..."></textarea><br><br>
        ${importButtons}
        <button onclick="closeModal()" class="sbtn">取消</button>
    `, true);
}

// 从文件导入存档
function importSaveFromFile() {
    window._isImportingFile = true;
    
    if (typeof AndroidInterface !== 'undefined' && AndroidInterface.pickFile) {
        AndroidInterface.pickFile('text', 'fileContentCallback', 'fileErrorCallback');
        return;
    }
    
    const input = document.createElement('input');
    input.type = 'file';
    input.accept = '.txt,text/*';
    input.onchange = function(e) {
        const file = e.target.files[0];
        if (!file) {
            window._isImportingFile = false;
            return;
        }
        
        const reader = new FileReader();
        reader.onload = function(event) {
            const content = event.target.result;
            if (content) {
                const textarea = document.getElementById('import-code');
                if (textarea) {
                    textarea.value = content;
                }
            }
            window._isImportingFile = false;
        };
        reader.onerror = function() {
            window._isImportingFile = false;
            showModal(`<span style="color:#ff0;">【 系统提示 】</span><br><br>
                <span style="color:#f66;">读取文件失败</span>
                <br><br>
                <button onclick="closeModal()" class="sbtn">确定</button>
            `, true);
        };
        reader.readAsText(file);
    };
    input.click();
}

function fileContentCallback(content) {
    window._isImportingFile = false;
    if (content) {
        const textarea = document.getElementById('import-code');
        if (textarea) {
            textarea.value = content;
        }
    }
}

function fileErrorCallback(error) {
    window._isImportingFile = false;
    showModal(`<span style="color:#ff0;">【 系统提示 】</span><br><br>
        <span style="color:#f66;">读取文件失败: ${error}</span>
        <br><br>
        <button onclick="closeModal()" class="sbtn">确定</button>
    `, true);
}

// 确认导入存档
// 解析并验证存档码，加载存档数据
function confirmImportSave() {
    const textarea = document.getElementById('import-code');
    if (!textarea) return;
    
    let base64Data = textarea.value.trim();
    if (!base64Data) {
        showModal(`<span style="color:#ff0;">【 系统提示 】</span><br><br>
            请输入存档码！
            <br><br>
            <button onclick="closeModal()" class="sbtn">确定</button>
        `, true);
        return;
    }
    
    // 移除可能的空白字符和换行（仅对base64格式有效，明文JSON需要保留内部空格）
    const isLikelyBase64 = (str) => {
        const trimmed = str.trim();
        return /^[A-Za-z0-9+/=]+$/.test(trimmed) && trimmed.length % 4 === 0;
    };
    
    if (isLikelyBase64(base64Data)) {
        base64Data = base64Data.replace(/\s/g, '');
    }
    
    // ========================================
    // 作弊模块开关命令检测
    // ========================================
    // 检查是否包含作弊开关命令（明文）
    const inputText = base64Data.trim();
    if (inputText === '开启作弊') {
        // 开启作弊模块
        showCheatModule = true;
        player.showCheatModule = true;
        saveGameData();
        closeModal();
        updateCheatUI();
        showModal(`<span style="color:#ff0;">【 系统提示 】</span><br><br>
            <span style="color:#afa;">作弊模块已开启！</span>
            <br><br>
            <button onclick="closeModal()" class="sbtn">确定</button>
        `, true);
        return;
    } else if (inputText === '关闭作弊') {
        // 关闭作弊模块并重置倍率
        showCheatModule = false;
        player.showCheatModule = false;
        player.cheat = player.cheat || {};
        player.cheat.offlineMultiplier = 1;
        saveGameData();
        closeModal();
        updateCheatUI();
        showModal(`<span style="color:#ff0;">【 系统提示 】</span><br><br>
            <span style="color:#afa;">作弊模块已关闭！</span>
            <br><br>
            <button onclick="closeModal()" class="sbtn">确定</button>
        `, true);
        return;
    }
    
    // ========================================
    // 存档解码与验证
    // ========================================
    try {
        let saveData = null;
        
        const trimmedData = base64Data.trim();
        
        // 判断是否为明文JSON（以{开头或包含有效JSON结构）
        const isJsonLike = (str) => {
            const trimmed = str.trim();
            if (trimmed.startsWith('{') && trimmed.endsWith('}')) {
                try {
                    JSON.parse(trimmed);
                    return true;
                } catch (e) {
                    return false;
                }
            }
            return false;
        };
        
        // 如果看起来像JSON，优先尝试解析明文
        if (isJsonLike(trimmedData)) {
            try {
                saveData = trimmedData;
                JSON.parse(saveData);
            } catch (e1) {
                // 明文解析失败，尝试base64解码
                saveData = base64ToUtf8(trimmedData);
            }
        } else {
            // 不是JSON格式，尝试base64解码
            saveData = base64ToUtf8(trimmedData);
            
            // 如果base64解码失败，尝试直接解析（可能是未编码的JSON）
            if (!saveData) {
                try {
                    saveData = trimmedData;
                    JSON.parse(saveData);
                } catch (e2) {
                    showModal(`<span style="color:#ff0;">【 系统提示 】</span><br><br>
                        <span style="color:#f66;">存档码解码失败！</span><br>
                        <span style="color:#888;font-size:12px;">请确保完整复制存档码</span>
                        <br><br>
                        <button onclick="closeModal()" class="sbtn">确定</button>
                    `, true);
                    return;
                }
            }
        }
        
        // 解析JSON数据
        let loaded;
        try {
            loaded = JSON.parse(saveData);
        } catch (jsonErr) {
            console.error('JSON解析失败:', jsonErr);
            showModal(`<span style="color:#ff0;">【 系统提示 】</span><br><br>
                <span style="color:#f66;">存档数据格式错误！</span><br>
                <span style="color:#888;font-size:12px;">存档可能已损坏</span>
                <br><br>
                <button onclick="closeModal()" class="sbtn">确定</button>
            `, true);
            return;
        }
        
        // 验证存档数据完整性
        if (!loaded.name && !loaded.bag && !loaded.realmIndex && !loaded.characters) {
            showModal(`<span style="color:#ff0;">【 系统提示 】</span><br><br>
                <span style="color:#f66;">存档数据无效！</span><br>
                <span style="color:#888;font-size:12px;">缺少必要的数据字段</span>
                <br><br>
                <button onclick="closeModal()" class="sbtn">确定</button>
            `, true);
            return;
        }

        // 检查是否为新版多角色存档
        if (loaded.characters && Array.isArray(loaded.characters)) {
            // 新版多角色存档导入
            importMultiCharacterSave(loaded);
            return;
        }

        // 旧版单角色存档导入（保持兼容）
        // 合并默认数据并加载
        player = { ...defaultPlayer, ...loaded };
        
        // ========================================
        // 存档字段兼容性处理
        // ========================================
        // 确保必要字段存在
        migrateSaveData(player);
        if (!player.currentMap) {
            player.currentMap = 1;
        }
        if (!player.laws) {
            player.laws = { ...defaultPlayer.laws };
        } else {
            for (let key in defaultPlayer.laws) {
                if (player.laws[key] === undefined || player.laws[key] === null) {
                    player.laws[key] = '0';
                } else {
                    player.laws[key] = String(player.laws[key]);
                }
            }
            if (player.laws.time !== undefined) {
                delete player.laws.time;
            }
        }
        if (!player.battleHistory) {
            player.battleHistory = [];
        }
        
        // ========================================
        // 同步游戏状态
        // ========================================
        // 同步地图状态
        battleState.currentMap = player.currentMap || 1;
        
        // 保存导入的存档
        const importCharId = getCurrentCharId();
        player.id = importCharId;
        localStorage.setItem(getCharacterSaveKey(importCharId), JSON.stringify(player));

        // 重置角色列表：使用固定槽位格式
        const newCharList = [null, null, null, null];
        // 确定槽位索引
        let slotIndex = 0;
        if (importCharId === 'char_1') slotIndex = 0;
        else if (importCharId === 'char_2') slotIndex = 1;
        else if (importCharId === 'char_3') slotIndex = 2;
        else if (importCharId === 'char_4') slotIndex = 3;
        newCharList[slotIndex] = { id: importCharId, name: player.name || '角色名称' };
        saveCharacterList(newCharList);

        // 清理其他旧角色存档（删除不在新列表中的角色存档）
        for (let key in localStorage) {
            if (key.startsWith('wenziguaji_save_char_')) {
                const charId = key.replace('wenziguaji_save_', '');
                if (charId !== importCharId) {
                    localStorage.removeItem(key);
                }
            }
        }

        closeModal();
        
        window.worldExpState = null;
        window.worldExpInBackground = false;
        window.worldExpOriginalBattleContent = null;
        window.worldExpBattleSpeed = 0;
        window.worldExpBattleMax = false;
        window.worldExpBattleGeneration = 0;
        window.worldExpLogScrollTop = undefined;
        window.worldExpContentScrollTop = undefined;
        window.worldExpLastHeartbeat = 0;
        window.worldExpLastKillCount = 0;
        window.worldExpLastEnemyCount = 0;
        window.pendingWorldExpState = null;
        localStorage.removeItem('worldExpBattleData');
        
        // 导入存档后执行离线结算
        try {
            processOfflineRewards(player, true);
            player.lastSaveTime = Date.now();
            const importCharId2 = getCurrentCharId();
            localStorage.setItem(getCharacterSaveKey(importCharId2), JSON.stringify(player));
        } catch (offlineErr) {
            console.error('导入存档离线结算异常:', offlineErr);
        }
        
        // 刷新所有界面
        calculateCultivationStats();  // 重新计算属性
        updateplayernameUI();         // 更新顶部境界显示
        updateStatusUI();             // 更新状态栏
        updateBattleUI();             // 更新战斗界面
        updateCultivationUI();        // 更新修炼界面
        updateWeaponUI();             // 更新法宝界面
        updateEquipmentUI();          // 更新装备界面
        updateBagUI();                // 更新背包界面
        updateCharacterTagUI();       // 更新角色标签

        window._needReloadPageAfterImport = true;
        showModal(`<span style="color:#ff0;">【 系统提示 】</span><br><br>
            <span style="color:#afa;">存档导入成功！</span>
            <br><br>
            <button onclick="closeModal()" class="sbtn">确定</button>
        `, true);
    } catch (e) {
        // 导入失败处理
        console.error('导入存档失败:', e);
        showModal(`<span style="color:#ff0;">【 系统提示 】</span><br><br>
            <span style="color:#f66;">导入失败：${e.message || '未知错误'}</span>
            <br><br>
            <button onclick="closeModal()" class="sbtn">确定</button>
        `, true);
    }
}

// 导入多角色存档
function importMultiCharacterSave(loaded) {
    try {
        const characters = loaded.characters;
        if (!characters || !Array.isArray(characters) || characters.length === 0) {
            showModal(`<span style="color:#ff0;">【 系统提示 】</span><br><br>
                <span style="color:#f66;">存档中没有角色数据！</span>
                <br><br>
                <button onclick="closeModal()" class="sbtn">确定</button>
            `, true);
            return;
        }

        // 使用固定槽位格式
        const newCharList = [null, null, null, null];
        let switchToCharId = null;

        for (let i = 0; i < characters.length && i < 4; i++) {
            const char = characters[i];
            if (!char.data) continue;

            // 使用固定ID
            const charId = 'char_' + (i + 1);
            const charName = char.name || '角色名称';
            let charData = { ...defaultPlayer, ...char.data };
            charData.id = charId;

            migrateSaveData(charData);
            if (!charData.currentMap) charData.currentMap = 1;
            if (!charData.laws) {
                charData.laws = { ...defaultPlayer.laws };
            }
            if (!charData.battleHistory) charData.battleHistory = [];

            localStorage.setItem(getCharacterSaveKey(charId), JSON.stringify(charData));
            newCharList[i] = { id: charId, name: charName };

            if (switchToCharId === null) {
                switchToCharId = charId;
            }
        }

        const validCount = newCharList.filter(c => c !== null).length;
        if (validCount === 0) {
            showModal(`<span style="color:#ff0;">【 系统提示 】</span><br><br>
                <span style="color:#f66;">没有有效的角色数据！</span>
                <br><br>
                <button onclick="closeModal()" class="sbtn">确定</button>
            `, true);
            return;
        }

        saveCharacterList(newCharList);

        if (switchToCharId) {
            setCurrentCharId(switchToCharId);
            player = loadGameData();
        }

        closeModal();

        window.worldExpState = null;
        window.worldExpInBackground = false;
        window.worldExpOriginalBattleContent = null;
        window.worldExpBattleSpeed = 0;
        window.worldExpBattleMax = false;
        window.worldExpBattleGeneration = 0;
        window.worldExpLogScrollTop = undefined;
        window.worldExpContentScrollTop = undefined;
        window.worldExpLastHeartbeat = 0;
        window.worldExpLastKillCount = 0;
        window.worldExpLastEnemyCount = 0;
        window.pendingWorldExpState = null;
        localStorage.removeItem('worldExpBattleData');

        try {
            processOfflineRewards(player, true);
            player.lastSaveTime = Date.now();
            localStorage.setItem(getCharacterSaveKey(getCurrentCharId()), JSON.stringify(player));
        } catch (offlineErr) {
            console.error('导入存档离线结算异常:', offlineErr);
        }

        calculateCultivationStats();
        updateplayernameUI();
        updateStatusUI();
        updateBattleUI();
        updateCultivationUI();
        updateWeaponUI();
        updateEquipmentUI();
        updateBagUI();
        updateCharacterTagUI();

        window._needReloadPageAfterImport = true;
        const importCount = newCharList.filter(c => c !== null).length;
        showModal(`<span style="color:#ff0;">【 系统提示 】</span><br><br>
            <span style="color:#afa;">存档导入成功！</span><br>
            <span style="color:#888;">共导入 ${importCount} 个角色</span>
            <br><br>
            <button onclick="closeModal()" class="sbtn">确定</button>
        `, true);
    } catch (e) {
        console.error('导入多角色存档失败:', e);
        showModal(`<span style="color:#ff0;">【 系统提示 】</span><br><br>
            <span style="color:#f66;">导入失败：${e.message || '未知错误'}</span>
            <br><br>
            <button onclick="closeModal()" class="sbtn">确定</button>
        `, true);
    }
}

// ========================================
// 存档清除系统
// ========================================
// 清除存档
// 显示确认弹窗，防止误操作
function clearSaveData() {
    const charId = getCurrentCharId();
    const list = getCharacterList();
    const char = list.find(c => c && c.id === charId);
    const charName = char ? char.name : '此角色';

    showModal(`<span style="color:#ff0;">【 重置游戏 】</span><br><br>
        <span style="color:#f66;">确定要重置角色 <span style="color:#ff0;">${escapeHtml(charName)}</span> 吗？</span><br>
        <span style="color:#f66;">此操作不可恢复！</span><br><br>
        <button onclick="confirmClearSave()" class="sbtn">确定重置</button>
        <button onclick="closeModal()" class="sbtn">取消</button>
    `, true);
}

// 确认清除存档
// 执行清除操作并重置游戏状态
function confirmClearSave() {
    const charId = getCurrentCharId();
    localStorage.removeItem(getCharacterSaveKey(charId));

    const list = getCharacterList();
    const charIndex = list.findIndex(c => c && c.id === charId);
    if (charIndex !== -1) {
        list[charIndex] = null;
    }

    const firstValid = list.find(c => c !== null);
    if (firstValid) {
        setCurrentCharId(firstValid.id);
        player = loadGameData();
    } else {
        saveCharacterList([]);
        setCurrentCharId('char_1');
        player = { ...defaultPlayer };
    }

    closeModal();
    calculateCultivationStats();
    player.hp = player.maxHp;
    updateStatusUI();
    updateBattleUI();
    updateCultivationUI();
    updateWeaponUI();
    updateEquipmentUI();
    updateBagUI();
    updateCharacterTagUI();
    showModal(`<span style="color:#ff0;">【 系统提示 】</span><br><br>
        游戏已重置！
        <br><br>
        <button onclick="closeModal();" class="sbtn">确定</button>
    `, true);
}

// ========================================
// 背景图片系统
// ========================================
let backgroundImageList = [];
let currentBackgroundIndex = 0;
let backgroundSwitchInterval = null;

// 切换背景颜色（深色/浅色主题）
function changeBackground() {
    showBackgroundImageModal();
}

// 显示背景图片设置弹窗，包含图片上传、透明度调节、文字颜色切换等选项
function showBackgroundImageModal() {
    const savedBackground = localStorage.getItem('wenziguaji_background');
    const hasBackground = savedBackground && savedBackground.length > 0;
    const terminalOpacity = localStorage.getItem('wenziguaji_terminal_opacity') || '0.3';
    const modalOpacity = localStorage.getItem('wenziguaji_modal_opacity') || '0.3';
    const boxOpacity = localStorage.getItem('wenziguaji_box_opacity') || '0.5';
    const textColor = localStorage.getItem('wenziguaji_text_color') || 'white';
    const savedImageList = localStorage.getItem('wenziguaji_background_list');
    const imageList = savedImageList ? JSON.parse(savedImageList) : [];
    const autoSwitch = localStorage.getItem('wenziguaji_background_autoswitch') === 'true';
    const switchInterval = parseInt(localStorage.getItem('wenziguaji_background_interval')) || 5;
    const imageCount = imageList.length;
    
    let imageListHtml = '';
    if (imageCount > 0) {
        imageListHtml = `<br><br><span style="color:var(--text-color,#fff);">已选图片 (${imageCount}张):</span><br>`;
        imageList.forEach((img, idx) => {
            imageListHtml += `<span style="color:var(--text-color-dim,#888);font-size:12px;">${idx + 1}. 图片${idx + 1}</span> `;
        });
        imageListHtml += `<br><button onclick="clearAllBackgroundImages()" style="background:rgba(200,50,50,0.9);color:#fff;border:1px solid #666;padding:5px 15px;cursor:pointer;margin-top:5px;">清除全部</button>`;
    }

    showModal(`<span style="color:#ff0;">【 背景图片设置 】</span><br><br>
        <span style="color:var(--text-color,#fff);">支持上传JPG、PNG格式图片</span><br>
        <span style="color:var(--text-color-dim,#888);">图片将以拉伸方式铺满整个游戏背景</span>
        ${hasBackground || imageCount > 0 ? '<br><br><span style="color:#afa;">当前已设置背景图片</span>' : ''}
        ${imageListHtml}
        <br><br>
        <button onclick="pickMultipleImagesFromAndroid()" style="background:rgba(51,51,51,0.9);color:var(--text-color,#fff);border:1px solid #666;padding:5px 15px;cursor:pointer;">选择图片</button>
        <br><br>
        <span style="color:var(--text-color,#fff);">主界面遮罩: <span id="terminalOpacityValue">${Math.round((1 - parseFloat(terminalOpacity)) * 100)}%</span> (0%=纯黑,100%=全透明)</span><br>
        <input type="range" id="terminalOpacitySlider" min="0" max="100" value="${Math.round((1 - parseFloat(terminalOpacity)) * 100)}" onchange="updateTerminalOpacity(this.value)" style="width:200px;">
        <br><br>
        <span style="color:var(--text-color,#fff);">内容框透明度: <span id="boxOpacityValue">${Math.round((1 - parseFloat(boxOpacity)) * 100)}%</span> (0%=不透明,100%=全透明)</span><br>
        <input type="range" id="boxOpacitySlider" min="0" max="100" value="${Math.round((1 - parseFloat(boxOpacity)) * 100)}" onchange="updateBoxOpacity(this.value)" style="width:200px;">
        <br><br>
        <span style="color:var(--text-color,#fff);">弹窗遮罩: <span id="modalOpacityValue">${Math.round((1 - parseFloat(modalOpacity)) * 100)}%</span> (0%=纯黑,100%=全透明)</span><br>
        <input type="range" id="modalOpacitySlider" min="0" max="100" value="${Math.round((1 - parseFloat(modalOpacity)) * 100)}" onchange="updateModalOpacity(this.value)" style="width:200px;">
        <br><br>
        <span style="color:var(--text-color,#fff);">文字颜色: </span>
        <button onclick="setTextColor('white')" style="background:${textColor === 'white' ? 'rgba(200,200,200,0.9)' : 'rgba(51,51,51,0.9)'};color:var(--text-color,#fff);border:1px solid #666;padding:5px 12px;cursor:pointer;">白色</button>
        <button onclick="setTextColor('black')" style="background:${textColor === 'black' ? 'rgba(200,200,200,0.9)' : 'rgba(51,51,51,0.9)'};color:var(--text-color,#fff);border:1px solid #666;padding:5px 12px;cursor:pointer;">黑色</button>
        <br><br>
        <button onclick="closeModal()" style="background:rgba(51,51,51,0.9);color:var(--text-color,#fff);border:1px solid #666;padding:5px 15px;cursor:pointer;">关闭</button>
        <span style="color:var(--text-color-dim,#888);font-size:12px;margin-left:10px;">自动切换: <button onclick="toggleBackgroundAutoSwitch();" style="background:${autoSwitch ? 'rgba(100,200,100,0.9)' : 'rgba(51,51,51,0.9)'};color:var(--text-color,#fff);border:1px solid #666;padding:2px 8px;cursor:pointer;font-size:11px;">${autoSwitch ? '开启' : '关闭'}</button></span>
        ${autoSwitch ? `<br><br><span style="color:var(--text-color,#fff);font-size:12px;">切换间隔: <span id="switchIntervalValue">${switchInterval}</span>秒</span><br><input type="range" id="switchIntervalSlider" min="1" max="60" value="${switchInterval}" onchange="updateBackgroundSwitchInterval(this.value)" style="width:200px;"><span style="color:var(--text-color-dim,#888);font-size:11px;"> (1-60秒)</span>` : ''}
    `, true);
}

// 更新主界面遮罩透明度（0%=纯黑，100%=全透明）
function updateTerminalOpacity(value) {
    const opacity = 1 - value / 100;
    localStorage.setItem('wenziguaji_terminal_opacity', opacity.toString());
    document.getElementById('terminalOpacityValue').textContent = value + '%';
    applyBackgroundImage();
}

// 更新内容框透明度并保存到本地存储
function updateBoxOpacity(value) {
    const opacity = 1 - value / 100;
    localStorage.setItem('wenziguaji_box_opacity', opacity.toString());
    document.getElementById('boxOpacityValue').textContent = value + '%';
    applyBoxOpacity();
}

// 应用内容框透明度到CSS变量
function applyBoxOpacity() {
    const boxOpacity = localStorage.getItem('wenziguaji_box_opacity') || '0.5';
    document.body.style.setProperty('--box-opacity', boxOpacity);
}

// 更新弹窗遮罩透明度并保存到本地存储
function updateModalOpacity(value) {
    const opacity = 1 - value / 100;
    localStorage.setItem('wenziguaji_modal_opacity', opacity.toString());
    document.getElementById('modalOpacityValue').textContent = value + '%';
}

// 设置文字颜色（白色/黑色）并保存到本地存储
function setTextColor(color) {
    localStorage.setItem('wenziguaji_text_color', color);
    applyTextColor();
}

// 应用文字颜色到CSS变量，同时设置次要文字和暗淡文字颜色
function applyTextColor() {
    const textColor = localStorage.getItem('wenziguaji_text_color') || 'white';
    if (textColor === 'black') {
        document.body.style.setProperty('--text-color', '#000000');
        document.body.style.setProperty('--text-color-secondary', '#333333');
        document.body.style.setProperty('--text-color-dim', '#888888');
    } else {
        document.body.style.setProperty('--text-color', '#ffffff');
        document.body.style.setProperty('--text-color-secondary', '#cccccc');
        document.body.style.setProperty('--text-color-dim', '#888888');
    }
}

// 从Android端选取单张背景图片
function pickImageFromAndroid() {
    if (typeof AndroidInterface !== 'undefined') {
        pickImageFromFileInput('handleBackgroundImageSuccess');
    } else {
        pickImageFromFileInput('handleBackgroundImageSuccess');
    }
}

// 从Android端选取多张背景图片
function pickMultipleImagesFromAndroid() {
    if (typeof AndroidInterface !== 'undefined') {
        pickImageFromFileInput('handleMultipleBackgroundImagesSuccess');
    } else {
        pickImageFromFileInput('handleMultipleBackgroundImagesSuccess');
    }
}

// 创建文件选择器，读取图片文件并回调处理函数
// 支持单张和多张图片选择
function pickImageFromFileInput(callback) {
    const input = document.createElement('input');
    input.type = 'file';
    input.accept = 'image/*';
    if (callback === 'handleMultipleBackgroundImagesSuccess') {
        input.multiple = true;
    }
    input.onchange = function(e) {
        const files = e.target.files;
        if (!files || files.length === 0) return;
        
        if (callback === 'handleBackgroundImageSuccess') {
            const reader = new FileReader();
            reader.onload = function(event) {
                window[callback](event.target.result);
            };
            reader.readAsDataURL(files[0]);
        } else if (callback === 'handleMultipleBackgroundImagesSuccess') {
            const base64Array = [];
            let loaded = 0;
            Array.from(files).forEach((file, idx) => {
                const reader = new FileReader();
                reader.onload = function(event) {
                    base64Array.push(event.target.result);
                    loaded++;
                    if (loaded === files.length) {
                        window[callback](base64Array);
                    }
                };
                reader.readAsDataURL(file);
            });
        }
    };
    input.click();
}

// 处理单张背景图片设置成功
// 将图片缩放至屏幕尺寸后保存到localStorage并应用
function handleBackgroundImageSuccess(base64Data) {
    let imgSrc = base64Data.startsWith('data:') ? base64Data : 'data:image/jpeg;base64,' + base64Data;
    const img = new Image();
    img.onload = function() {
        const pageWidth = window.innerWidth;
        const pageHeight = window.innerHeight;
        const canvas = document.createElement('canvas');
        canvas.width = pageWidth;
        canvas.height = pageHeight;
        const ctx = canvas.getContext('2d');
        ctx.drawImage(img, 0, 0, pageWidth, pageHeight);
        const base64 = canvas.toDataURL('image/jpeg', 0.9);
        localStorage.setItem('wenziguaji_background', base64);
        
        let savedImageList = localStorage.getItem('wenziguaji_background_list');
        let imageList = savedImageList ? JSON.parse(savedImageList) : [];
        if (!imageList.includes(base64)) {
            imageList.push(base64);
            localStorage.setItem('wenziguaji_background_list', JSON.stringify(imageList));
        }
        
        backgroundImageList = imageList;
        currentBackgroundIndex = imageList.length - 1;
        
        applyBackgroundImage();
        closeModal();
        showModal(`<span style="color:#ff0;">【 系统提示 】</span><br><br>
            <span style="color:#afa;">背景图片设置成功！</span>
            <br><br>
            <button onclick="closeModal();showBackgroundImageModal();" class="sbtn">确定</button>
        `, true);
    };
    img.onerror = function() {
        showModal(`<span style="color:#ff0;">【 系统提示 】</span><br><br>
            <span style="color:#f66;">图片加载失败</span>
            <br><br>
            <button onclick="closeModal()" class="sbtn">确定</button>
        `, true);
    };
    img.src = imgSrc;
}

// 处理多张背景图片设置成功
// 逐张缩放至屏幕尺寸后保存到图片列表，并启动自动切换
function handleMultipleBackgroundImagesSuccess(base64DataArray) {
    try {
        let imageList = [];
        let savedImageList = localStorage.getItem('wenziguaji_background_list');
        if (savedImageList) {
            imageList = JSON.parse(savedImageList);
        }
        
        let processIndex = 0;
        const processNextImage = () => {
            if (processIndex >= base64DataArray.length) {
                if (imageList.length > 0) {
                    localStorage.setItem('wenziguaji_background_list', JSON.stringify(imageList));
                    backgroundImageList = imageList;
                    localStorage.setItem('wenziguaji_background', imageList[0]);
                    currentBackgroundIndex = 0;
                    applyBackgroundImage();
                    startBackgroundAutoSwitch();
                }
                closeModal();
                showModal(`<span style="color:#ff0;">【 系统提示 】</span><br><br>
                    <span style="color:#afa;">成功添加 ${base64DataArray.length} 张背景图片！</span>
                    <br><br>
                    <button onclick="closeModal();showBackgroundImageModal();" class="sbtn">确定</button>
                `, true);
                return;
            }
            
            let base64Data = base64DataArray[processIndex];
            let imgSrc = base64Data.startsWith('data:') ? base64Data : 'data:image/jpeg;base64,' + base64Data;
            const img = new Image();
            img.onload = function() {
                const pageWidth = window.innerWidth;
                const pageHeight = window.innerHeight;
                const canvas = document.createElement('canvas');
                canvas.width = pageWidth;
                canvas.height = pageHeight;
                const ctx = canvas.getContext('2d');
                ctx.drawImage(img, 0, 0, pageWidth, pageHeight);
                const base64 = canvas.toDataURL('image/jpeg', 0.9);
                if (!imageList.includes(base64)) {
                    imageList.push(base64);
                }
                processIndex++;
                processNextImage();
            };
            img.onerror = function() {
                processIndex++;
                processNextImage();
            };
            img.src = imgSrc;
        };
        
        processNextImage();
    } catch (error) {
        showModal(`<span style="color:#ff0;">【 系统提示 】</span><br><br>
            <span style="color:#f66;">处理图片失败: ${error.message}</span>
            <br><br>
            <button onclick="closeModal()" class="sbtn">确定</button>
        `, true);
    }
}

// 处理背景图片选择失败的错误提示
function handleBackgroundImageError(errorMsg) {
    if (errorMsg && errorMsg !== '取消选择') {
        showModal(`<span style="color:#ff0;">【 系统提示 】</span><br><br>
            <span style="color:#f66;">选择图片失败: ${errorMsg}</span>
            <br><br>
            <button onclick="closeModal()" class="sbtn">确定</button>
        `, true);
    }
}

// 清除当前背景图片并恢复默认
function clearBackgroundImage() {
    localStorage.removeItem('wenziguaji_background');
    stopBackgroundAutoSwitch();
    applyBackgroundImage();
    closeModal();
    showModal(`<span style="color:#ff0;">【 系统提示 】</span><br><br>
        <span style="color:#afa;">背景图片已清除！</span>
        <br><br>
        <button onclick="closeModal()" class="sbtn">确定</button>
    `, true);
}

// 清除所有背景图片及相关设置（包括图片列表、自动切换配置）
function clearAllBackgroundImages() {
    localStorage.removeItem('wenziguaji_background');
    localStorage.removeItem('wenziguaji_background_list');
    localStorage.removeItem('wenziguaji_background_autoswitch');
    localStorage.removeItem('wenziguaji_background_interval');
    backgroundImageList = [];
    currentBackgroundIndex = 0;
    stopBackgroundAutoSwitch();
    applyBackgroundImage();
    closeModal();
    showModal(`<span style="color:#ff0;">【 系统提示 】</span><br><br>
        <span style="color:#afa;">全部背景图片已清除！</span>
        <br><br>
        <button onclick="closeModal()" class="sbtn">确定</button>
    `, true);
}

// 切换背景图片自动轮播开关
function toggleBackgroundAutoSwitch() {
    const current = localStorage.getItem('wenziguaji_background_autoswitch') === 'true';
    localStorage.setItem('wenziguaji_background_autoswitch', (!current).toString());
    if (!current) {
        startBackgroundAutoSwitch();
    } else {
        stopBackgroundAutoSwitch();
    }
    closeModal();
    showBackgroundImageModal();
}

// 更新背景图片自动切换间隔（1-60秒）
function updateBackgroundSwitchInterval(value) {
    localStorage.setItem('wenziguaji_background_interval', value);
    document.getElementById('switchIntervalValue').textContent = value;
    if (localStorage.getItem('wenziguaji_background_autoswitch') === 'true') {
        startBackgroundAutoSwitch();
    }
}

// 启动背景图片自动轮播定时器
// 仅在图片数量>1且开启自动切换时生效
function startBackgroundAutoSwitch() {
    stopBackgroundAutoSwitch();
    const savedImageList = localStorage.getItem('wenziguaji_background_list');
    const imageList = savedImageList ? JSON.parse(savedImageList) : [];
    if (imageList.length <= 1) return;
    
    const autoSwitch = localStorage.getItem('wenziguaji_background_autoswitch') === 'true';
    if (!autoSwitch) return;
    
    const interval = parseInt(localStorage.getItem('wenziguaji_background_interval')) || 5;
    backgroundImageList = imageList;
    
    const savedBackground = localStorage.getItem('wenziguaji_background');
    if (savedBackground) {
        currentBackgroundIndex = imageList.indexOf(savedBackground);
        if (currentBackgroundIndex < 0) currentBackgroundIndex = 0;
    }
    
    setTimeout(() => {
        Scheduler.add('backgroundSwitch', switchToNextBackground, interval * 1000);
    }, 3000);
}

function stopBackgroundAutoSwitch() {
    Scheduler.remove('backgroundSwitch');
}

// 切换到下一张背景图片（循环轮播）
function switchToNextBackground() {
    const savedImageList = localStorage.getItem('wenziguaji_background_list');
    const imageList = savedImageList ? JSON.parse(savedImageList) : [];
    if (imageList.length <= 0) return;
    
    currentBackgroundIndex = (currentBackgroundIndex + 1) % imageList.length;
    localStorage.setItem('wenziguaji_background', imageList[currentBackgroundIndex]);
    applyBackgroundImage();
}

// 应用背景图片到终端容器，同时应用透明度和文字颜色设置
function applyBackgroundImage() {
    const terminal = document.querySelector('.terminal');
    const savedBackground = localStorage.getItem('wenziguaji_background');
    const savedImageList = localStorage.getItem('wenziguaji_background_list');
    if (savedImageList) {
        backgroundImageList = JSON.parse(savedImageList);
    }
    const terminalOpacity = localStorage.getItem('wenziguaji_terminal_opacity') || '0.3';
    document.body.style.setProperty('--terminal-opacity', terminalOpacity);
    applyTextColor();
    applyBoxOpacity();
    if (savedBackground && savedBackground.length > 0) {
        terminal.style.backgroundImage = `url(${savedBackground})`;
        terminal.style.backgroundSize = '100% 100%';
        terminal.style.backgroundPosition = 'center';
        terminal.style.backgroundRepeat = 'no-repeat';
        terminal.style.backgroundColor = 'transparent';
    } else {
        terminal.style.backgroundImage = 'none';
        terminal.style.backgroundColor = '#0a0a0a';
    }
    if (localStorage.getItem('wenziguaji_background_autoswitch') === 'true') {
        startBackgroundAutoSwitch();
    }
}

// ========================================
// 修炼系统初始化
// ========================================
// 初始化修炼系统
// 设置定时器处理灵气吸收、灵脉产出、灵药成长等
let lastUptimeUpdate = 0;
let cachedFieldMultiplier = '1';
let lastFieldMultiplierCalc = 0;

// 灵压计算缓存
let cachedSpiritPressure = null;
let lastSpiritPressureCalc = 0;
let lastGatheringArrayLevel = -1;
let lastArrayNodesKey = '';

// 节点加成缓存
let cachedNodeBonus = 0;
let lastNodeBonusCalc = 0;

// 内天地速度加成缓存
let cachedNeitiandiSpeedBonus = null;
let lastNeitiandiSpeedBonusCalc = 0;
let lastBenYuanCount = -1;
let lastShengLingCount = -1;
let lastBoundHerbGrade = -1;

function getFieldMultiplier() {
    const now = Date.now();
    if (now - lastFieldMultiplierCalc < 5000) {
        return cachedFieldMultiplier;
    }
    
    cachedFieldMultiplier = '1';
    player.spiritField.forEach(item => {
        if (item && item.grade > 0) {
            const slotBonus = $subBig($pow('1.05', String(item.grade)), '1');
            cachedFieldMultiplier = $addBig(cachedFieldMultiplier, slotBonus);
        }
    });
    lastFieldMultiplierCalc = now;
    return cachedFieldMultiplier;
}

function getNodeBonus() {
    const now = Date.now();
    const nodesKey = player.arrayNodes.map(n => n.grade).join(',');
    
    if (now - lastNodeBonusCalc < 5000 && nodesKey === lastArrayNodesKey) {
        return cachedNodeBonus;
    }
    
    cachedNodeBonus = 0;
    player.arrayNodes.forEach(node => {
        cachedNodeBonus += node.grade;
    });
    lastNodeBonusCalc = now;
    lastArrayNodesKey = nodesKey;
    return cachedNodeBonus;
}

function getSpiritPressure() {
    const now = Date.now();
    const nodesKey = player.arrayNodes.map(n => n.grade).join(',');
    const levelChanged = player.gatheringArrayLevel !== lastGatheringArrayLevel;
    const nodesChanged = nodesKey !== lastArrayNodesKey;
    
    if (!levelChanged && !nodesChanged && now - lastSpiritPressureCalc < 5000 && cachedSpiritPressure) {
        return cachedSpiritPressure;
    }
    
    const nodeBonus = getNodeBonus();
    cachedSpiritPressure = $evalBig(`${$pow(1.07, player.gatheringArrayLevel)} * ${$pow(1.05, nodeBonus)}`);
    lastSpiritPressureCalc = now;
    lastGatheringArrayLevel = player.gatheringArrayLevel;
    lastArrayNodesKey = nodesKey;
    return cachedSpiritPressure;
}

function getNeitiandiSpeedBonus() {
    const now = Date.now();
    const benYuanCount = Number($floor(getFirstCharacterBenYuan() || 0));
    const shengLingCount = Number($floor(player.shengLing || 0));
    const boundHerb = getFirstCharacterBoundHerb();
    const boundHerbGrade = boundHerb?.grade || 0;
    
    const benYuanChanged = benYuanCount !== lastBenYuanCount;
    const shengLingChanged = shengLingCount !== lastShengLingCount;
    const herbChanged = boundHerbGrade !== lastBoundHerbGrade;
    
    if (!benYuanChanged && !shengLingChanged && !herbChanged && 
        now - lastNeitiandiSpeedBonusCalc < 5000 && cachedNeitiandiSpeedBonus) {
        return cachedNeitiandiSpeedBonus;
    }
    
    const lgBonus = $addBig('1', $log10($addBig(String(benYuanCount), '1')));
    let neitiandiSpeedBonus = lgBonus;
    
    if (player.realmIndex >= 4 && shengLingCount > 0) {
        const exponent = calcNeitiandiLevel(boundHerbGrade);
        const logBase = $log10('500');
        const logArg = $evalBig(`500 + ${shengLingCount}`);
        const logValue = $evalBig(`${$log10(logArg)} / ${logBase}`);
        const logPower = $evalBig(`${logValue} ^ 11`);
        const denominator = $addBig(logPower, '1');
        const fraction = $evalBig(`1 / ${denominator}`);
        const oneMinus = $subBig('1', fraction);
        const multiplied = $evalBig(`0.0135039 * ${oneMinus}`);
        const baseBonus = $addBig('1', multiplied);
        const complexBonus = $pow(baseBonus, String(exponent));
        neitiandiSpeedBonus = $addBig(lgBonus, complexBonus);
    }
    
    cachedNeitiandiSpeedBonus = neitiandiSpeedBonus;
    lastNeitiandiSpeedBonusCalc = now;
    lastBenYuanCount = benYuanCount;
    lastShengLingCount = shengLingCount;
    lastBoundHerbGrade = boundHerbGrade;
    
    return neitiandiSpeedBonus;
}

function initCultivationSystem() {
    calculateCultivationStats();
    player.hp = player.maxHp;
    
    checkCultivationUpgrade();
    
    let lastUptimeUpdate = 0;
    
    Scheduler.add('cultivationTick', () => {
        const fieldMultiplier = getFieldMultiplier();
        const spiritPressure = getSpiritPressure();
        const neitiandiSpeedBonus = getNeitiandiSpeedBonus();
        
        const baseAbsorb = $evalBig(`${spiritPressure} * ${neitiandiSpeedBonus} * 10`);
        
        if ($gteBig(player.vein, baseAbsorb)) {
            player.vein = $subBig(player.vein, baseAbsorb);
            player.cultivation = $addBig(player.cultivation, baseAbsorb);
            checkCultivationUpgrade();
        } else if ($gteBig(player.vein, '0.001')) {
            player.cultivation = $addBig(player.cultivation, player.vein);
            player.vein = '0';
            checkCultivationUpgrade();
        }
        
        if ($gteBig(player.veinStone, '0.001')) {
            let release = $evalBig(`${player.veinStone} * 0.2 * ${fieldMultiplier} / 6`);
            if (release === 'Infinity' || release === Infinity) release = '1e308';
            if (player.vein !== 'Infinity' && player.vein !== Infinity) {
                player.vein = $addBig(player.vein, release);
            }
            player.veinStone = $evalBig(`${player.veinStone} * 0.99995`);
        }
        
        if ($gteBig(player.immortalVeinStone, '0.01')) {
            const release = $evalBig(`${player.immortalVeinStone} * 0.01 / 6`);
            player.spiritStone = $addBig(player.spiritStone, release);
        }
        
        spiritFieldGroundPowerFull();
        herbGrowthTick();

        const now = Date.now();
        if (now - lastUptimeUpdate >= 30000) {
            scheduleUIUpdate();
            lastUptimeUpdate = now;
        }
    }, 10000);
}

// ========================================
// 修炼升级检测
// ========================================
// ========================================
// 修炼升级检测
// ========================================
// 检查是否可以升级
// 判断玩家是否达到升级或突破条件
function checkCultivationUpgrade(playerData) {
    const target = playerData || player;
    const required = getRequiredCultivation(target.innerLevel);
    
    if (target.realmIndex >= 4) {
        target.canUpgrade = $gteBig(target.cultivation, String(required));
        target.canBreakthrough = false;
    } else {
        target.canUpgrade = $gteBig(target.cultivation, String(required)) && target.level < 9;
        target.canBreakthrough = $gteBig(target.cultivation, String(required)) && target.level >= 9 && target.realmIndex < 4;
    }
}

// ========================================
// 升级/突破成功率计算
// ========================================
// 获取升级成功率
// 不同境界有不同的基础成功率，丹药可提升成功率
function getUpgradeSuccessRate() {
    const rates = [0.90, 0.88, 0.86, 0.84];  // 各境界基础成功率：练气90%，筑基88%，金丹86%，元婴84%
    const baseRate = rates[player.realmIndex] || 0.80;
    const pillBonus = (player.pillBreakthroughBonus || 0);  // 丹药加成
    return $min(baseRate + pillBonus, 1);  // 最高100%
}

// 获取突破成功率
// 突破比升级更难，成功率更低
function getBreakthroughSuccessRate() {
    const rates = [0.35, 0.28, 0.22, 0.17];  // 各境界突破成功率：练气35%，筑基28%，金丹22%，元婴17%
    const baseRate = rates[player.realmIndex] || 0.10;
    const pillBonus = (player.pillBreakthroughBonus || 0);  // 丹药加成
    return $min(baseRate + pillBonus, 1);  // 最高100%
}

// ========================================
// 升级系统
// ========================================

// 执行升级
// 消耗灵力尝试提升一个小境界
function doUpgrade() {
    if (!player.canUpgrade) return;
    if (player.realmIndex < 4 && player.level >= 9) return;
    
    const successRate = getUpgradeSuccessRate();
    const successRateNum = parseFloat(String(successRate));
    
    if (successRateNum >= 1) {
        // 100%成功率：一次性计算升多少级
        const currentInnerLevel = player.innerLevel;
        const currentCultivation = player.cultivation;
        
        // 寰纪凝光系数：消耗 ÷ (1 + 个数)，相当于资源 × (1 + 个数)
        const huangjiCount = getFirstCharacterHuangjiCount();
        const resourceMultiplier = 1 + huangjiCount;
        const effectiveCultivation = $evalBig(`${currentCultivation} * ${resourceMultiplier}`);
        
        // 计算可升级次数
        // 公式：从当前级升n级需要的总灵力 = 100 * 1.3^(innerLevel-1) * (1.3^n - 1) / (1.3 - 1)
        // 反推：n = floor(log_{1.3}(cultivation * 0.3 / (100 * 1.3^(innerLevel-1)) + 1))
        const firstTerm = $pow('1.3', String(currentInnerLevel - 1));
        const denominator = $evalBig(`100 * ${firstTerm}`);
        const innerValue = $evalBig(`${effectiveCultivation} * 0.3 / ${denominator} + 1`);
        const logValue = $log10(innerValue);
        const logRatio = $log10('1.3');
        const nMax = Math.floor(parseFloat($divBig(logValue, logRatio)));
        
        // 化神前最多升到9重
        let maxUpgrade = nMax;
        if (player.realmIndex < 4) {
            maxUpgrade = Math.min(nMax, 9 - player.level);
        }
        
        if (maxUpgrade <= 0) {
            player.canUpgrade = false;
            updateCultivationUI();
            return;
        }
        
        // 计算消耗的灵力（等比数列求和）
        const ratioPower = $pow('1.3', String(maxUpgrade));
        const totalCost = $evalBig(`${denominator} * (${ratioPower} - 1) / 0.3`);
        
        // 实际消耗需要除以系数
        const actualCost = $evalBig(`${totalCost} / ${resourceMultiplier}`);
        player.cultivation = $subBig(player.cultivation, actualCost);
        player.level += maxUpgrade;
        player.innerLevel += maxUpgrade;
        
        calculateCultivationStats();
        player.hp = player.maxHp;
        checkCultivationUpgrade();
        updateplayernameUI();
        updateCultivationUI();
        updateStatusUI();
        updateCharacterTagUI();
        saveGameData();
    } else {
        const required = getRequiredCultivation(player.innerLevel);
        const currentRealm = realmNames[player.realmIndex] || '练气';
        
        const performUpgrade = () => {
            if (!$gteBig(player.cultivation, String(required))) {
                player.canUpgrade = false;
                updateCultivationUI();
                showResultModal(false, '灵力不足，升级失败！');
                return;
            }
            
            player.cultivation = $subBig(player.cultivation, String(required));
            
            if (Math.random() < successRateNum) {
                player.level += 1;
                player.innerLevel += 1;
                calculateCultivationStats();
                player.hp = player.maxHp;
                checkCultivationUpgrade();
                updateplayernameUI();
                updateCultivationUI();
                updateStatusUI();
                saveGameData();
                const newRealm = realmNames[player.realmIndex] || '练气';
                showResultModal(true, `恭喜！境界突破至 ${newRealm} ${player.level}重`);
            } else {
                checkCultivationUpgrade();
                updateplayernameUI();
                updateCultivationUI();
                updateStatusUI();
                saveGameData();
                showResultModal(false, '升级失败，灵力已扣除，下次继续努力！');
            }
        };
        
        confirmModal(
            `消耗 ${formatNumber(required)} 灵力进行升级\n当前境界: ${currentRealm} ${player.level}重\n成功率: ${(successRateNum * 100).toFixed(1)}%\n\n是否确认升级？`,
            performUpgrade
        );
    }
}

// 切换自动升级开关
function toggleAutoUpgrade() {
    player.autoUpgrade = !player.autoUpgrade;
    updateAutoUpgradeBtn();
    saveGameData();
}

// 执行自动升级检查（定时器调用）
function executeAutoUpgrade() {
    if (!player.autoUpgrade) return;
    if (!player.canUpgrade) return;
    
    const successRate = getUpgradeSuccessRate();
    const successRateNum = parseFloat(String(successRate));
    
    if (successRateNum >= 1) {
        doUpgrade();
    }
}

// ========================================
// 突破系统
// ========================================
// 执行突破
// 消耗灵力尝试突破到下一个大境界
function doBreakthrough() {
    if (!player.canBreakthrough) return;
    if (player.level < 9) return;
    if (player.realmIndex >= 4) return;
    
    const required = getRequiredCultivation(player.innerLevel);
    const successRate = getBreakthroughSuccessRate();
    const successRateNum = parseFloat(String(successRate));
    const currentRealm = realmNames[player.realmIndex] || '练气';
    const nextRealm = realmNames[player.realmIndex + 1] || '炼虚';
    
    const performBreakthrough = () => {
        if (typeof MetaSystems !== 'undefined') MetaSystems.onBreakthroughAttempt();
        if (!$gteBig(player.cultivation, String(required))) {
            player.canBreakthrough = false;
            updateCultivationUI();
            if (successRateNum < 1) {
                showResultModal(false, '灵力不足，突破失败！');
            }
            return;
        }
        
        player.cultivation = $subBig(player.cultivation, String(required));
        
        if (Math.random() < successRateNum) {
            player.realmIndex += 1;
            player.level = 1;
            player.innerLevel += 10;
            calculateCultivationStats();
            player.hp = player.maxHp;
            checkCultivationUpgrade();
            updateplayernameUI();
            updateCultivationUI();
            updateStatusUI();
            updateCharacterTagUI();
            saveGameData();
            if (typeof MetaSystems !== 'undefined') MetaSystems.onBreakthroughSuccess(player.realmIndex);
            if (successRateNum < 1) {
                const newRealm = realmNames[player.realmIndex] || '练气';
                showResultModal(true, `恭喜！突破成功，进入 ${newRealm} 境界！`);
            }
        } else {
            checkCultivationUpgrade();
            updateplayernameUI();
            updateCultivationUI();
            updateStatusUI();
            updateCharacterTagUI();
            saveGameData();
            if (successRateNum < 1) {
                showResultModal(false, '突破失败，灵力已扣除，下次继续努力！');
            }
        }
    };
    
    if (successRateNum >= 1) {
        performBreakthrough();
    } else {
        confirmModal(
            `消耗 ${formatNumber(required)} 灵力进行突破\n当前境界: ${currentRealm} ${player.level}重\n目标境界: ${nextRealm} 1重\n成功率: ${(successRateNum * 100).toFixed(1)}%\n\n突破失败只会损失灵力，是否继续？`,
            performBreakthrough
        );
    }
}

