// ========================================
// 弹窗系统
// ========================================
function getModalOpacity() {
    return localStorage.getItem('wenziguaji_modal_opacity') || '0.3';
}

// 显示普通弹窗
// 参数：content - 内容，isHtml - 是否为HTML格式
let modalZIndexCounter = 10003;

function showModal(content, isHtml = false, autoCloseMs = 0) {
    const modal = document.createElement('div');
    modal.className = 'customModal';
    modalZIndexCounter += 2;
    modal.style.cssText = `position:fixed;top:0;left:0;width:100%;height:100%;background:rgba(0,0,0,${getModalOpacity()});display:flex;justify-content:center;align-items:center;z-index:${modalZIndexCounter};backdrop-filter:blur(4px);-webkit-backdrop-filter:blur(4px);`;
    modal.onclick = (e) => {
        if (e.target === modal) closeModal();
    };
    
    // 根据内容类型生成不同的HTML
    if (isHtml) {
        modal.innerHTML = `
            <div style="background:rgba(0,0,0,${getModalOpacity()});border:1px solid #aaa;border-radius:15px;padding:20px;color:var(--text-color,#fff);font-family:monospace;max-width:900px;max-height:90vh;overflow-y:auto;text-align:center;box-shadow:0 0 10px rgba(255,255,255,0.2),inset 0 0 10px rgba(255,255,255,0.05);">
                ${content}
            </div>
        `;
    } else {
        modal.innerHTML = `
            <div style="background:rgba(0,0,0,${getModalOpacity()});border:1px solid #aaa;border-radius:15px;padding:20px;color:var(--text-color,#fff);font-family:monospace;max-width:900px;max-height:90vh;overflow-y:auto;box-shadow:0 0 10px rgba(255,255,255,0.2),inset 0 0 10px rgba(255,255,255,0.05);">
                <pre style="white-space:pre-wrap;margin:0;color:var(--text-color,#fff);">${content}</pre>
            </div>
        `;
    }
    document.body.appendChild(modal);
    
    if (autoCloseMs > 0) {
        setTimeout(() => {
            const modals = document.querySelectorAll('.customModal');
            if (modals.length > 0) {
                closeModal();
            }
        }, autoCloseMs);
    }
}

// 显示确认弹窗
// 参数：message - 提示信息，onConfirm - 确认回调函数
function confirmModal(message, onConfirm) {
    const modal = document.createElement('div');
    modal.className = 'customModal';
    modalZIndexCounter += 2;
    modal.style.cssText = `position:fixed;top:0;left:0;width:100%;height:100%;background:rgba(0,0,0,${getModalOpacity()});display:flex;justify-content:center;align-items:center;z-index:${modalZIndexCounter};backdrop-filter:blur(4px);-webkit-backdrop-filter:blur(4px);`;
    modal.innerHTML = `
        <div style="background:rgba(0,0,0,${getModalOpacity()});border:1px solid #aaa;border-radius:15px;padding:20px;color:var(--text-color,#fff);font-family:monospace;text-align:center;min-width:300px;box-shadow:0 0 10px rgba(255,255,255,0.2),inset 0 0 10px rgba(255,255,255,0.05);">
            <pre style="white-space:pre-wrap;margin:0 0 20px 0;color:var(--text-color,#fff);">${message}</pre>
            <div style="display:flex;gap:20px;justify-content:center;">
                <button id="confirmBtn" style="background:#fff;color:#000;border:1px solid #fff;padding:8px 24px;cursor:pointer;font-family:monospace;font-weight:bold;border-radius:5px;">确定</button>
                <button id="cancelBtn" class="sbtn-820" style="padding:8px 24px;font-family:monospace;border-radius:5px">取消</button>
            </div>
        </div>
    `;
    document.body.appendChild(modal);
    
    // 绑定确定按钮事件
    document.getElementById('confirmBtn').addEventListener('click', function() {
        closeModal();
        if (typeof onConfirm === 'function') {
            setTimeout(onConfirm, 50);  // 延迟执行，确保弹窗已关闭
        }
    });
    // 绑定取消按钮事件
    document.getElementById('cancelBtn').addEventListener('click', function() {
        closeModal();
    });
}

// ========================================
// 结果弹窗
// ========================================
// 显示结果弹窗
// 参数：success - 是否成功，message - 提示信息，onClose - 关闭回调
function showResultModal(success, message, onClose) {
    // 根据成功/失败设置不同颜色
    const color = success ? '#fff' : '#f00';
    const borderColor = success ? '#fff' : '#f00';
    const title = success ? '【 成功 】' : '【 失败 】';
    
    const modal = document.createElement('div');
    modal.className = 'customModal';
    modalZIndexCounter += 2;
    modal.style.cssText = `position:fixed;top:0;left:0;width:100%;height:100%;background:rgba(0,0,0,${getModalOpacity()});display:flex;justify-content:center;align-items:center;z-index:${modalZIndexCounter};backdrop-filter:blur(4px);-webkit-backdrop-filter:blur(4px);`;
    modal.innerHTML = `
        <div style="background:rgba(0,0,0,${getModalOpacity()});border:2px solid ${borderColor};padding:20px;color:${color};font-family:monospace;text-align:center;min-width:300px;border-radius:4px;">
            <pre style="white-space:pre-wrap;margin:0 0 20px 0;color:${color};">${title}

${message}</pre>
            <button id="resultConfirmBtn" style="background:${color};color:#000;border:1px solid ${borderColor};padding:8px 24px;cursor:pointer;font-family:monospace;font-weight:bold;">[确定]</button>
        </div>
    `;
    document.body.appendChild(modal);
    
    // 绑定确定按钮事件
    document.getElementById('resultConfirmBtn').addEventListener('click', function() {
        closeModal();
        if (typeof onClose === 'function') {
            setTimeout(onClose, 50);
        }
    });
}

// ========================================
// 弹窗关闭
// ========================================
// 关闭所有弹窗
// 移除页面上所有的自定义弹窗
function closeModal() {
    const modals = document.querySelectorAll('.customModal');
    if (modals.length > 0) {
        const topModal = modals[modals.length - 1];
        topModal.remove();
        modalZIndexCounter -= 2;
    }
    
    if (document.querySelectorAll('.customModal').length === 0) {
        modalZIndexCounter = 10003;
    }
    
    window._isImportingFile = false;
    
    if (window._needReloadPageAfterImport) {
        window._needReloadPageAfterImport = false;
        location.reload();
        return;
    }
    
    if (window._needReloadPageAfterOffline) {
        window._needReloadPageAfterOffline = false;
        location.reload();
        return;
    }
    
    if (window.currentCharIdx !== undefined && document.querySelectorAll('.customModal').length === 0) {
        showLunDaoTaiCharInfo(window.currentCharIdx);
    }
}

function closeAllModals() {
    const modals = document.querySelectorAll('.customModal');
    modals.forEach(m => m.remove());
    modalZIndexCounter = 10003;
}

// 显示游戏说明
function showGameGuide() {
    if (typeof AndroidInterface !== 'undefined' && AndroidInterface.readFile) {
        try {
            const content = AndroidInterface.readFile('游戏说明.txt');
            if (content) {
                displayGameGuide(content);
                return;
            }
        } catch (e) {
            console.warn('AndroidInterface.readFile failed:', e);
        }
    }
    
    fetch('游戏说明.txt')
        .then(response => response.text())
        .then(text => {
            displayGameGuide(text);
        })
        .catch(error => {
            showModal('<span style="color:#ff0;">【 系统提示 】</span><br><br><span style="color:#f66;">加载游戏说明失败</span><br><br><button onclick="closeModal()" class="sbtn">关闭</button>', true);
        });
}

// 打开存档标签页
function openSaveTab() {
    const tabs = document.querySelectorAll('.tab');
    const tabContents = document.querySelectorAll('.tab-content');
    tabs.forEach(t => t.classList.remove('active'));
    tabContents.forEach(c => c.classList.remove('active'));
    document.querySelector('.tab[data-tab="save"]').classList.add('active');
    document.getElementById('tab-save').classList.add('active');
    
    const qiYunInput = document.getElementById('qiYunInput');
    if (qiYunInput) {
        qiYunInput.value = getFanXuLuFloor() || 1;
    }
}

function saveQiYunSetting() {
    const input = document.getElementById('qiYunInput');
    if (!input) return;
    
    let value = parseInt(input.value) || 1;
    value = Math.max(0, Math.min(10000, value));
    input.value = value;
    
    setFanXuLuFloor(value);
    
    const coef = getQiYunCoefficient();
    const p1 = getQiYunProbability(0.01) * 100;
    const p5 = getQiYunProbability(0.05) * 100;
    
    showModal(`<span style="color:#0f0;">【 气运设置已保存 】</span><br><br>当前气运值: ${value}<br>偏移系数: ${coef.toFixed(4)}<br><br><span style="color:#4fc3f7;">概率提升示例：</span><br>1% → ${p1.toFixed(2)}%<br>5% → ${p5.toFixed(2)}%<br><br><span style="color:var(--text-color-dim,#888);font-size:12px;">公式: 新随机数 = 原随机数 × 系数</span>`, true);
}

