    let progress = 0;
    if (required > 0) {
        progress = $min(100, $floor($evalBig(`${cultivation} / ${required}`) * 100));
    }
    const filled = $max(0, $min(10, $floor(progress / 10)));
    const progressBar = '█'.repeat(filled) + '░'.repeat(10 - filled);

