// 执行神通自动升级
// 遍历所有已开启的神通，每个都尝试升级（需要对应阶数灵药）
function executeDivineAutoUpgrade() {
    if (!player.divineAutoUpgrade || player.divineAutoUpgradeList.length === 0) return;
    
    const list = player.divineAutoUpgradeList;
    
    // 遍历所有已勾选的神通，每个都尝试升级
    for (const abilityKey of list) {
        const ability = player.divineAbilities[abilityKey];
        const currentLevel = Number(ability.level) || 0;
        const nextLevel = currentLevel + 1;
        
        // 查找足够阶数的灵药（每次重新查找，因为升级后索引可能变化）
        const herbs = findHerbsByGrade(nextLevel);
        if (herbs.length === 0) continue;
        
        // 选择最高阶的灵药进行升级
        herbs.sort((a, b) => b.item.grade - a.item.grade);
        const bestHerb = herbs[0];
        
        // 执行升级（静默模式，不弹窗）
        upgradeDivineAbilitySilent(abilityKey, bestHerb.index);
    }
}

// 静默升级神通（自动功能使用）
function upgradeDivineAbilitySilent(abilityKey, bagIndex) {
    const ability = player.divineAbilities[abilityKey];
    
    if (bagIndex === null || !player.bag[bagIndex]) return;
    
    const herb = player.bag[bagIndex];
    if (herb.grade < 1) return;
    
    herb.count = $subBig(herb.count, '1');
    if ($lteBig(herb.count, '0')) {
        player.bag.splice(bagIndex, 1);
    }
    
    ability.level = Number(herb.grade);
    
    updateCultivationUI();
    updateBagUI();
    saveGameData();
}

