// 执行所有自动功能（统一定时器）
// 每5秒执行一次，本灵根自动更换第1个，灵脉第2个，仙脉第3个，背包物品最后，其他随机
function executeAutoFunctions() {
    // 本灵根自动更换第1个执行（不参与随机排列）
    if (player.autoSelectHighestHerb) {
        autoSelectHighestGradeHerb();
    }
    
    // 灵脉投入第2个执行（不参与随机排列）
    if (player.autoDepositStone) {
        executeAutoDepositStone();
    }
    
    // 仙脉投入第3个执行（不参与随机排列）
    if (player.autoDepositImmortalVein) {
        executeAutoDepositImmortalVein();
    }
    
    // 收集需要执行的自动功能（排除固定顺序的功能）
    const autoFunctions = [];
    
    // 法则自动加点
    if (player.lawAutoAddPoints && player.lawAutoAddPointsList.length > 0) {
        autoFunctions.push({ name: 'lawAutoAddPoints', fn: executeLawAutoAddPoints });
    }
    
    // 法宝自动加点
    if (player.treasureAutoAddPoints && player.treasureAutoAddPointsList.length > 0) {
        autoFunctions.push({ name: 'treasureAutoAddPoints', fn: executeTreasureAutoAddPoints });
    }
    
    // 境界自动升级
    if (player.autoUpgrade && player.canUpgrade) {
        autoFunctions.push({ name: 'autoUpgrade', fn: executeAutoUpgrade });
    }
    
    // 自动聚灵阵
    if (player.autoGatheringArray) {
        autoFunctions.push({ name: 'autoGatheringArray', fn: executeAutoGatheringArray });
    }
    
    // 自动灵田
    if (player.autoSpiritField) {
        autoFunctions.push({ name: 'autoSpiritField', fn: executeAutoSpiritField });
    }
    
    // 神通自动升级
    if (player.divineAutoUpgrade && player.divineAutoUpgradeList.length > 0) {
        autoFunctions.push({ name: 'divineAutoUpgrade', fn: executeDivineAutoUpgrade });
    }
    
    // 随机排列执行顺序
    for (let i = autoFunctions.length - 1; i > 0; i--) {
        const j = Math.floor(Math.random() * (i + 1));
        [autoFunctions[i], autoFunctions[j]] = [autoFunctions[j], autoFunctions[i]];
    }
    
    // 依次执行随机排列后的功能
    for (const func of autoFunctions) {
        func.fn();
    }
    
    // 背包物品自动使用最后执行
    if (player.autoUseBagItem && player.autoUseBagItemTypes.length > 0) {
        executeAutoUseBagItem();
    }
}

// 执行自动使用背包物品
// 每5秒执行一次，根据用户选择的类型和起始行自动使用物品
function executeAutoUseBagItem() {
    if (!player.autoUseBagItem || player.autoUseBagItemTypes.length === 0) return;

    const herbNames = ['灵心草', '幽兰花', '朱血藤', '银灵叶', '金果', '玉髓', '星尘花', '太初叶', '混元果', '虚无根',
                       '虚无空冥草', '先天一炁芝', '鸿蒙初形花', '混元真质蕊', '两仪混沌莲'];
    const pillNames = ['天元丹', '淬体丹', '固灵丹', '暴神丹', '灵犀丹', '破境丹'];

    const skipCount = player.autoUseBagItemStartRow || 0;
    const startIndex = player.autoUseBagItemTypes.includes('afterRow') ? skipCount : 0;

    for (const type of player.autoUseBagItemTypes) {
        if (type === 'afterRow') continue;
        
        if (type === 'timeCrystal') {
            for (let i = player.bag.length - 1; i >= startIndex; i--) {
                const item = player.bag[i];
                if (item && item.name === '时间结晶' && $gteBig(item.count, '1')) {
                    const count = parseInt(String(item.count).includes('e') ? parseFloat(String(item.count)).toString() : String(item.count).split('.')[0]);
                    doUseTimeCrystalSilent(i, count);
                }
            }
        } else if (type === 'huangji') {
            for (let i = player.bag.length - 1; i >= startIndex; i--) {
                const item = player.bag[i];
                if (item && item.name === '寰纪凝光' && $gteBig(item.count, '1')) {
                    const count = parseInt(String(item.count).includes('e') ? parseFloat(String(item.count)).toString() : String(item.count).split('.')[0]);
                    doUsehuangjiSilent(i, count);
                }
            }
        } else if (type === 'allPills') {
            for (let i = player.bag.length - 1; i >= startIndex; i--) {
                const item = player.bag[i];
                if (item && pillNames.includes(item.name) && $gteBig(item.count, '1')) {
                    const count = parseInt(String(item.count).includes('e') ? parseFloat(String(item.count)).toString() : String(item.count).split('.')[0]);
                    doUsePillSilent(i, count);
                }
            }
        } else if (type === 'allHerbs') {
            for (let i = player.bag.length - 1; i >= startIndex; i--) {
                const item = player.bag[i];
                if (item && herbNames.includes(item.name) && $gteBig(item.count, '1')) {
                    const count = parseInt(String(item.count).includes('e') ? parseFloat(String(item.count)).toString() : String(item.count).split('.')[0]);
                    doUseItemSilent(i, count);
                }
            }
        }
    }
    checkCultivationUpgrade();
    calculateCultivationStats();
    updateBagUI();
    updateCultivationUI();
    updateStatusUI();
    saveGameData();
}

// 静默使用灵草（不显示弹窗）
// 计算灵力收益和世界本源增加，更新背包数据
function doUseItemSilent(slotIndex, count) {
    const item = player.bag[slotIndex];
    if (!item || $lteBig(item.count, '0')) return;

    const availableCount = $gteBig(item.count, String(count)) ? count : parseInt(String(item.count).includes('e') ? parseFloat(String(item.count)).toString() : String(item.count).split('.')[0]);
    const useCount = Math.min(count, availableCount);
    const cultivationGain = $evalBig(`2 * 6.1615 ^ ${item.grade} * ${useCount}`);
    player.cultivation = $addBig(player.cultivation, cultivationGain);

    const herbNames = ['灵心草', '幽兰花', '朱血藤', '银灵叶', '金果', '玉髓', '星尘花', '太初叶', '混元果', '虚无根',
                       '虚无空冥草', '先天一炁芝', '鸿蒙初形花', '混元真质蕊', '两仪混沌莲'];
    if (herbNames.includes(item.name) && item.grade >= 1) {
        const benYuanRates = [0, 0.05, 0.07, 0.1, 0.14, 0.2, 0.3, 0.45, 0.65, 1];
        const rate = item.grade >= 9 ? 1 : (benYuanRates[item.grade] || 0);
        const benYuanGain = useCount * rate;
        if (benYuanGain > 0) {
            addFirstCharacterBenYuan(benYuanGain);
            player.benYuan = getFirstCharacterBenYuan();
        }
    }

    item.count = $subBig(item.count, String(useCount));
    if ($lteBig(item.count, '0')) {
        player.bag.splice(slotIndex, 1);
    }
    saveGameData();
}

// 静默使用时间结晶（不显示弹窗）
// 获得指定秒数的离线收益
function doUseTimeCrystalSilent(slotIndex, count) {
    const item = player.bag[slotIndex];
    if (!item || $lteBig(item.count, '0')) return;

    const availableCount = $gteBig(item.count, String(count)) ? count : parseInt(String(item.count).includes('e') ? parseFloat(String(item.count)).toString() : String(item.count).split('.')[0]);
    const useCount = Math.min(count, availableCount);
    const totalSeconds = useCount * 600;

    processOfflineRewards(player, true, totalSeconds);

    item.count = $subBig(item.count, String(useCount));
    if ($lteBig(item.count, '0')) {
        player.bag.splice(slotIndex, 1);
    }
    saveGameData();
}

// 静默使用寰纪凝光（不显示弹窗）
// 增加寰纪凝光计数，降低修炼消耗
function doUsehuangjiSilent(slotIndex, count) {
    const item = player.bag[slotIndex];
    if (!item || $lteBig(item.count, '0')) return;

    const availableCount = $gteBig(item.count, String(count)) ? count : parseInt(String(item.count).includes('e') ? parseFloat(String(item.count)).toString() : String(item.count).split('.')[0]);
    const useCount = Math.min(count, availableCount);

    // 获取本体角色数据并更新寰纪凝光服用个数
    const charList = getCharacterList();
    const mainChar = charList[0];
    if (!mainChar) return;
    const firstCharId = mainChar.id;
    const firstCharSaveKey = getCharacterSaveKey(firstCharId);
    const firstCharDataStr = localStorage.getItem(firstCharSaveKey);
    if (!firstCharDataStr) return;
    let firstCharData;
    try {
        firstCharData = JSON.parse(firstCharDataStr);
    } catch (e) {
        return;
    }

    const prevCount = firstCharData.huangjiCount || 0;
    firstCharData.huangjiCount = prevCount + useCount;
    localStorage.setItem(firstCharSaveKey, JSON.stringify(firstCharData));

    const newCount = firstCharData.huangjiCount;

    // 如果当前角色是本体，同步更新 player.huangjiCount
    // 如果是化身，不设置 player.huangjiCount（化身不应有此属性）
    const currentCharId = getCurrentCharId();
    if (currentCharId === firstCharId) {
        player.huangjiCount = newCount;
    }

    item.count = $subBig(item.count, String(useCount));
    if ($lteBig(item.count, '0')) {
        player.bag.splice(slotIndex, 1);
    }
    calculateCultivationStats();
    saveGameData();
}

// 静默使用丹药（不显示弹窗）
// 根据丹药类型更新对应属性，记录服用次数和最高阶数
function doUsePillSilent(slotIndex, count) {
    const item = player.bag[slotIndex];
    if (!item || $lteBig(item.count, '0')) return;

    const pillNames = {
        '破境丹': { type: 'breakthrough', effectValue: 0.01 },
        '固灵丹': { type: 'defense', effectValue: 1 },
        '淬体丹': { type: 'health', effectValue: 10 },
        '暴神丹': { type: 'critDamage', effectValue: 10 },
        '灵犀丹': { type: 'critRate', effectValue: 0.2 },
        '天元丹': { type: 'attack', effectValue: 1 }
    };

    const pillInfo = pillNames[item.name];
    if (!pillInfo) return;

    const availableCount = $gteBig(item.count, String(count)) ? count : parseInt(String(item.count).includes('e') ? parseFloat(String(item.count)).toString() : String(item.count).split('.')[0]);
    const useCount = Math.min(count, availableCount);

    // 同步更新localStorage中的本体角色存档数据
    const charList = getCharacterList();
    const mainChar = charList[0];
    if (mainChar) {
        const firstCharId = mainChar.id;
        const firstCharSaveKey = getCharacterSaveKey(firstCharId);
        const firstCharDataStr = localStorage.getItem(firstCharSaveKey);
        if (firstCharDataStr) {
            try {
                let firstCharData = JSON.parse(firstCharDataStr);
                if (!firstCharData.consumedPills) {
                    firstCharData.consumedPills = {
                        attack: { total: 0, maxGrade: 0 },
                        health: { total: 0, maxGrade: 0 },
                        defense: { total: 0, maxGrade: 0 },
                        critDamage: { total: 0, maxGrade: 0 },
                        critRate: { total: 0, maxGrade: 0 },
                        breakthrough: { total: 0, maxGrade: 0 }
                    };
                }
                if (!firstCharData.consumedPills[pillInfo.type]) {
                    firstCharData.consumedPills[pillInfo.type] = { total: 0, maxGrade: 0 };
                }
                const prevTotal = firstCharData.consumedPills[pillInfo.type].total || 0;
                const prevMaxGrade = firstCharData.consumedPills[pillInfo.type].maxGrade || 0;
                firstCharData.consumedPills[pillInfo.type].total = prevTotal + useCount;
                firstCharData.consumedPills[pillInfo.type].maxGrade = Math.max(prevMaxGrade, item.grade);
                localStorage.setItem(firstCharSaveKey, JSON.stringify(firstCharData));
            } catch (e) {}
        }
    }

    if (!player.consumedPills[pillInfo.type]) {
        player.consumedPills[pillInfo.type] = { total: 0, maxGrade: 0 };
    }
    player.consumedPills[pillInfo.type].total += useCount;
    if (item.grade > player.consumedPills[pillInfo.type].maxGrade) {
        player.consumedPills[pillInfo.type].maxGrade = item.grade;
    }

    item.count = $subBig(item.count, String(useCount));
    if ($lteBig(item.count, '0')) {
        player.bag.splice(slotIndex, 1);
    }
    calculateCultivationStats();
    saveGameData();
}

// 自动升级阵眼灵药
// 检查背包中最高阶灵药，自动替换阵眼中的低阶灵药
function autoUpgradeArrayNodes() {
    const nodeNames = ['虚无空冥草', '先天一炁芝', '鸿蒙初形花', '混元真质蕊', '两仪混沌莲'];
    for (let i = 0; i < 5; i++) {
        const expectedName = nodeNames[i];
        const herbs = player.bag.filter(item => item.name === expectedName);
        if (herbs.length === 0) continue;
        herbs.sort((a, b) => b.grade - a.grade);
        const highestGrade = herbs[0].grade;
        const currentNode = player.arrayNodes[i];
        if (currentNode.grade < highestGrade) {
            bindArrayNodeSilent(i, highestGrade);
        }
    }
}

// 静默绑定阵眼灵药（不显示弹窗）
// 将指定阶位的灵药绑定到指定阵眼位置
function bindArrayNodeSilent(nodeIndex, grade) {
    const gradeNum = Number(grade);
    const nodeNames = ['虚无空冥草', '先天一炁芝', '鸿蒙初形花', '混元真质蕊', '两仪混沌莲'];
    const expectedName = nodeNames[nodeIndex];

    if (player.arrayNodes[nodeIndex].grade > 0) {
        const oldGrade = player.arrayNodes[nodeIndex].grade;
        const existingItem = player.bag.find(item => item.name === expectedName && item.grade === oldGrade);
        if (existingItem) {
            existingItem.count = $addBig(existingItem.count, '1');
        } else {
            player.bag.push({ name: expectedName, grade: oldGrade, count: '1' });
        }
    }

    const bagItem = player.bag.find(item => item.name === expectedName && item.grade === gradeNum);
    if (bagItem) {
        bagItem.count = $subBig(bagItem.count, '1');
        if ($lteBig(bagItem.count, '0')) {
            player.bag = player.bag.filter(item => !(item.name === expectedName && item.grade === gradeNum));
        }
    }

    player.arrayNodes[nodeIndex].grade = gradeNum;
    clearSpiritFieldSpeedBonusCache();
    updateEquipmentUI();
}

// ========================================
// 韵灵系统
// ========================================
// 孕育韵灵
function birthYunLing() {
    if (!$gteBig(player.immortalVeinStone, '1')) {
        showModal('<span style="color:#f66;">仙脉值不足，无法孕育韵灵</span>');
        return;
    }
    
    if (player.yunLing && player.yunLing.exists) {
        showModal('<span style="color:#f66;">韵灵已存在，无法重复孕育</span>');
        return;
    }
    
    player.yunLing = {
        exists: true,
        name: '💫仙脉之灵',
        bornTime: Date.now(),
        talent1: {
            hpBonus: '0',
            atkBonus: '0',
            defBonus: '0'
        },
        talent2: {
            totalResurrected: 0
        }
    };
    
    saveGameData();
    updateEquipmentUI();
    showModal(`<span style="color:#0f0;">韵灵孕育成功！</span><br><br>你的仙脉中诞生了一个灵体，名为<span style="color:#ff0;">💫仙脉之灵</span>`);
}

// 重命名韵灵
function renameYunLing(newName) {
    if (!player.yunLing || !player.yunLing.exists) {
        return;
    }

    newName = newName.trim();
    if (newName.length === 0) {
        newName = '💫仙脉之灵';
    }
    if (newName.length > 10) {
        newName = newName.substring(0, 10);
    }

    player.yunLing.name = newName;
    saveGameData();
    closeModal();
    updateEquipmentUI();
}

// 显示韵灵属性面板
function showYunLingPanel() {
    if (!player.yunLing || !player.yunLing.exists) {
        if ($gtBig(player.immortalVeinStone, '0')) {
            player.yunLing = {
                exists: true,
                name: '💫仙脉之灵',
                bornTime: Date.now(),
                talent1: {
                    hpBonus: '0',
                    atkBonus: '0',
                    defBonus: '0'
                },
                talent2: {
                    totalResurrected: 0
                }
            };
            saveGameData();
        } else {
            return;
        }
    }

    const stats = calcYunLingStats();
    const yunLing = player.yunLing;
    const skillLevels = getYunLingSkillLevels();
    const benYuanCount = getFirstCharacterBenYuan();

    const talent2Count = yunLing.talent2?.totalResurrected || 0;
    const baseHp = stats ? formatNumber(stats.baseHp) : '0';
    const baseAtk = stats ? formatNumber(stats.baseAtk) : '0';
    const baseDef = stats ? formatNumber(stats.baseDef) : '0';
    const hpBonus = stats ? formatNumber(stats.hpBonus) : '0';
    const atkBonus = stats ? formatNumber(stats.atkBonus) : '0';
    const defBonus = stats ? formatNumber(stats.defBonus) : '0';

    // 技能效果值
    const skill1Effect = getYunLingSkillEffect(1, skillLevels.skill1);
    const skill2Effect = getYunLingSkillEffect(2, skillLevels.skill2);
    const skill3Effect = getYunLingSkillEffect(3, skillLevels.skill3);
    const skill4Effect = getYunLingSkillEffect(4, skillLevels.skill4);
    
    // 仙源无限下限百分比（用于显示）
    const skill1MinRates = [8, 16, 32, 64, 128];
    const skill1MinPercent = skill1MinRates[Math.max(0, Math.min(4, skillLevels.skill1 - 1))];
    
    // 仙源无限实际百分比计算（用于显示）
    let skill1ActualPercents = { hp: skill1MinPercent, atk: skill1MinPercent, def: skill1MinPercent };
    let skill1CalcInfo = '';
    if (stats) {
        const hpLg10 = parseFloat($log10(stats.hp)) || 1;
        const atkLg10 = parseFloat($log10(stats.attack)) || 1;
        const defLg10 = parseFloat($log10(stats.defense)) || 1;
        const hpRate = Math.max(skill1Effect * hpLg10, skill1MinPercent / 100) * 100;
        const atkRate = Math.max(skill1Effect * atkLg10, skill1MinPercent / 100) * 100;
        const defRate = Math.max(skill1Effect * defLg10, skill1MinPercent / 100) * 100;
        skill1ActualPercents = { hp: hpRate.toFixed(1), atk: atkRate.toFixed(1), def: defRate.toFixed(1) };
        const basePercent = (skill1Effect * 100).toFixed(2);
        skill1CalcInfo = `<br><span style="color:#888;font-size:10px;">公式：max(${basePercent}% × lg10(属性), ${skill1MinPercent}%)，三维分别计算。升级变化8-16-32-64-128</span>`;
        skill1CalcInfo += `<br><span style="color:#888;font-size:10px;">当前：生命${skill1ActualPercents.hp}%，攻击${skill1ActualPercents.atk}%，防御${skill1ActualPercents.def}%</span>`;
    }

    let bonusHtml = '';
    if (stats) {
        bonusHtml = `
            <div style="margin-top:10px;text-align:left;">
                <div style="color:#ff0;margin-bottom:5px;">【 属性 】</div>
                <div style="color:var(--text-color-dim,#888);font-size:12px;margin-left:10px;line-height:1.8;">
                    <div>生命: ${baseHp} → +${hpBonus}</div>
                    <div>攻击: ${baseAtk} → +${atkBonus}</div>
                    <div>防御: ${baseDef} → +${defBonus}</div>
                    <div>速度: 100 (固定值)</div>
                </div>
            </div>
        `;
    }
    
    // 技能升级按钮
    function getSkillUpgradeHtml(skillIndex, currentLevel) {
        if (currentLevel >= 5) {
            return '<span style="color:#0f0;">已满级</span>';
        }
        const cost = getYunLingSkillUpgradeCost(currentLevel - 1);
        const canUpgrade = $gteBig(benYuanCount, cost);
        return `<button onclick="upgradeYunLingSkill(${skillIndex})" class="sbtn-xs" ${canUpgrade ? '' : 'disabled'}>升级(${cost}本源)</button>`;
    }
    
    let talentHtml = `
        <div style="margin-top:10px;text-align:left;">
            <div style="color:#ff0;margin-bottom:5px;">【 天赋 】</div>
            <div style="color:var(--text-color-dim,#888);font-size:11px;margin-left:10px;line-height:1.8;">
                <div style="margin-bottom:8px;padding:5px;border:1px solid rgba(255,255,255,0.1);border-radius:3px;">
                    <div style="display:flex;justify-content:space-between;align-items:center;">
                        <span style="color:#0ff;">仙源无限 Lv.${skillLevels.skill1}</span>
                        ${getSkillUpgradeHtml(1, skillLevels.skill1)}
                    </div>
                    <div style="margin-top:3px;">在线战斗中，若自身死亡，战斗胜利后可吸收对方逸散道则重生，并且自身永久提升三维属性。可无限叠加。${skill1CalcInfo}</div>
                </div>
                <div style="margin-bottom:8px;padding:5px;border:1px solid rgba(255,255,255,0.1);border-radius:3px;">
                    <div style="display:flex;justify-content:space-between;align-items:center;">
                        <span style="color:#0ff;">护道回春 Lv.${skillLevels.skill2}</span>
                        ${getSkillUpgradeHtml(2, skillLevels.skill2)}
                    </div>
                    <div style="margin-top:3px;">你死亡时，韵灵复活你，恢复最大${skill2Effect}%血量。每次战斗最多一次。<br><span style="color:#888;">累计复活次数: ${talent2Count}</span></div>
                </div>
                <div style="margin-bottom:8px;padding:5px;border:1px solid rgba(255,255,255,0.1);border-radius:3px;">
                    <div style="display:flex;justify-content:space-between;align-items:center;">
                        <span style="color:#0ff;">道锁疾锋 Lv.${skillLevels.skill3}</span>
                        ${getSkillUpgradeHtml(3, skillLevels.skill3)}
                    </div>
                    <div style="margin-top:3px;">每次攻击使对方攻速变为当前值的${(skill3Effect * 100).toFixed(1)}%（叠加道滞领域后递减）</div>
                </div>
                <div style="margin-bottom:8px;padding:5px;border:1px solid rgba(255,255,255,0.1);border-radius:3px;">
                    <div style="display:flex;justify-content:space-between;align-items:center;">
                        <span style="color:#0ff;">脉蚀易伤 Lv.${skillLevels.skill4}</span>
                        ${getSkillUpgradeHtml(4, skillLevels.skill4)}
                    </div>
                    <div style="margin-top:3px;">易伤增伤，仙脉本源侵蚀目标，触发全伤提升debuff。每次递增${((skill4Effect - 1) * 100).toFixed(0)}%（加法模式，1+${(skill4Effect - 1).toFixed(1)}×次数），影响所有攻击</div>
                </div>
            </div>
        </div>
        <div style="margin-top:10px;text-align:center;color:#888;font-size:11px;">
            当前本源: ${formatNumber(benYuanCount)} | 技能等级化身共享
        </div>
    `;
    
    let actionHtml = '';
    actionHtml += `<div style="margin-top:15px;text-align:center;"><button onclick="closeModal()" class="sbtn">确定</button></div>`;

    showModal(`
        <span style="color:#f0f;">❖ 韵灵详情 ❖</span><br><br>
        <div style="text-align:center;">
            <div style="font-size:18px;color:#ff0;cursor:pointer;" onclick="showRenameYunLingModal()">${(yunLing.name && yunLing.name !== '仙脉之灵') ? yunLing.name : '💫仙脉之灵'}</div>
        </div>
        ${bonusHtml}
        ${talentHtml}
        ${actionHtml}
    `, true);
}

// 确认升级仙脉之灵技能
function confirmUpgradeYunLingSkill(skillIndex) {
    const skillLevels = getYunLingSkillLevels();
    const skillKey = 'skill' + skillIndex;
    const currentLevel = skillLevels[skillKey];
    
    if (currentLevel >= 5) {
        showModal('<span style="color:#f66;">该技能已满级！</span>');
        return;
    }
    
    const cost = getYunLingSkillUpgradeCost(currentLevel - 1);
    const benYuanCount = getFirstCharacterBenYuan();
    
    if ($ltBig(benYuanCount, cost)) {
        showModal(`<span style="color:#f66;">本源不足！需要${cost}本源</span>`);
        return;
    }
    
    const afterBenYuan = $subBig(benYuanCount, cost);
    const skillNames = ['', '仙源无限', '护道回春', '道锁疾锋', '脉蚀易伤'];
    
    showConfirmModal(
        '技能升级',
        `<div style="text-align:left;">
            <div>技能：<span style="color:#0ff;">${skillNames[skillIndex]}</span> Lv.${currentLevel} → Lv.${currentLevel + 1}</div>
            <div>消耗：<span style="color:#ff0;">${cost}</span> 本源</div>
            <div>剩余：<span style="color:#ff0;">${formatNumber(afterBenYuan)}</span> 本源</div>
            <div style="margin-top:10px;color:#f66;font-size:11px;">⚠️ 本源存量影响修炼速度，请谨慎消耗！</div>
        </div>`,
        `doUpgradeYunLingSkill(${skillIndex})`
    );
}

// 执行升级仙脉之灵技能
function doUpgradeYunLingSkill(skillIndex) {
    const skillLevels = getYunLingSkillLevels();
    const skillKey = 'skill' + skillIndex;
    const currentLevel = skillLevels[skillKey];
    
    const cost = getYunLingSkillUpgradeCost(currentLevel - 1);
    
    // 扣除本源并升级技能
    const charList = getCharacterList();
    const mainChar = charList[0];
    if (!mainChar) return;
    const firstCharId = mainChar.id;
    const saveKey = getCharacterSaveKey(firstCharId);
    const charDataStr = localStorage.getItem(saveKey);
    if (!charDataStr) return;
    
    try {
        const charData = JSON.parse(charDataStr);
        // 扣除本源
        const currentBenYuan = String(charData.benYuan || '0');
        charData.benYuan = $subBig(currentBenYuan, cost);
        // 更新技能等级
        if (!charData.yunLingSkillLevels) {
            charData.yunLingSkillLevels = { skill1: 1, skill2: 1, skill3: 1, skill4: 1 };
        }
        charData.yunLingSkillLevels[skillKey] = currentLevel + 1;
        localStorage.setItem(saveKey, JSON.stringify(charData));
        
        // 如果当前角色是主角色，同步更新player对象并保存
        const currentCharId = getCurrentCharId();
        if (currentCharId === firstCharId) {
            player.benYuan = charData.benYuan;
            player.yunLingSkillLevels = charData.yunLingSkillLevels;
            saveGameData();
        }
        
        // 刷新面板
        closeModal();
        showYunLingPanel();
    } catch (e) {
        showModal('<span style="color:#f66;">升级失败！</span>');
    }
}

// 升级仙脉之灵技能（保留旧函数名兼容）
function upgradeYunLingSkill(skillIndex) {
    confirmUpgradeYunLingSkill(skillIndex);
}

// 显示主角战斗属性面板
function showPlayerBattlePanel() {
    const realmName = realmNames[player.realmIndex] || '练气';
    const innerLevel = player.innerLevel || 1;

    let stats = `【 ${player.name} 属性 】
境界: ${realmName} ${innerLevel}重
生命: ${formatNumber(player.hp)}/${formatNumber(player.maxHp)}
攻击: ${formatNumber(player.attack)}
防御: ${formatNumber(player.defense)}
暴击率: ${(parseFloat(player.criticalRate) || 0).toFixed(1)}%
暴击伤害: ${(parseFloat(player.criticalDamage) || 0).toFixed(0)}%
攻击速度: ${Number(player.speed).toFixed(1)}
位格: ${(player.power || 0).toFixed(2)}`;

    const divineAbilities = player.divineAbilities || {};
    const divineKeys = ['qingmuRoumai', 'cuiyeYuqi', 'qingmuZhenshen', 'hunyuanGuiyi', 'zhutianWeiyi'];
    const divineNames = {
        qingmuRoumai: '青霖愈体',
        cuiyeYuqi: '翠叶御气',
        qingmuZhenshen: '青木真身',
        hunyuanGuiyi: '混元归一',
        zhutianWeiyi: '长生久视'
    };

    let hasDivineAbility = false;
    let divineHtml = '';
    divineKeys.forEach(key => {
        const ability = divineAbilities[key];
        const level = ability ? Number(ability.level) || 0 : 0;
        if (level > 0) {
            if (!hasDivineAbility) {
                divineHtml += '\n\n【 神通 】';
                hasDivineAbility = true;
            }
            let currentEffect = '';
            switch(key) {
                case 'qingmuRoumai':
                    const healChance = (50 - 47.33 / (1 + Math.pow(level / 23.6, 0.57))).toFixed(2);
                    const baseHeal = $floor($evalBig(`${player.maxHp} * 0.5`));
                    const zhenshenLevel = divineAbilities.qingmuZhenshen?.level || 0;
                    let qinglinHealAmount = baseHeal;
                    if (zhenshenLevel > 1) {
                        const preBattleMaxHp = battleState.originalMaxHp || player.maxHp;
                        const lgHp = $log10(String(preBattleMaxHp));
                        const lgLgHp = $log10(String(lgHp));
                        const damageLimitRatio = $evalBig(`0.05 + 0.95 * (0.25 / (${lgLgHp} / 3))`);
                        const maxDamage = $floor($evalBig(`${player.maxHp} * ${damageLimitRatio}`));
                        qinglinHealAmount = $min(baseHeal, $floor($evalBig(`${maxDamage} * 0.25`)));
                    }
                    currentEffect = `恢复概率${healChance}%，恢复量${formatLawLevel(qinglinHealAmount)}`;
                    break;
                case 'cuiyeYuqi':
                    currentEffect = `附加${level * 10}%额外伤害`;
                    break;
                case 'qingmuZhenshen':
                    const preBattleMaxHp2 = battleState.originalMaxHp || player.maxHp;
                    const lgHp2 = $log10(String(preBattleMaxHp2));
                    const lgLgHp2 = $log10(String(lgHp2));
                    const zhenshenLimitRatio = level > 1 ? parseFloat($evalBig(`0.05 + 0.95 * (0.25 / (${lgLgHp2} / 3))`)).toFixed(4) : '0.25';
                    const zhenshenBonusHp = $evalBig(`${player.attack} * 10 * ${level}`);
                    currentEffect = `额外生命+${formatLawLevel(zhenshenBonusHp)}，受伤上限${(parseFloat(zhenshenLimitRatio) * 100).toFixed(2)}%最大生命`;
                    break;
                case 'hunyuanGuiyi':
                    const hunyuanDamage = $evalBig(`${player.hp} * 0.1 * ${level}`);
                    currentEffect = `附加${formatLawLevel(hunyuanDamage)}伤害`;
                    break;
                case 'zhutianWeiyi':
                    const zhutianSimCount = Math.ceil(Math.log(level) / Math.log(1.5)) || 1;
                    const lgDefense = $log10(String(player.defense));
                    const denominator = Math.log10(10 + parseFloat(lgDefense) / 20);
                    const dodgeChance = level > 1 ? Math.max(0, 0.5 - 0.45 / denominator) : 0;
                    currentEffect = `模拟${zhutianSimCount}次战斗，${(dodgeChance * 100).toFixed(1)}%概率无视伤害`;
                    break;
            }
            divineHtml += `\n• ${divineNames[key]} Lv.${level} ${currentEffect}`;
        }
    });
    if (!hasDivineAbility) {
        divineHtml += '\n\n【 神通 】\n未领悟神通';
    }

    const weapon = player.weapon || {};
    let weaponHtml = '\n\n【 法宝神通 】';
    if (weapon.daozhiLevel && weapon.daozhiLevel > 0) {
        const daozhiLevelNum = weapon.daozhiLevel || 0;
        const daozhiLogLevel = $log10(String(daozhiLevelNum + 1));
        const daozhiLogBase = $log10('1.5');
        const daozhiReduction = Math.min(parseFloat($evalBig(`${daozhiLogLevel} / ${daozhiLogBase}`)), 60);
        weaponHtml += `\n• 道滞领域 Lv.${weapon.daozhiLevel} 降低目标攻速${daozhiReduction.toFixed(1)}`;
    }
    if (weapon.jianzhenLevel && weapon.jianzhenLevel > 0) {
        const jianzhenLevelNum = weapon.jianzhenLevel || 0;
        const jianzhenLogLevel = $log10(String(jianzhenLevelNum + 1));
        const jianzhenLogBase = $log10('1.5');
        const jianzhenCoef = parseFloat($evalBig(`${jianzhenLogLevel} / ${jianzhenLogBase} / 10`)).toFixed(3);
        weaponHtml += `\n• 飞剑随行 Lv.${weapon.jianzhenLevel} 系数${jianzhenCoef}(线性递增)`;
    }
    if (weapon.daozhiLevel <= 0 && weapon.jianzhenLevel <= 0) {
        weaponHtml += '\n无';
    }

    closeModal();
    showModal(stats + divineHtml + weaponHtml);
}

