// 更新法则界面显示，包括各法则领悟等级和属性加成
function updateLawUI() {
    const skillContent = document.querySelector('#skill-content');
    if (!skillContent) return;

    const autoMaxBtnText = player.lawAutoMax === 'instant' ? '一键最高级: 直接' : 
                           player.lawAutoMax === 'gradual' ? '一键最高级: 逐渐' : '一键最高级: 关';
    const autoMaxBtnBg = player.lawAutoMax === 'off' ? 'rgba(51,51,51,var(--terminal-opacity))' : 'rgba(0,100,0,var(--terminal-opacity))';
    
    let html = `
    <div class="law-box" style="display:flex;justify-content:space-between;align-items:center;"><span>❖法则碎片❖  ${formatNumber(player.lawFragments)}</span> <button onclick="toggleLawAutoMax()" style="background:${autoMaxBtnBg};color:var(--text-color,#fff);border:1px solid #666;padding:1px 4px;cursor:pointer;">${autoMaxBtnText}</button></div>
    `;

    for (let key in laws) {
        const law = laws[key];
        const awareness = String(player.laws[key] || 0);
        const level = awareness;
        const nextCost = getLawFragmentCost(level);

        const awarenessNum = Number(awareness);
        const filledBlocks = awarenessNum < 1e15 ? $max(0, $min(10, $floor(awarenessNum / 10))) : 10;
        const progressBar = '█'.repeat(filledBlocks) + '░'.repeat(10 - filledBlocks);

        html += `
        <div class="law-box" style="display:flex;justify-content:space-between;align-items:center;"><span>${law.name}(${law.desc}): ${formatLawLevel(awareness)}%</span> <button onclick="upgradeLaw('${key}')" class="sbtn-xxs">领悟(消耗${formatLawLevel(nextCost)})</button></div>
        `;
    }

    skillContent.innerHTML = html;
}

