let tutorialOverlay = null;
let tutorialHighlight = null;
let tutorialCheckInterval = null;

function startTutorialAutoCheck() {
    Scheduler.remove('tutorialCheck');
    Scheduler.add('tutorialCheck', () => {
        if (player.tutorialStep > 0 && player.tutorialStep <= tutorialSteps.length) {
            const step = tutorialSteps[player.tutorialStep - 1];
            if (step && step.checkComplete && step.checkComplete()) {
                autoAdvanceTutorial();
            }
        }
    }, 500);
}

function stopTutorialAutoCheck() {
    Scheduler.remove('tutorialCheck');
}

function autoAdvanceTutorial() {
    if (player.tutorialStep < 0 || player.tutorialStep > tutorialSteps.length) {
        return;
    }
    
    player.tutorialStep++;
    saveGameData();
    
    if (player.tutorialStep > tutorialSteps.length) {
        player.tutorialStep = -1;
        saveGameData();
        stopTutorialAutoCheck();
        hideTutorialUI();
        showModal(`<span style="color:#0f0;">🎉 新手引导完成！</span><br><br>你已完成所有新手引导，祝你在修仙之路上越走越远！`);
    } else {
        showTutorialUI();
    }
}

function showTutorialUI() {
    if (player.tutorialStep < 1 || player.tutorialStep > tutorialSteps.length) {
        return;
    }

    const step = tutorialSteps[player.tutorialStep - 1];
    const position = step.position || 'bottom';

    if (!tutorialOverlay) {
        tutorialOverlay = document.createElement('div');
        tutorialOverlay.id = 'tutorial-overlay';
        tutorialOverlay.style.cssText = `
            position: fixed;
            z-index: 9998;
        `;
        document.body.appendChild(tutorialOverlay);
    }

    let positionStyle = '';
    switch(position) {
        case 'top':
            positionStyle = 'top: 10px; left: 10px; right: 10px;';
            break;
        case 'bottom':
            positionStyle = 'bottom: 70px; left: 10px; right: 10px;';
            break;
        case 'higher':
            positionStyle = 'bottom: 200px; left: 10px; right: 10px;';
            break;
        case 'center':
            positionStyle = 'top: 50%; left: 50%; transform: translate(-50%, -50%);';
            break;
    }

    tutorialOverlay.style.cssText = `
        position: fixed;
        z-index: 9998;
        ${positionStyle}
    `;

    tutorialOverlay.innerHTML = `
        <div style="
            background: rgba(30, 30, 30, 0.95);
            border: 2px solid #ff0;
            border-radius: 10px;
            padding: 15px;
            text-align: center;
            color: #fff;
            box-shadow: 0 0 20px rgba(255, 255, 0, 0.3);
        ">
            <div style="color: #ff0; font-size: 14px; margin-bottom: 8px;">
                【 新手引导 ${player.tutorialStep}/${tutorialSteps.length} 】${step.title}
            </div>
            <div style="color: #ccc; font-size: 12px; line-height: 1.5; margin-bottom: 12px;">
                ${step.description}
            </div>
            <div style="display: flex; gap: 10px; justify-content: center;">
                ${player.tutorialStep === tutorialSteps.length ? `
                    <button onclick="finishTutorial()" style="
                        background: rgba(0, 150, 0, 0.8);
                        color: #fff;
                        border: 1px solid #0a0;
                        padding: 6px 16px;
                        border-radius: 5px;
                        cursor: pointer;
                        font-size: 12px;
                    ">知道了</button>
                ` : `
                    <button onclick="skipTutorial()" style="
                        background: rgba(100, 100, 100, 0.8);
                        color: #fff;
                        border: 1px solid #666;
                        padding: 6px 16px;
                        border-radius: 5px;
                        cursor: pointer;
                        font-size: 12px;
                    ">跳过引导</button>
                `}
            </div>
        </div>
    `;
    tutorialOverlay.style.display = 'block';
    if (player.tutorialStep !== tutorialSteps.length) {
        startTutorialAutoCheck();
    }
}

function hideTutorialUI() {
    stopTutorialAutoCheck();
    if (tutorialOverlay) {
        tutorialOverlay.style.display = 'none';
    }
}

function finishTutorial() {
    player.tutorialStep = -1;
    saveGameData();
    stopTutorialAutoCheck();
    hideTutorialUI();
}

function skipTutorial() {
    player.tutorialStep = -3;
    saveGameData();
    closeAllModals();
    showModal(`<span style="color:#ff0;">【 跳过引导 】</span><br><br>确定要跳过新手引导吗？跳过后将不再显示。<br><br><button onclick="confirmSkipTutorial()" class="sbtn-gr">确定</button> <button onclick="cancelSkipTutorial()" class="sbtn">取消</button>`, true);
}

function confirmSkipTutorial() {
    player.tutorialStep = -1;
    player.tutorialSkipped = true;
    saveGameData();
    closeAllModals();
    hideTutorialUI();
}

function cancelSkipTutorial() {
    player.tutorialStep = -2;
    saveGameData();
    closeAllModals();
    showModal(`<span style="color:#ff0;">【 新手引导 】</span><br><br>是否开始新手引导？可以帮助你快速了解游戏基础操作。<br><br><button onclick="startTutorial()" class="sbtn-gr">确定</button> <button onclick="skipTutorial()" class="sbtn">取消</button>`, true);
}

function startTutorial() {
    closeAllModals();
    player.tutorialStep = 1;
    player.tutorialSkipped = false;
    saveGameData();
    showTutorialUI();
}

