    function generateName() {
        const surname = rng.pick(surnames);
        const c1 = rng.pick(charPool);
        let c2 = rng.pick(charPool);
        while (c2 === c1) c2 = rng.pick(charPool);
        return surname + c1 + c2;
    }
    
