    const realmNames = ['凡人', '练气', '筑基', '金丹', '元婴'];
    const realmLevels = ['练气', '筑基', '金丹', '元婴'];
    const maxRealmLevelIdx = Math.min(3, Math.max(0, Math.floor((topLevel - 1) / 9)));
    
    const realmPercents = [90, 8, 1.5, 0.4, 0.1];
    let actualPercents = realmPercents.slice(0, maxRealmLevelIdx + 2);
    const totalPercent = actualPercents.reduce((a, b) => a + b, 0);
    actualPercents = actualPercents.map(p => p / totalPercent * 100);
    
    for (let i = 0; i <= maxRealmLevelIdx + 1 && i < realmNames.length; i++) {
        const count = Math.floor(totalPopulation * actualPercents[i] / 100);
        realmDistribution.push({ name: realmNames[i], count });
    }
    
    const famousCount = rng.nextInt(8, 9);
    const topCount = rng.nextInt(3, 5);
    const allCandidates = [];
    
    const allSects = generateSectNamesForMap(mapNumber);
    const selectRng2 = createDateRandomGenerator('sect_select', mapNumber);
