    let html = `<div style="max-height:70vh;overflow-y:auto;padding:10px;">`;
    html += `<div style="color:#ff0;font-size:16px;text-align:center;margin-bottom:10px;">【 ${mapNumber.toString().padStart(3, '0')} ${mapName} - 世界概览 】</div>`;
    
    html += `<div class="mod-box-2" style="margin-bottom:10px;padding:10px;border-color:transparent;">`;
    html += `<div style="color:#e9d898;margin-bottom:5px;">【 生灵总数 】</div>`;
    html += `<div style="font-size:14px;">${totalPopulation}</div>`;
