function showSectList(mapNumber) {
    const mapIndex = mapNumber - 1;
    const mapName = mapNames[mapIndex] || '未知';
    const allSects = generateSectNamesForMap(mapNumber);
    
    const selectRng = createDateRandomGenerator('sect_select', mapNumber);
    const displayCount = selectRng.nextInt(3, 5);
    const displaySects = [];
    const usedIndices = new Set();
    while (displaySects.length < displayCount && displaySects.length < allSects.length) {
        const idx = selectRng.nextInt(0, allSects.length - 1);
        if (!usedIndices.has(idx)) {
            usedIndices.add(idx);
            displaySects.push(allSects[idx]);
        }
    }
    
    let html = `<div style="max-height:70vh;overflow-y:auto;padding:10px;">`;
    html += `<div style="color:#ff0;font-size:16px;text-align:center;margin-bottom:10px;">【 ${mapNumber.toString().padStart(3, '0')} ${mapName} - 宗门列表 】</div>`;
    html += `<div style="color:var(--text-color-dim,#888);font-size:12px;text-align:center;margin-bottom:15px;">共${displaySects.length}个宗门</div>`;
    
    displaySects.forEach((sect) => {
        html += `<div onclick="showSectDetail(${mapNumber},'${sect}')" class="mod-box-2" style="margin-bottom:8px;padding:10px;cursor:pointer;text-align:center;">
            <div style="color:var(--text-color,#fff);font-size:14px;">${sect}</div>
        </div>`;
    });
    
    html += `</div>`;
    
    showModal(html, true);
}

function showFengMoZhiDi(mapNumber) {
    const mapIndex = mapNumber - 1;
    const mapMonsters = monsterData[mapIndex] || [];
    const mapName = mapNames[mapIndex] || '未知';
    
    let stats = `【 ${mapNumber.toString().padStart(3, '0')} ${mapName} - 封魔之地 】\n封印着道尊曾经消灭的魔物。也是修仙者的历练圣地\n`;
    
    mapMonsters.forEach((monsterName, idx) => {
        const monsterLevel = (mapNumber - 1) * 5 + idx + 1;
        const levelMinus1 = String(monsterLevel - 1);
        const lgResult = $log10(levelMinus1);
        const lg49Result = $log10(String(monsterLevel + 90));
        const baseHpExpr = `((1.147 + ${lgResult} / 375) ^ ${levelMinus1}) * (49 ^ ${lg49Result}) / 20`;
        const baseAtkExpr = `6 * (1.147 + ${lgResult} / 375) ^ ${levelMinus1}`;
        const baseDefExpr = `3 * (1.147 + ${lgResult} / 375) ^ ${levelMinus1}`;
        const baseHp = $floor($evalBig(baseHpExpr));
        const baseAtk = $floor($evalBig(baseAtkExpr));
        const baseDef = $floor($evalBig(baseDefExpr));
        
        stats += `\n【 ${monsterName} 属性 】`;
        stats += `\nLv.${monsterLevel}`;
        stats += `\n生命: ${formatPrecision(String(baseHp))}`;
        stats += `\n攻击: ${formatPrecision(String(baseAtk))}`;
        stats += `\n防御: ${formatPrecision(String(baseDef))}`;
    });
    
    showModal(stats);
}

function simpleHash(str) {
    let hash = 0;
    for (let i = 0; i < str.length; i++) {
        const char = str.charCodeAt(i);
        hash = ((hash << 5) - hash) + char;
        hash = hash & hash;
    }
    return Math.abs(hash);
}

function seededRandom(seed) {
    const x = Math.sin(seed) * 10000;
    return x - Math.floor(x);
}

// 获取标准日期字符串格式
function getStandardDateString(date) {
    const d = date || new Date();
    return `${d.getFullYear()}-${d.getMonth() + 1}-${d.getDate()}`;
}

// 统一的固定随机数生成器
// 基于当前日期、救世日期和种子，循环迭代生成无限固定随机数
function createDateRandomGenerator(...seeds) {
    const currentDate = getStandardDateString();
    return createFixedDateRandomGenerator(currentDate, ...seeds);
}

// 指定日期的固定随机数生成器
function createFixedDateRandomGenerator(fixedDate, ...seeds) {
    let realDianHuaTime = player.realDianHuaTime || player.dianHuaTime || fixedDate;
    
    // 规范化格式：确保"日"和时分之间有空格，格式如 "2026年05月05日 21:47"
    realDianHuaTime = realDianHuaTime.replace(/日(\d)/, '日 $1');
    
    // 组合指定日期、救世日期和种子
    const combinedSeed = fixedDate + '_' + realDianHuaTime + '_' + seeds.join('_');
    
    // 迭代哈希确保足够长度
    let hash1 = simpleHash(combinedSeed);
    let hash2 = simpleHash(String(hash1) + combinedSeed);
    let hash3 = simpleHash(String(hash1) + String(hash2) + combinedSeed);
    let baseSeed = simpleHash(String(hash1) + String(hash2) + String(hash3));
    
    let currentHash = baseSeed;
    let callCount = 0;
    
    return {
        next: function() {
            currentHash = simpleHash(String(currentHash) + String(hash1) + String(hash2) + callCount);
            callCount++;
            return seededRandom(currentHash);
        },
        nextInt: function(min, max) {
            return Math.floor(this.next() * (max - min + 1)) + min;
        },
        pick: function(array) {
            return array[Math.floor(this.next() * array.length)];
        },
        getDateStr: function() {
            return currentDate;
        },
        getDianHuaTime: function() {
            return dianHuaTime;
        }
    };
}

