function getRealmNameByLevel(level) {
    const realmLevels = ['练气', '筑基', '金丹', '元婴', '化神'];
    const levelNum = Math.floor(level);
    const realmIndex = Math.floor((levelNum - 1) / 9);
    if (realmIndex < 0) return '练气';
    if (realmIndex < 4) {
        return realmLevels[realmIndex];
    }
    return '化神';
}

function getRealmFullName(level) {
    const realmLevels = ['练气', '筑基', '金丹', '元婴', '化神'];
    const levelNum = Math.floor(level);
    const realmIndex = Math.floor((levelNum - 1) / 9);
    const subLevel = ((levelNum - 1) % 9) + 1;
    if (realmIndex < 0) return '练气1';
    if (realmIndex < 4) {
        return realmLevels[realmIndex] + subLevel;
    }
    return '化神' + (levelNum - 36);
}

