function showSectDetail(mapNumber, sectName) {
    const mapIndex = mapNumber - 1;
    const mapName = mapNames[mapIndex] || '未知';
    
    const candidates = window.worldCandidatesData && window.worldCandidatesData[mapNumber];
    const sectMembers = candidates ? candidates.filter(c => c.sectName === sectName) : [];
    
    const zhangMen = sectMembers.find(m => m.position === '掌门');
    const elders = sectMembers.filter(m => m.position === '长老');
    const coreDisciples = sectMembers.filter(m => m.position === '核心弟子');
    
    window.currentSectMembersData = {};
    sectMembers.forEach(m => {
        window.currentSectMembersData[m.name] = m;
    });
    
    const eliteCount = 100 + Math.floor(Math.randomNeutral() * 100);
    const normalCount = 5000 + Math.floor(Math.randomNeutral() * 5000);
    
    function makeClickable(name, position) {
        return `<span style="color:var(--text-color,#fff);cursor:pointer;" onclick="showSectMemberInfo('${name}','${position}',${mapNumber},'${sectName}')">${name}</span>`;
    }
    
    let html = `<div style="max-height:70vh;overflow-y:auto;padding:10px;">`;
    html += `<div style="color:#ff0;font-size:16px;text-align:center;margin-bottom:10px;">【 ${sectName} 】</div>`;
    html += `<div style="color:var(--text-color-dim,#888);font-size:12px;text-align:center;margin-bottom:15px;">所在地: ${mapNumber.toString().padStart(3, '0')} ${mapName}</div>`;
    
    if (zhangMen) {
        html += `<div class="mod-box-2" style="margin-bottom:10px;padding:10px;border-color:transparent;"><div style="color:#e9d898;margin-bottom:5px;">【 掌门 】</div>${makeClickable(zhangMen.name, '掌门')}</div>`;
    }
    
    html += `<div class="mod-box-2" style="margin-bottom:10px;padding:10px;border-color:transparent;"><div style="color:#e9d898;margin-bottom:5px;">【 长老 】(${elders.length}人)</div>`;
    html += elders.map(e => makeClickable(e.name, '长老')).join('、');
    html += `</div>`;
    
    html += `<div class="mod-box-2" style="margin-bottom:10px;padding:10px;border-color:transparent;"><div style="color:#e9d898;margin-bottom:5px;">【 核心弟子 】(${coreDisciples.length}人)</div>`;
    const corePerLine = 5;
    for (let j = 0; j < coreDisciples.length; j += corePerLine) {
        html += coreDisciples.slice(j, j + corePerLine).map(c => makeClickable(c.name, '核心弟子')).join('、') + '<br>';
    }
    html += `</div>`;
    
    html += `<div class="mod-box-2" style="margin-bottom:10px;padding:10px;border-color:transparent;"><span style="color:#e9d898;">【 精英弟子 】</span>${eliteCount}人`;
    html += ` <span style="color:var(--text-color-dim,#888);font-size:11px;cursor:pointer;" onclick="showEliteDisciples(${mapNumber},${eliteCount},'${sectName}')">(点击查看)</span></div>`;
    
    html += `<div class="mod-box-2" style="padding:10px;border-color:transparent;"><span style="color:#e9d898;">【 普通弟子 】</span>${normalCount}人</div>`;
    
    html += `</div>`;
    
    showModal(html, true);
}

