function collecttongjiehoubei() {
    const pendingCount = getPendingtongjiehoubeiCount();
    if (pendingCount <= 0) {
        showModal('<span style="color:#f66;">暂无留讯</span><br><br><button onclick="closeModal()" class="sbtn">确定</button>', true);
        return;
    }
    
    const remainingCount = pendingCount - 1;
    const today = new Date();
    const newLastDate = new Date(today);
    newLastDate.setDate(newLastDate.getDate() - remainingCount);
    player.lasttongjiehoubeiDate = newLastDate.toDateString();
    
    const seedDate = new Date(today);
    seedDate.setDate(seedDate.getDate() - remainingCount);
    const seed = generateHuaShenSeedForDate(seedDate);
    const template = tongjiehoubeiTemplates[seed.templateIndex];
    
    addItemToBag(player.bag, '时间结晶', 1, 20);
    addItemToBag(player.bag, '寰纪凝光', 1, 1);
    
    saveGameData();
    
    const html = `<div style="text-align:center;max-height:60vh;overflow-y:auto;padding:15px;">
        <div style="color:#0ff;font-size:14px;line-height:2;">${template.caller}<span style="color:#ff0;">${seed.name}</span>${template.content}</div>
        ${remainingCount > 0 ? `<div style="color:#e9d898;font-size:12px;margin-top:10px;">尚有 ${remainingCount} 条留讯待查看</div>` : ''}
        <div style="margin-top:20px;">
            <button onclick="closeModal();showDianHuaMapUI(100);" class="sbtn">确定</button>
            ${remainingCount > 0 ? `<button onclick="collectAlltongjiehoubei(${remainingCount})" class="sbtn-gr">一键查看</button>` : ''}
        </div>
    </div>`;
    
    const modal = document.createElement('div');
    modal.className = 'customModal';
    modalZIndexCounter += 2;
    modal.style.cssText = `position:fixed;top:0;left:0;width:100%;height:100%;background:rgba(0,0,0,${getModalOpacity()});display:flex;justify-content:center;align-items:center;z-index:${modalZIndexCounter};backdrop-filter:blur(4px);-webkit-backdrop-filter:blur(4px);`;
    modal.onclick = (e) => {
        if (e.target === modal) {
            modal.remove();
            showDianHuaMapUI(100);
        }
    };
    modal.innerHTML = `
        <div style="background:rgba(0,0,0,${getModalOpacity()});border:1px solid #aaa;border-radius:15px;padding:20px;color:var(--text-color,#fff);font-family:monospace;max-width:900px;max-height:90vh;overflow-y:auto;text-align:center;box-shadow:0 0 10px rgba(255,255,255,0.2),inset 0 0 10px rgba(255,255,255,0.05);">
            ${html}
        </div>
    `;
    document.body.appendChild(modal);
}

function collectAlltongjiehoubei(remainingCount) {
    if (remainingCount <= 0) return;
    
    const today = new Date();
    let html = `<div style="text-align:center;padding:15px;">`;
    html += `<div style="color:#ff0;font-size:16px;margin-bottom:15px;">【 留讯汇总 】</div>`;
    
    let messages = [];
    for (let i = 0; i < remainingCount; i++) {
        const seedDate = new Date(today);
        seedDate.setDate(seedDate.getDate() - remainingCount + i);
        const seed = generateHuaShenSeedForDate(seedDate);
        const template = tongjiehoubeiTemplates[seed.templateIndex];
        messages.push({name: seed.name, caller: template.caller, content: template.content});
    }
    
    html += `<div style="color:var(--text-color,#fff);font-size:12px;line-height:1.8;text-align:left;max-height:60vh;overflow-y:auto;padding-right:10px;">`;
    messages.forEach((msg, idx) => {
        html += `<div>${idx + 1}. ${msg.caller}<span style="color:#ff0;">${msg.name}</span>${msg.content}</div>`;
    });
    html += `</div>`;
    
    html += `<div style="color:#0ff;font-size:13px;margin-top:15px;">共收到 ${remainingCount} 条留讯</div>`;
    html += `<div style="color:var(--text-color,#fff);font-size:13px;margin-top:5px;">获得<span style="color:#ff0;">时间结晶×${20 * remainingCount}</span>、<span style="color:#ff0;">寰纪凝光×${remainingCount}</span></div>`;
    
    addItemToBag(player.bag, '时间结晶', 1, 20 * remainingCount);
    addItemToBag(player.bag, '寰纪凝光', 1, remainingCount);
    
    // 使用 toDateString 格式保存日期，设为今天
    player.lasttongjiehoubeiDate = today.toDateString();
    saveGameData();
    
    html += `</div>`;
    html += `<div style="margin-top:20px;text-align:center;">
        <button onclick="closeAllModals();showDianHuaMapUI(100);" class="sbtn">确定</button>
    </div>`;
    showModal(html, true);
}

function generateHuaShenSeedForDate(targetDate) {
    const dateStr = targetDate.toDateString();
    const realDianHuaTime = player.realDianHuaTime || player.dianHuaTime || dateStr;
    const combinedSeed = dateStr + '_' + realDianHuaTime + '_huashen_seed';
    
    let hash1 = simpleHash(combinedSeed);
    let hash2 = simpleHash(String(hash1) + combinedSeed);
    let hash3 = simpleHash(String(hash1) + String(hash2) + combinedSeed);
    let baseSeed = simpleHash(String(hash1) + String(hash2) + String(hash3));
    
    let currentHash = baseSeed;
    let callCount = 0;
    
    function next() {
        currentHash = simpleHash(String(currentHash) + '_' + callCount);
        callCount++;
        return (currentHash % 10000) / 10000;
    }
    
    function nextInt(min, max) {
        return Math.floor(next() * (max - min + 1)) + min;
    }
    
    function pick(array) {
        return array[Math.floor(next() * array.length)];
    }
    
    const surnames = ['凌', '沐', '苏', '云', '洛', '楚', '晏', '砚', '辞', '白', '风', '月', '霜', '雪', '寒', '清', '玄', '灵', '烟', '卿', '安', '君', '屿', '舟', '知', '时', '南', '西', '泠', '姬', '姜', '姒', '嬴', '上官', '慕容', '令狐', '钟离', '南宫', '北冥', '司空', '司徒', '独孤', '百里', '长孙', '宗政', '濮阳', '淳于', '太叔', '申屠', '温', '顾', '谢', '宋', '阮', '裴', '季', '沈', '陆', '许', '秦', '江', '程', '贺', '唐', '祁', '竺', '疏', '遥', '幻', '幽', '冥', '芜', '痕', '烬', '席', '卫', '傅', '孟', '姚', '尤', '施', '孔', '曹', '华', '陶', '戚', '喻', '柏', '章', '奚', '郎', '韦', '苗', '方', '俞', '袁', '柳', '史'];
    const charPool = ['川', '峦', '汀', '浔', '岑', '沂', '岚', '嵩', '沄', '洲', '屿', '涧', '峯', '浦', '潇', '澈', '澄', '澜', '峤', '溪', '宸', '曜', '珩', '璟', '琛', '璨', '曦', '暝', '霄', '穹', '星', '辰', '玄', '朔', '昭', '晞', '朗', '烨', '昀', '灵', '瑶', '琼', '瑛', '瑜', '瑾', '笙', '箫', '弦', '珵', '玥', '璃', '珞', '玑', '祯', '瑞', '祺', '麟', '凤', '清', '疏', '寂', '闲', '悠', '逸', '尘', '空', '宁', '安', '静', '舒', '然', '沐', '栖', '梧', '棠', '杉', '云', '烟', '雾', '霭', '风', '絮', '霜', '雪', '露', '霖', '霏', '濛', '霞', '霓', '虹', '砚', '书', '辞', '墨', '锋', '剑', '道', '真', '悟', '修', '行', '远', '寻', '访', '游', '隐'];
    
    const surname = pick(surnames);
    const c1 = pick(charPool);
    let c2 = pick(charPool);
    while (c2 === c1) c2 = pick(charPool);
    const name = surname + c1 + c2;
    
    const templateIndex = nextInt(0, 8);
    
    return { name, templateIndex };
}

