// 宗门后缀
const sectSuffixes = ['宗', '门', '阁', '宫', '轩', '派', '楼', '观', '苑', '堂', '府', '殿', '院', '墟', '境', '天', '界', '域'];

// 为每个地图生成10个宗门名称
function generateSectNamesForMap(mapNumber) {
    if (mapNumber === 100 || mapNumber === 101) {
        return mapNumber === 100 ? ['无上大罗天'] : ['无尽虚空'];
    }
    
    const mapName = mapNames[mapNumber - 1] || '未知';
    const rng = createDateRandomGenerator('sect_names', mapNumber);
    
    const sects = [];
    const usedNames = new Set();
    
    // 从地图名称提取关键字作为宗门名称基础
    const mapChars = mapName.split('');
    
    for (let i = 0; i < 10; i++) {
        let name;
        let attempts = 0;
        
        do {
            const baseChar = mapChars[rng.nextInt(0, mapChars.length - 1)];
            const suffix = sectSuffixes[rng.nextInt(0, sectSuffixes.length - 1)];
            
            const extraChars = ['玄', '灵', '天', '地', '云', '风', '月', '星', '玉', '紫', '青', '碧', '金', '银', '苍', '寒', '幽', '幻', '仙', '神'];
            const extraChar1 = extraChars[rng.nextInt(0, extraChars.length - 1)];
            const extraChar2 = extraChars[rng.nextInt(0, extraChars.length - 1)];
            
            const patterns = [
                extraChar1 + baseChar + suffix,
                baseChar + extraChar1 + suffix,
                extraChar1 + extraChar2 + suffix,
                extraChar1 + suffix + '门',
            ];
            
            name = patterns[rng.nextInt(0, patterns.length - 1)];
            attempts++;
        } while ((name.length < 3 || usedNames.has(name)) && attempts < 100);
        
        usedNames.add(name);
        sects.push(name);
    }
    
    return sects;
}

// 获取地图的主宗门名称（第一个）
function getMainSectName(mapNumber) {
    const sects = generateSectNamesForMap(mapNumber);
    return sects[0] || '未知宗门';
}

