// 隐藏自动世界攻略覆盖层
function hideAutoWorldExpOverlay() {
    const overlay = document.getElementById('autoWorldExpOverlay');
    if (overlay) overlay.remove();
}

// 开始自动世界攻略
function startAutoWorldExp() {
    checkAndResetWorldExploreCount();
    
    if (player.worldExploreCount <= 0) {
        closeModal();
        showModal(`<div style="text-align:center;padding:20px;">
            <span style="color:#f66;font-size:16px;">世界攻略次数不足</span><br><br>
            <span style="color:var(--text-color-dim,#888);">今日世界攻略次数已用尽，请明日再来</span><br><br>
            <button onclick="closeModal()" class="sbtn-lg">确定</button>
        </div>`, true);
        return;
    }
    
    const backDepthInput = document.getElementById('autoWorldExpBackDepth');
    const backDepth = parseInt(backDepthInput.value) || 0;
    
    player.autoWorldExpBackDepth = Math.max(0, backDepth);
    player.autoWorldExp = true;
    player.autoWorldExpPhase = 'deepening';
    
    closeModal();
    showAutoWorldExpOverlay();
    updateStatusUI();
    saveGameData();
    
    // 模拟点击自动深入按钮，循环点击直到开启自动深入
    const voidAutoBtn = document.getElementById('voidAutoBtn');
    if (voidAutoBtn) {
        let clickCount = 0;
        const maxClicks = 3;
        
        function clickUntilDeepen() {
            if (player.voidAutoBattle === 'deepen') {
                return;
            }
            if (clickCount >= maxClicks) {
                return;
            }
            clickCount++;
            voidAutoBtn.click();
            setTimeout(() => {
                clickUntilDeepen();
            }, 50);
        }
        
        clickUntilDeepen();
    }
}

// 执行自动世界攻略逻辑（定时器调用）
function executeAutoWorldExp() {
    if (!player.autoWorldExp) return;
    if (battleState.currentMap !== 101) return;
    
    if (window.worldExpState && !window.worldExpState.battleEnded) {
        return;
    }
    
    switch (player.autoWorldExpPhase) {
        case 'deepening':
            if (player.voidAutoBattle === 'off' || player.voidAutoPhase === 'iterate') {
                player.autoWorldExpPhase = 'retreating';
                executeAutoWorldExpRetreat();
            }
            break;
            
        case 'retreating':
            break;
            
        case 'waiting':
            player.autoWorldExpPhase = 'battling';
            // 模拟点击世界攻略按钮
            showWorldExploration();
            // 延迟模拟点击max按钮
            setTimeout(() => {
                const maxBtn = document.getElementById('worldExpMaxBtn');
                if (maxBtn && !window.worldExpBattleMax) {
                    maxBtn.click();
                }
            }, 500);
            break;
            
        case 'battling':
            break;
    }
}

// 执行自动回退或深入
function executeAutoWorldExpRetreat() {
    const maxSuccessDepth = player.voidAutoMaxSuccessDepth || 0;
    const backDepth = player.autoWorldExpBackDepth || 0;
    
    // backDepth > 0: 回退层数
    // backDepth < 0: 向前深入层数
    // backDepth = 0: 保持当前深度
    let targetDepth;
    if (backDepth > 0) {
        // 回退：确保至少为1
        targetDepth = maxSuccessDepth > 0 ? Math.max(1, maxSuccessDepth - backDepth) : 0;
    } else if (backDepth < 0) {
        // 深入：向前深入
        targetDepth = maxSuccessDepth + Math.abs(backDepth);
    } else {
        // 保持当前深度
        targetDepth = maxSuccessDepth > 0 ? maxSuccessDepth : 0;
    }
    
    // 使用与 setVoidDepth 相同的完整逻辑设置深度
    player.voidDepth = targetDepth;
    player.voidAutoPhase = 'init';
    player.voidAutoInitDepth = 0;
    player.voidAutoInitLeft = 0;
    player.voidAutoInitRight = 0;
    player.voidAutoMaxSuccessDepth = 0;
    player.voidAutoInstakillAttackCount = 0;
    player.voidAutoBattle = 'off';
    
    player.autoWorldExpPhase = 'waiting';
    updateStatusUI();
    saveGameData();
    
    setTimeout(() => {
        executeAutoWorldExp();
    }, 500);
}

// 中断自动世界攻略
function interruptAutoWorldExp(reason) {
    if (!player.autoWorldExp) return false;
    
    player.autoWorldExp = false;
    player.autoWorldExpPhase = 'idle';
    hideAutoWorldExpOverlay();
    updateStatusUI();
    saveGameData();
    
    showModal(`<span style="color:#f66;">【 自动世界攻略已中断 】</span><br><br><span style="color:var(--text-color-dim,#888);">原因：${reason}</span><br><br><button onclick="closeModal()" class="sbtn">确定</button>`, true);
    return true;
}

// 处理世界攻略结束后的自动世界攻略逻辑
function handleAutoWorldExpEnd() {
    if (!player.autoWorldExp) return;
    
    // 检查次数是否耗尽，在最后一次世界攻略战斗结束后判断
    checkAndResetWorldExploreCount();
    if (player.worldExploreCount <= 0) {
        // 次数耗尽，返回无尽虚空并开启自动秒杀
        player.autoWorldExp = false;
        player.autoWorldExpPhase = 'idle';
        hideAutoWorldExpOverlay();
        
        // 返回虚空
        goVoidBack();
        
        // 开启自动秒杀
        player.voidAutoBattle = 'instakill';
        player.voidAutoPhase = 'init';
        player.voidAutoInitDepth = player.voidDepth;
        player.voidAutoInitLeft = 0;
        player.voidAutoInitRight = 0;
        player.voidAutoMaxSuccessDepth = 0;
        
        updateStatusUI();
        saveGameData();
        return;
    }
    
    // 重置自动深入状态，准备重新开始
    player.voidAutoPhase = 'init';
    player.voidAutoInitLeft = 0;
    player.voidAutoInitRight = 0;
    
    player.autoWorldExpPhase = 'deepening';
    updateStatusUI();
    saveGameData();
    
    // 模拟点击自动深入按钮，循环点击直到开启自动深入
    const voidAutoBtn = document.getElementById('voidAutoBtn');
    if (voidAutoBtn) {
        // 循环点击直到变成 deepen 模式
        let clickCount = 0;
        const maxClicks = 3; // 最多点击3次（off->deepen->instakill->off）
        
        function clickUntilDeepen() {
            if (player.voidAutoBattle === 'deepen') {
                // 已经是深入模式，完成
                return;
            }
            if (clickCount >= maxClicks) {
                // 超过最大点击次数，放弃
                return;
            }
            clickCount++;
            voidAutoBtn.click();
            // 延迟检查是否成功
            setTimeout(() => {
                clickUntilDeepen();
            }, 50);
        }
        
        clickUntilDeepen();
    }
}

// 显示世界探索界面，包含探索进度和奖励信息
function showWorldExploration() {
    if (window.worldExpState && !window.worldExpState.battleEnded) {
        window.worldExpInBackground = false;
        document.querySelectorAll('.tab').forEach(t => t.classList.remove('active'));
        document.querySelectorAll('.tab-content').forEach(t => t.classList.remove('active'));
        document.querySelector('[data-tab="battle"]').classList.add('active');
        document.getElementById('tab-battle').classList.add('active');
        renderWorldExpBattle();
        return;
    }
    
    if (player.worldExpState && player.worldExpState.killCount > 0) {
        window.pendingWorldExpState = player.worldExpState;
        const savedState = window.pendingWorldExpState;
        const killCount = savedState.killCount;
        const worldName = savedState.worldName || '未知世界';
        const enemyCount = savedState.enemyCount || 0;
        
        let content = `<span style="color:#ff0;">【 世界攻略中断 】</span><br><br>
            <span style="color:var(--text-color-dim,#888);">世界: ${worldName}</span><br>
            <span style="color:var(--text-color-dim,#888);">击杀数: ${killCount}</span><br>
            <span style="color:var(--text-color-dim,#888);">敌方剩余: ${enemyCount}</span><br><br>
            <button onclick="continueWorldExpBattle()" class="sbtn-lg" style="background:#11D65D;margin-right:10px">继续攻略</button>
            <button onclick="settleInterruptedBattle()" class="sbtn-820">结算退出</button>`;
        
        showModal(content, true);
        return;
    }
    
    checkAndResetWorldExploreCount();
    if (player.worldExploreCount <= 0) {
        const tomorrow = new Date();
        tomorrow.setDate(tomorrow.getDate() + 1);
        tomorrow.setHours(0, 0, 0, 0);
        const tomorrowStr = tomorrow.toLocaleDateString('zh-CN', { month: 'long', day: 'numeric' });
        showModal('<span style="color:#f66;">今日世界探索次数已用尽</span><br><br>' +
            `<span style="color:var(--text-color-dim,#888);">下次更新: ${tomorrowStr} 00:00</span><br><br>` +
            '<button onclick="closeModal()" class="sbtn">确定</button>', true);
        return;
    }
    showModal('<span style="color:#ff0;">探索到未知世界，是否出击？</span><br><br>' +
        '<button id="worldExpConfirmBtn" onclick="closeModal();executeWorldExploration();" class="sbtn-gr" style="margin-right:10px">是</button>' +
        '<button onclick="closeModal()" class="sbtn">否</button>', true);
    
    // 自动世界攻略模式下，自动点击"是"按钮
    if (player.autoWorldExp) {
        setTimeout(() => {
            const confirmBtn = document.getElementById('worldExpConfirmBtn');
            if (confirmBtn) {
                confirmBtn.click();
            }
        }, 100);
    }
}

// 判断技能是否应该记录到日志（避免重复刷屏）
function shouldLogSkill() {
    return (window.worldExpBattleSpeed || 1) < 8;
}

// 添加技能触发日志到战斗记录
function addSkillLog(state, message) {
    if (shouldLogSkill()) {
        state.battleLog.push(message);
    }
}

