const skillList = Object.values(worldExpSkills);

function copySkillsWithActions(skills) {
    if (!skills || !Array.isArray(skills)) return [];
    return skills.map(skill => {
        const skillKey = Object.keys(worldExpSkills).find(k => worldExpSkills[k].name === skill.name);
        const originalSkill = skillKey ? worldExpSkills[skillKey] : null;
        if (!originalSkill) return skill;
        return {
            name: originalSkill.name,
            desc: originalSkill.desc,
            effect: originalSkill.effect,
            type: originalSkill.type,
            trigger: originalSkill.trigger,
            noInherit: originalSkill.noInherit,
            fixedValues: skill.fixedValues || {},
            action: originalSkill.action
        };
    });
}

// 获取当前已学习的技能数量
function getSkillCount(isEnemy = false) {
    const rand = Math.random() * 100;
    if (isEnemy) {
        if (rand < 13) return 1;
        if (rand < 25) return 2;
        if (rand < 37) return 3;
        if (rand < 53) return 4;
        return 5;
    }
    if (rand < 13) return 5;
    if (rand < 25) return 4;
    if (rand < 37) return 3;
    if (rand < 53) return 2;
    return 1;
}

// 生成世界探索技能的固定数值配置
function generateWorldExpSkillFixedValues(skillName, isEnemy = false) {
    const values = {};
    const rand = Math.random();
    switch(skillName) {
        case '灵泉润枯法': values.healPercent = isEnemy ? Math.floor(50 + rand * 150) : randomStep(50, 200); break;
        case '碎虚绝魂击': values.thresholdPercent = isEnemy ? Math.floor(20 + rand * 40) : randomStep(20, 60); break;
        case '蚀血噬魂打': values.damagePercent = isEnemy ? Math.floor(20 + rand * 40) : randomStep(20, 60); break;
        case '千影连星刺': values.hitCount = isEnemy ? Math.floor(2 + rand * 4) : randomStep(2, 6); break;
        case '戮绝残血式': values.damagePercent = isEnemy ? Math.floor(200 + rand * 400) : randomStep(200, 600); break;
        case '血元反哺术': values.healPercent = isEnemy ? Math.floor(50 + rand * 150) : randomStep(50, 200); break;
        case '万域镇魔波': values.reducePercent = isEnemy ? Math.floor(rand * 50) : randomStep(0, 50); break;
        case '寒骨封脉击': values.speedReduce = isEnemy ? Math.floor(5 + rand * 15) : randomStep(5, 20); break;
        case '御灵反滞诀': values.speedReduce = isEnemy ? Math.floor(5 + rand * 15) : randomStep(5, 20); break;
        case '幽墟幻折身': values.reflectPercent = isEnemy ? Math.floor(20 + rand * 60) : randomStep(20, 80); break;
        case '疾风御体诀': values.speedBoost = isEnemy ? Math.floor(20 + rand * 20) : randomStep(20, 40); break;
        case '焚魂同寂咒': values.selfDamagePercent = isEnemy ? [70, 60, 50, 40, 30][Math.floor(rand * 5)] : [30, 40, 50, 60, 70][Math.floor(rand * 5)]; break;
        case '骁勇锻体术': values.atkBoostPercent = isEnemy ? Math.floor(8 + rand * 22) : randomStep(8, 30); break;
        case '玄罡护生界': values.damageLimitPercent = isEnemy ? [30, 35, 40, 45, 50][Math.floor(rand * 5)] : [50, 45, 40, 35, 30][Math.floor(rand * 5)]; break;
    }
    return values;
}

function applyDamageToTarget(state, target, damage, sourceName = '未知') {
    if (!target || !target.alive) return 0;
    
    const targetAllies = state.playerUnits.includes(target) ? state.playerUnits : state.enemyUnits;
    const xuangangUnit = targetAllies.find(u => u.alive && u.skills && u.skills.some(s => s.name === '玄罡护生界'));
    
    let finalDamage = damage;
    
    if (xuangangUnit) {
        const mySkill = xuangangUnit.skills.find(s => s.name === '玄罡护生界');
        const fv = mySkill?.fixedValues || {damageLimitPercent: 40};
        const maxDamage = $floor($evalBig(`${target.maxHp} * ${fv.damageLimitPercent} / 100`));
        if ($gtBig(finalDamage, maxDamage)) {
            const reduced = $subBig(finalDamage, maxDamage);
            finalDamage = maxDamage;
            addSkillLog(state, `<span style="color:#0ff">【${xuangangUnit.name}】玄罡护生界生效，${target.name} 豁免 ${formatNumber(reduced)} 伤害（伤害上限${fv.damageLimitPercent}%最大生命）</span>`);
        }
    }
    
    target.hp = $subBig(target.hp, finalDamage);
    
    if ($lteBig(target.hp, 0)) {
        target.hp = 0;
        target.alive = false;
        handleUnitDeath(state, target);
    }
    
    return finalDamage;
}

// 处理单位死亡逻辑，触发掉落和经验结算
function handleUnitDeath(state, unit) {
    if (!unit || unit.alive || $gtBig(unit.hp, 0)) return;
    const isPlayerUnit = state.playerUnits.includes(unit);
    if (isPlayerUnit) {
        const newShengLing = $subBig(String(player.shengLing || '0'), '1');
        player.shengLing = $gteBig(newShengLing, '0') ? newShengLing : '0';
        state.playerDeathCount = (state.playerDeathCount || 0) + 1;
        addSkillLog(state, `<span style="color:#f66">【${unit.name}】牺牲</span>`);
        
        if (unit.skills && unit.skills.length > 0 && Math.random() < 0.2) {
            const aliveAllies = state.playerUnits.filter(u => u.alive && u !== unit);
            if (aliveAllies.length > 0) {
                const inheritableSkills = unit.skills.filter(s => !s.noInherit);
                if (inheritableSkills.length === 0) return;
                const skillToInherit = inheritableSkills[Math.floor(Math.random() * inheritableSkills.length)];
                const targetUnit = aliveAllies[Math.floor(Math.random() * aliveAllies.length)];
                
                const existingSkillNames = new Set(targetUnit.skills ? targetUnit.skills.map(s => s.name) : []);
                if (!existingSkillNames.has(skillToInherit.name)) {
                    const inheritedSkill = {
                        name: skillToInherit.name,
                        desc: skillToInherit.desc,
                        effect: skillToInherit.effect,
                        type: skillToInherit.type,
                        trigger: skillToInherit.trigger,
                        action: skillToInherit.action,
                        fixedValues: generateWorldExpSkillFixedValues(skillToInherit.name, false)
                    };
                    if (!targetUnit.skills) targetUnit.skills = [];
                    targetUnit.skills.push(inheritedSkill);
                    addSkillLog(state, `<span style="color:#ff0">【${unit.name}】将【${skillToInherit.name}】传承给【${targetUnit.name}】</span>`);
                }
            }
        }
    } else {
        state.enemyCount = Math.max(0, state.enemyCount - 1);
        processMonsterDrop(player.maxVoidVictoryLevel + 500);
        addSkillLog(state, `<span style="color:#ff0">斩杀【${unit.name}】</span>`);
    }
}

// 处理怪物掉落物品，计算资源收益
function processMonsterDrop(monsterLevel) {
    const state = window.worldExpState;
    if (state) {
        state.killCount = (state.killCount || 0) + 1;
    }
}

// 结算世界探索战斗，发放奖励并更新进度
function settleWorldExpBattle(isVictory) {
    const state = window.worldExpState;
    if (!state) return;
    
    const killCount = state.killCount || 0;
    const monsterLevel = (player.voidDepth || 0) + 500;
    const worldName = state.worldName || '未知世界';
    
    // 击杀数不足1000时，结算为空
    if (killCount < 1000) {
        let content = `<div style="text-align:center;">
            <span style="color:#f66;font-size:18px;">【 战斗失败 】</span><br>
            <span style="color:#ff0;">${worldName}</span><br>
            <span style="color:var(--text-color-dim,#888);">击杀数: ${killCount}</span><br><br>
            <span style="color:var(--text-color-dim,#888);">杀敌不足1000，无收益</span><br><br>
            <button onclick="closeModal()" class="sbtn-lg">确定</button>
        </div>`;
        
        delete player.worldExpState;
        window.lastWorldExpBattleState = {
            playerUnits: state.playerUnits,
            enemyUnits: state.enemyUnits,
            killCount: state.killCount || 0,
            playerDeathCount: state.playerDeathCount || 0,
            enemyCount: state.enemyCount || 0,
            deadPlayerKills: state.deadPlayerKills || [],
            deadEnemyKills: state.deadEnemyKills || [],
            worldName: state.worldName || '未知世界'
        };
        window.worldExpState = null;
        window.worldExpInBackground = true;
        window.worldExpBattleSpeed = 0;
        window.worldExpBattleMax = false;
        
        showModal(content, true);
        
        // 自动世界攻略模式下，延迟关闭弹窗并模拟点击返回按钮
        if (player.autoWorldExp) {
            setTimeout(() => {
                closeModal();
                // 模拟点击返回按钮
                const backBtn = document.getElementById('worldExpBackBtn');
                if (backBtn) {
                    backBtn.click();
                }
                updateStatusUI();
                
                // 军覆没，停止自动世界攻略
                player.autoWorldExp = false;
                player.autoWorldExpPhase = 'idle';
                hideAutoWorldExpOverlay();
                saveGameData();
            }, 1500);
        }
        return;
    }
    
    let spiritStones = 0;
    let immortalStones = 0;
    let treasure = 0;
    let lawFragments = 0;
    let timeCrystals = 0;  // 时间结晶掉落
    const items = [];
    const stoneBase = calcStoneBase(monsterLevel);
    const probSpirit = getQiYunProbability(0.01);
    const probImmortal = getQiYunProbability(0.0002);
    const probLaw = getQiYunProbability(0.05);
    const probHerb = getQiYunProbability(0.01);

    spiritStones = $floor($evalBig(`${killCount} * ${probSpirit} * ${stoneBase}`));
    immortalStones = $floor($evalBig(`${killCount} * ${probImmortal} * ${stoneBase}`));
    treasure = $floor($evalBig(`${killCount} * ${$pow(1.0339, monsterLevel)} * 10`));
    lawFragments = $floor($evalBig(`${killCount} * ${probLaw} * ${$pow(1.0339, monsterLevel)} * 5`));
    
    timeCrystals = calcTimeCrystalsExpectation(killCount, 2000, getFanXuLuFloor() || 0);
    
    const herbCount = $floor($evalBig(`${killCount} * ${probHerb}`));

    for (let i = 0; i < herbCount; i++) {
        const immortalHerbs = [
            '虚无空冥草', '先天一炁芝', '鸿蒙初形花', '混元真质蕊', '两仪混沌莲'
        ];
        const herbName = immortalHerbs[Math.floor(Math.randomNeutral() * immortalHerbs.length)];

        const grade = calcHerbGrade(monsterLevel);

        if (grade > 0) {
            const existingItem = items.find(item => item.name === herbName && item.grade === grade);
            if (existingItem) {
                existingItem.count = $addBig(existingItem.count, '1');
            } else {
                items.push({ name: herbName, grade: grade, count: '1' });
            }
        }
    }
    
    player.spiritStone = $addBig(player.spiritStone, String(spiritStones));
    player.immortalStone = $addBig(player.immortalStone, String(immortalStones));
    player.treasure = $addBig(player.treasure, String(treasure));
    player.lawFragments = $addBig(player.lawFragments, String(lawFragments));
    
    // 添加时间结晶到背包
    if (timeCrystals > 0) {
        const existingCrystal = player.bag.find(b => b.name === '时间结晶' && b.grade === 1);
        if (existingCrystal) {
            existingCrystal.count = $addBig(existingCrystal.count, String(timeCrystals));
        } else {
            player.bag.push({ name: '时间结晶', grade: 1, count: String(timeCrystals) });
        }
    }
    
    items.forEach(item => {
        const existingItem = player.bag.find(b => b.name === item.name && b.grade === item.grade);
        if (existingItem) {
            existingItem.count = $addBig(existingItem.count, item.count);
        } else {
            player.bag.push(item);
        }
        
        if (item.grade > player.highestHerbGrade) {
            player.highestHerbGrade = item.grade;
        }
    });
    
    let content = `<div style="text-align:center;">
        <span style="color:${isVictory ? '#0f0' : '#f66'};font-size:18px;">【 ${isVictory ? '战斗胜利' : '战斗失败'} 】</span><br>
        <span style="color:#ff0;">${worldName}</span><br>
        <span style="color:var(--text-color-dim,#888);">击杀数: ${killCount}</span><br><br>
        <span style="color:#afa;">【 总收益 】</span><br>`;
    
    if ($gtBig(String(spiritStones), '0')) {
        content += `<span style="color:var(--text-color,#fff);">灵石: +${formatPrecision(spiritStones)}</span><br>`;
    }
    if ($gtBig(String(immortalStones), '0')) {
        content += `<span style="color:var(--text-color,#fff);">仙石: +${formatPrecision(immortalStones)}</span><br>`;
    }
    if ($gtBig(String(treasure), '0')) {
        content += `<span style="color:var(--text-color,#fff);">天材地宝: +${formatPrecision(treasure)}</span><br>`;
    }
    if ($gtBig(String(lawFragments), '0')) {
        content += `<span style="color:var(--text-color,#fff);">法则碎片: +${formatPrecision(lawFragments)}</span><br>`;
    }
    if (timeCrystals > 0) {
        content += `<span style="color:var(--text-color,#fff);">时间结晶: +${formatNumber(timeCrystals)}</span><br>`;
    }
    
    if (items.length > 0) {
        const herbText = items.map(item => `${item.name}(${item.grade}阶)x${formatPrecision(item.count)}`).join('<br>');
        content += `<span style="color:var(--text-color,#fff);">仙草:<br>${herbText}</span><br>`;
    }
    
    if ($lteBig(String(spiritStones), '0') && $lteBig(String(immortalStones), '0') && 
        $lteBig(String(treasure), '0') && $lteBig(String(lawFragments), '0') && items.length === 0 && timeCrystals === 0) {
        content += `<span style="color:var(--text-color-dim,#888);">无收益</span><br>`;
    }
    
    content += `<br><button onclick="closeModal()" class="sbtn-lg">确定</button>
    </div>`;
    
    // 记录战斗历史（用于离线结算）
    if (isVictory && killCount > 0) {
        player.battleHistory.push({
            level: monsterLevel,
            duration: 1,  // 世界攻略不记录具体时长
            win: true,
            kills: killCount,
            timestamp: Date.now(),
            isWorldExp: true
        });
        // 只保留最近10场战斗
        if (player.battleHistory.length > 10) {
            player.battleHistory.shift();
        }
    }
    
    // 更新合道单位的杀敌数（技能不更新，传承技能只在战斗中生效）
    if (state.playerUnits) {
        const heDaoUnits = player.heDaoUnits || [];
        state.playerUnits.forEach(battleUnit => {
            if (battleUnit.isHeDao && battleUnit.originalSkills) {
                const heDaoUnit = heDaoUnits.find(h => h.name === battleUnit.name);
                if (heDaoUnit) {
                    heDaoUnit.killCount = (heDaoUnit.killCount || 0) + (battleUnit.killCount || 0);
                }
            }
        });
        player.heDaoUnits = heDaoUnits;
    }
    
    delete player.worldExpState;
    window.lastWorldExpBattleState = {
        playerUnits: state.playerUnits,
        enemyUnits: state.enemyUnits,
        killCount: state.killCount || 0,
        playerDeathCount: state.playerDeathCount || 0,
        enemyCount: state.enemyCount || 0,
        deadPlayerKills: state.deadPlayerKills || [],
        deadEnemyKills: state.deadEnemyKills || [],
        worldName: state.worldName || '未知世界'
    };
    window.worldExpState = null;
    window.worldExpInBackground = true;
    window.worldExpBattleSpeed = 0;
    window.worldExpBattleMax = false;
    showModal(content, true);
    
    // 自动世界攻略模式下，延迟关闭弹窗并模拟点击返回按钮
    if (player.autoWorldExp) {
        setTimeout(() => {
            closeModal();
            // 模拟点击返回按钮
            const backBtn = document.getElementById('worldExpBackBtn');
            if (backBtn) {
                backBtn.click();
            }
            updateStatusUI();
            
            handleAutoWorldExpEnd();
        }, 1500);
    }
}

