// 根据等级获取怪物数据（名称、属性）
function getMonsterDataForLevel(level, worldPrefix) {
    const monsters = [];
    const charPool = ['川', '峦', '汀', '浔', '岑', '沂', '岚', '嵩', '沄', '洲', '屿', '涧', '峯', '浦', '潇', '澈', '澄', '澜', '峤', '溪', '宸', '曜', '珩', '璟', '琛', '璨', '曦', '暝', '霄', '穹', '曜', '星', '辰', '玄', '朔', '昭', '晞', '朗', '烨', '昀', '灵', '瑶', '琼', '瑛', '瑜', '瑾', '瑶', '笙', '箫', '弦', '珵', '玥', '璃', '珞', '玑', '祯', '瑞', '祺', '麟', '凤', '清', '疏', '寂', '闲', '悠', '逸', '尘', '玄', '空', '澈', '宁', '安', '静', '舒', '然', '沐', '栖', '梧', '棠', '杉', '云', '烟', '雾', '霭', '风', '絮', '霜', '雪', '露', '霖', '霏', '濛', '霞', '霓', '虹', '风', '岚', '霭', '霄', '砚', '书', '辞', '砚', '墨', '锋', '剑', '道', '玄', '真', '悟', '修', '行', '远', '寻', '访', '游', '栖', '隐', '逸'];
    const getRandomChars = () => {
        const c1 = charPool[Math.floor(Math.randomNeutral() * charPool.length)];
        let c2 = charPool[Math.floor(Math.randomNeutral() * charPool.length)];
        while (c2 === c1) c2 = charPool[Math.floor(Math.randomNeutral() * charPool.length)];
        return c1 + c2;
    };
    for (let i = 0; i < 5; i++) {
        const fluctuationLevels = [0.85, 0.90, 0.95, 1.00, 1.05, 1.10, 1.15];
        const fluctuation = fluctuationLevels[Math.floor(Math.random() * fluctuationLevels.length)];
        const lgVal = $log10(String(level - 1));
        const hp = $floor($evalBig(`100 * (1.147 + ${lgVal} / 375) ^ ${level - 1} * ${fluctuation}`));
        const atk = $floor($evalBig(`6 * (1.147 + ${lgVal} / 375) ^ ${level - 1} * ${fluctuation}`));
        const def = 0;
        const speed = 100;
        monsters.push({
            name: worldPrefix + getRandomChars(),
            hp: hp,
            atk: atk,
            def: def,
            speed: speed
        });
    }
    return monsters;
}

// 显示单位属性详情弹窗（名称、生命、攻击、防御、速度）
function showUnitDetail(name, hp, atk, def, speed, isPlayer) {
    const color = isPlayer ? '#0f0' : '#f66';
    const box = document.getElementById('unitDetailBox');
    if (box) {
        box.innerHTML = `<div style="color:${color};font-size:18px;margin-bottom:15px;">${name}</div>
            <div style="color:var(--text-color,#fff);line-height:2;">
                <div>生命: ${formatNumber(hp)}</div>
                <div>攻击: ${formatNumber(atk)}</div>
                <div>防御: ${formatNumber(def)}</div>
                <div>速度: ${formatPrecision(speed)}</div>
            </div>
            <button onclick="this.parentElement.style.display='none'" class="sbtn-w" style="margin-top:15px">关闭</button>`;
        box.style.display = 'block';
    }
}

// 显示地图选择弹窗，列出可进入的地图区域
function showMapSelection() {
    const isVoidUnlocked = player.unlockedMaps.includes(101);
    const isVoidCurrent = battleState.currentMap === 101;
    const voidColor = isVoidCurrent ? '#0f0' : (isVoidUnlocked ? '#fff' : '#666');
    
    const hasPendingtongjiehoubei = player.worldDianHua && getPendingtongjiehoubeiCount() > 0;
    
    let voidHtml = '';
    if (isVoidUnlocked) {
        const hasDianHua = player.worldDianHua;
        const xujieColor = hasDianHua ? '#fff' : '#666';
        const xujieOnclick = hasDianHua ? 'onclick="showXuJieModal()" style="cursor:pointer;"' : '';
        const xujieText = hasDianHua ? '102<br>虚界' : '🔒<br>未解锁';
        voidHtml = `<div style="display:flex;gap:10px;margin-bottom:10px;">
            <div class="mod-box-2" style="flex:1;padding:25px 0;text-align:center;cursor:pointer;color:${voidColor};font-size:14px;" onclick="changeMap(101)">101<br>无尽虚空</div>
            <div class="mod-box-2" style="flex:1;padding:25px 0;text-align:center;color:${xujieColor};font-size:14px;" ${xujieOnclick}>${xujieText}</div>
        </div>`;
    } else if (player.unlockedMaps.includes(100)) {
        voidHtml = `<div style="display:flex;gap:10px;margin-bottom:10px;">
            <div class="mod-box-2" style="flex:1;padding:25px 0;text-align:center;cursor:pointer;color:#f66;font-size:14px;" onclick="startChallenge(101)">🔒<br>挑战解锁</div>
            <div class="mod-box-2" style="flex:1;padding:25px 0;text-align:center;color:#666;font-size:14px;">🔒<br>虚界</div>
        </div>`;
    }
    
    let table = '<table style="border-collapse:collapse;border:1px solid #fff;color:var(--text-color,#fff);font-family:monospace;text-align:center;width:100%;">';
    for (let i = 0; i < 20; i++) {
        table += '<tr>';
        for (let j = 0; j < 5; j++) {
            let mapNum;
            if (isVoidUnlocked) {
                mapNum = 100 - (i * 5 + j);
            } else {
                mapNum = i * 5 + j + 1;
            }
            if (mapNum < 1 || mapNum > 100) {
                table += `<td style="border:1px solid #333;padding:5px 10px;color:#333;width:20%;">---<br>--</td>`;
                continue;
            }
            const isUnlocked = player.unlockedMaps.includes(mapNum);
            const isCurrent = mapNum === battleState.currentMap;
            const color = isCurrent ? '#0f0' : (isUnlocked ? '#fff' : '#666');
            const isMap100WithPending = mapNum === 100 && hasPendingtongjiehoubei;
            const blinkClass = isMap100WithPending ? 'dianHua-blink' : '';
            const blinkStyle = isMap100WithPending ? 'border-color:#ff0;color:#ff0;' : '';
            
            if (isUnlocked) {
                table += `<td onclick="changeMap(${mapNum})" style="border:1px solid #fff;padding:5px 10px;cursor:pointer;color:${color};width:20%;${blinkStyle}" class="${blinkClass}">${mapNum.toString().padStart(3, '0')}<br>${mapNames[mapNum - 1]}</td>`;
            } else {
                const prevUnlocked = player.unlockedMaps.includes(mapNum - 1);
                if (prevUnlocked) {
                    table += `<td onclick="startChallenge(${mapNum})" style="border:1px solid #666;padding:5px 10px;cursor:pointer;color:#f66;width:20%;">🔒<br>挑战</td>`;
                } else {
                    table += `<td style="border:1px solid #333;padding:5px 10px;color:#333;width:20%;">🔒<br>--</td>`;
                }
            }
        }
        table += '</tr>';
    }
    table += '</table>';
    
    let titleHtml = `<span style="color:#ff0;font-size:16px;">【 地图选择 】</span>`;
    const canDianHua = player.realmIndex >= 4 && player.unlockedMaps.includes(101) && !player.worldDianHua;
    if (canDianHua) {
        titleHtml = `<span style="color:#ff0;font-size:16px;">【 地图选择 】</span><button onclick="showDianHuaConfirm()" class="sbtn dianHua-blink" style="margin-left:15px;font-size:12px;padding:2px 8px;color:#ff0;">点化</button>`;
    }
    
    let html = `<div id="mapSelectContent" style="padding:10px;color:var(--text-color,#fff);font-family:monospace;height:100%;box-sizing:border-box;overflow-y:auto;position:relative;">
        <div style="text-align:center;margin-bottom:10px;">${titleHtml}</div>
        ${voidHtml}
        ${table}
        <div style="text-align:center;margin-top:10px;">
            <span style="color:var(--text-color,#fff);">点击选择，绿字为当前</span><br>
            <span style="color:#f66;">点击锁挑战解锁</span>
        </div>
    </div>`;
    
    const battleContent = document.getElementById('battle-content');
    if (battleContent) {
        battleContent.innerHTML = html;
    }
}

