function getFanXuLuMirrorCount(floor) {
    return 1;
}

function getFanXuLuMirrorHp(floor) {
    return 179 + floor;
}

function showFanXuLu() {
    const currentFloor = getFanXuLuFloor();
    currentFanxuFloor = currentFloor;
    // 同步更新气运系数缓存（防止缓存过期）
    updateQiYunCoefficient(currentFloor);
    const mirrorHp = getFanXuLuMirrorHp(currentFloor);
    const dailyCount = getFanXuLuDailyCount();
    const dailyLimit = getFanXuLuDailyLimit();
    const remaining = Math.max(0, dailyLimit - dailyCount);
    
    const html = `<div style="padding:10px;color:var(--text-color,#fff);font-family:monospace;height:100%;box-sizing:border-box;display:flex;flex-direction:column;">
        <div style="text-align:center;margin-bottom:10px;"><span style="color:#ff0;font-size:16px;cursor:pointer;" onclick="showFanXuLuIntroModal()">【 返虚路 】</span></div>
        <div style="color:#ff0;font-size:12px;text-align:center;margin-bottom:8px;cursor:pointer;" onclick="showFanXuLuQiYunModal(${currentFloor})">返虚气息: ${currentFloor}</div>
        <div class="mod-box-2" style="padding:15px;text-align:center;margin-bottom:10px;">
            <div style="color:#f80;font-size:14px;margin-bottom:8px;">第 ${currentFloor} 层</div>
            <div style="color:#0f0;font-size:12px;margin-top:5px;">今日剩余挑战: ${remaining}/${dailyLimit}</div>
        </div>
        <div style="display:flex;gap:10px;justify-content:center;">
            <button onclick="startFanXuLuBattle()" class="sbtn-gr" style="font-size:14px;padding:8px 20px;"${remaining <= 0 ? ' disabled style="opacity:0.5;cursor:not-allowed;"' : ''}>开始挑战</button>
            <button onclick="showXuJieModal()" class="sbtn" style="font-size:14px;padding:8px 20px;">返回</button>
        </div>
    </div>`;
    
    const battleContent = document.getElementById('battle-content');
    if (battleContent) {
        battleContent.innerHTML = html;
    }
}

