function showFanXuLuQiYunModal(fanxuqixi) {
    const coef = 1 / (1 + fanxuqixi / 100);
    const p80 = 0.8 * coef + 0.2 * (1 - coef);
    const p20 = 0.2 * coef + 0.8 * (1 - coef);
    const pCrit = 0.2 * coef + 0.8 * (1 - coef);
    const pDodge = 0.2 * coef + 0.8 * (1 - coef);
    const pHeal = 0.2 * coef + 0.8 * (1 - coef);

    const modal = `<div style="background:rgba(0,0,0,${getModalOpacity()});border:2px solid #fff;padding:20px;color:var(--text-color,#fff);font-family:monospace;border-radius:4px;max-width:380px;max-height:80vh;overflow-y:auto;">
        <div style="color:#ff0;font-size:16px;margin-bottom:15px;text-align:center;">【 返虚气息效果 】</div>
        <div style="font-size:12px;line-height:1.8;text-align:left;">
            <div style="color:#0f0;margin-bottom:10px;">当前返虚气息: ${fanxuqixi}</div>
            <div style="margin-bottom:5px;">◆ 返虚气息影响</div>
            <div style="margin-left:10px;margin-bottom:5px;">
                返虚气息越高，底层随机函数受扰动越容易生成有利随机数，1返虚气息提高1%随机效果。<br> 
            <div style="color:#888;font-size:11px;margin-top:15px;text-align:center;">
                返虚气息 = 层数，层数越高加成越大
            </div>
        </div>
        <div style="text-align:center;margin-top:15px;">
            <button onclick="closeModal()" class="sbtn" style="padding:5px 20px;">关闭</button>
        </div>
    </div>`;
    closeModal();
    showModal(modal, true);
}

let fanXuLuBattleState = {
    inBattle: false,
    playerHp: '100',
    playerMaxHp: '100',
    mirrorHp: '100',
    mirrorMaxHp: '100',
    battleActions: [],
    actionIndex: 0,
    attackScheduler: null,
    paused: false,
    hitTarget: null,
    battleLog: [],
    battleLogHidden: false,
    currentFloor: 1,
    currentMirror: 1,
    totalMirrors: 3
};

function startFanXuLuBattle() {
    const dailyCount = getFanXuLuDailyCount();
    const dailyLimit = getFanXuLuDailyLimit();
    if (dailyCount >= dailyLimit) {
        return;
    }
    
    const currentFloor = getFanXuLuFloor();
    const mirrorMaxHp = getFanXuLuMirrorHp(currentFloor);
    
    fanXuLuBattleState = {
        inBattle: true,
        playerHp: '100',
        playerMaxHp: '100',
        mirrorHp: String(mirrorMaxHp),
        mirrorMaxHp: String(mirrorMaxHp),
        battleActions: [],
        actionIndex: 0,
        attackScheduler: null,
        paused: false,
        hitTarget: null,
        battleLog: [],
        battleLogHidden: false,
        currentFloor: currentFloor,
        qiYun: currentFloor
    };
    
    initFanXuLuBattleUI();
    simulateFanXuLuBattle();
}

function initFanXuLuBattleUI() {
    const battleContent = document.getElementById('battle-content');
    if (!battleContent) return;
    
    battleContent.innerHTML = `
        <div class="mod-box-2" id="fanxulu-content2"></div>
        <div class="mod-box-2" id="fanxulu-content3"></div>
        <div class="mod-box-2" id="fanxulu-content4"></div>
    `;
    
    updateFanXuLuBattleUI();
}

