    function generateName(rng) {
        const surname = rng.pick(surnames);
        const c1 = rng.pick(charPool);
        let c2 = rng.pick(charPool);
        while (c2 === c1) c2 = rng.pick(charPool);
        return surname + c1 + c2;
    }
    
    function calculateDailyLevelIncrease(generateDate, today, seedKey) {
        if (!generateDate) return 0;
        const parts = generateDate.split('-');
        if (parts.length !== 3) return 0;
        const createDate = new Date(parseInt(parts[0]), parseInt(parts[1]) - 1, parseInt(parts[2]));
        createDate.setHours(0, 0, 0, 0);
        const daysSinceCreation = Math.floor((today.getTime() - createDate.getTime()) / (1000 * 60 * 60 * 24));
        if (daysSinceCreation <= 0) return 0;
        
        let totalIncrease = 0;
        for (let i = 0; i < daysSinceCreation; i++) {
            const dayRng = createFixedDateRandomGenerator(generateDate, 'daily_level_' + seedKey + '_day_' + i, generateDate);
            totalIncrease += dayRng.nextInt(2, 4);
        }
        return totalIncrease;
    }
    
    function calculatetongjiehoubeiLevelIncrease(tongjiehoubeiDate, today, generateDate) {
        const daysSincetongjiehoubei = Math.floor((today.getTime() - tongjiehoubeiDate.getTime()) / (1000 * 60 * 60 * 24));
        if (daysSincetongjiehoubei <= 0) return 0;
        
        let totalIncrease = 0;
        for (let i = 0; i < daysSincetongjiehoubei; i++) {
            const dayRng = createFixedDateRandomGenerator(generateDate, 'tongjiehoubei_level_day_' + i, tongjiehoubeiDate.toDateString());
            totalIncrease += dayRng.nextInt(2, 4);
        }
        return totalIncrease;
    }
    
