function doGift(idx, giftType) {
    const char = window.lunDaoTaiCharacters[idx];
    if (!char) return;
    
    if (giftType === 'timeCrystal') {
        const item = player.bag.find(i => i.name === '时间结晶');
        if (!item || $lteBig(item.count, '0')) {
            return;
        }
        item.count = $subBig(item.count, '1');
        if ($lteBig(item.count, '0')) {
            player.bag = player.bag.filter(i => i.name !== '时间结晶');
        }
        const favorGain = 1;
        char.favor += favorGain;
        
        if (!player.lundaoCharData[char.charId]) {
            let generateDate;
            if (char.isFromtongjiehoubei && char.charId) {
                const tongjiehoubeiDate = new Date(char.charId);
                if (!isNaN(tongjiehoubeiDate.getTime())) {
                    generateDate = getStandardDateString(tongjiehoubeiDate);
                }
            }
            if (!generateDate) {
                generateDate = getStandardDateString();
            }
            player.lundaoCharData[char.charId] = { 
                count: 0, 
                extraLevel: 0, 
                giftFavor: 0, 
                giftCount: 0,
                lastAppear: Date.now(), 
                isFromtongjiehoubei: char.isFromtongjiehoubei,
                baseLevel: char.level - (char.extraLevel || 0),
                generateDate: generateDate
            };
        }
        player.lundaoCharData[char.charId].giftFavor += favorGain;
        player.lundaoCharData[char.charId].giftCount = (player.lundaoCharData[char.charId].giftCount || 0) + 1;
        player.lundaoCharData[char.charId].lastGiftDate = getStandardDateString();
        player.lundaoCharData[char.charId].count = char.lundaoCount || 0;
        player.lundaoCharData[char.charId].extraLevel = char.extraLevel || 0;
        if (player.lundaoCharData[char.charId].baseLevel === undefined) {
            player.lundaoCharData[char.charId].baseLevel = char.level - (char.extraLevel || 0);
        }
        if (!player.lundaoCharData[char.charId].generateDate) {
            if (char.isFromtongjiehoubei && char.charId) {
                const tongjiehoubeiDate = new Date(char.charId);
                if (!isNaN(tongjiehoubeiDate.getTime())) {
                    player.lundaoCharData[char.charId].generateDate = getStandardDateString(tongjiehoubeiDate);
                }
            }
            if (!player.lundaoCharData[char.charId].generateDate) {
                player.lundaoCharData[char.charId].generateDate = getStandardDateString();
            }
        }
        char.giftFavor = player.lundaoCharData[char.charId].giftFavor;
        char.giftCount = player.lundaoCharData[char.charId].giftCount;
    } else if (giftType === 'huanJiGuang') {
        const item = player.bag.find(i => i.name === '寰纪凝光');
        if (!item || $lteBig(item.count, '0')) {
            return;
        }
        item.count = $subBig(item.count, '1');
        if ($lteBig(item.count, '0')) {
            player.bag = player.bag.filter(i => i.name !== '寰纪凝光');
        }
        const favorGain = 100;
        char.favor += favorGain;
        
        if (!player.lundaoCharData[char.charId]) {
            let generateDate;
            if (char.isFromtongjiehoubei && char.charId) {
                const tongjiehoubeiDate = new Date(char.charId);
                if (!isNaN(tongjiehoubeiDate.getTime())) {
                    generateDate = getStandardDateString(tongjiehoubeiDate);
                }
            }
            if (!generateDate) {
                generateDate = getStandardDateString();
            }
            player.lundaoCharData[char.charId] = { 
                count: 0, 
                extraLevel: 0, 
                giftFavor: 0, 
                giftCount: 0,
                lastAppear: Date.now(), 
                isFromtongjiehoubei: char.isFromtongjiehoubei,
                baseLevel: char.level - (char.extraLevel || 0),
                generateDate: generateDate
            };
        }
        player.lundaoCharData[char.charId].giftFavor += favorGain;
        player.lundaoCharData[char.charId].giftCount = (player.lundaoCharData[char.charId].giftCount || 0) + 1;
        player.lundaoCharData[char.charId].lastGiftDate = getStandardDateString();
        player.lundaoCharData[char.charId].count = char.lundaoCount || 0;
        player.lundaoCharData[char.charId].extraLevel = char.extraLevel || 0;
        if (player.lundaoCharData[char.charId].baseLevel === undefined) {
            player.lundaoCharData[char.charId].baseLevel = char.level - (char.extraLevel || 0);
        }
        if (!player.lundaoCharData[char.charId].generateDate) {
            if (char.isFromtongjiehoubei && char.charId) {
                const tongjiehoubeiDate = new Date(char.charId);
                if (!isNaN(tongjiehoubeiDate.getTime())) {
                    player.lundaoCharData[char.charId].generateDate = getStandardDateString(tongjiehoubeiDate);
                }
            }
            if (!player.lundaoCharData[char.charId].generateDate) {
                player.lundaoCharData[char.charId].generateDate = getStandardDateString();
            }
        }
        char.giftFavor = player.lundaoCharData[char.charId].giftFavor;
        char.giftCount = player.lundaoCharData[char.charId].giftCount;
    }
    
    saveGameData();
    
    closeModal();
    showGiftModal(idx);
}

