// 通用升级费用计算：等级<1e100时100*1.25^等级，超过后等级*100
function getStandardCost(level) {
    const levelStr = String(level);
    if ($gteBig(levelStr, '1e100')) {
        return $evalBig(`${levelStr} * 100`);
    }
    return $evalBig(`floor(100 * 1.25^${levelStr})`);
}

// 天材地宝升级费用（委托getStandardCost）
function getTreasureCost(level) { return getStandardCost(level); }
// 灵田升级费用（委托getStandardCost）
function getSpiritFieldCost(level) { return getStandardCost(level); }
// 纳戒容量升级费用（委托getStandardCost）
function getBagLevelCost(level) { return getStandardCost(level); }

// 计算灵田升级消耗

// 计算等比数列求和：从等级fromLevel升到toLevel的总消耗
// 公式：S = a * (r^n - 1) / (r - 1)，其中a是首项，r是公比，n是项数
function calculateGeometricSum(fromLevel, toLevel, baseCost, ratio) {
    if (toLevel <= fromLevel) return '0';
    const n = toLevel - fromLevel;
    const fromLevelStr = String(fromLevel);
    const ratioStr = String(ratio);
    
    if ($gteBig(String(n), '1e10')) {
        return 'Infinity';
    }
    
    const a = $evalBig(`${baseCost} * ${ratioStr}^${fromLevelStr}`);
    const ratioPowN = $pow(ratioStr, String(n));
    const numerator = $subBig(ratioPowN, '1');
    const denominator = $subBig(ratioStr, '1');
    const sum = $mulBig(a, $divBig(numerator, denominator));
    
    return sum;
}

// 直接计算最高可升级等级和总消耗（O(1)复杂度）
// 公式：n_max = floor(log(1 + z*(b-1)/x, b))
// 参数：x=首项, b=公比, z=资源上限
function findMaxUpgradeLevelAndCost(currentLevel, treasure, baseCost, ratio) {
    const ratioStr = String(ratio);
    const treasureStr = String(treasure);
    const a = $evalBig(`${baseCost} * ${ratioStr}^${currentLevel}`);
    const rMinus1 = $subBig(ratioStr, '1');
    const zTimesRminus1 = $mulBig(treasureStr, rMinus1);
    const innerValue = $addBig('1', $divBig(zTimesRminus1, a));
    
    const logInner = $log10(innerValue);
    const logRatio = $log10(ratioStr);
    const logValue = $divBig(logInner, logRatio);
    const nMaxStr = $floor(logValue);
    const nMax = Math.max(0, Math.floor(parseFloat(nMaxStr)));
    
    const maxLevel = currentLevel + nMax;
    const totalCost = calculateGeometricSum(currentLevel, maxLevel, baseCost, ratio);
    
    return { maxLevel, totalCost };
}

// 通用天材地宝升级函数：检查资源→扣除→升级→更新UI
function upgradeWithTreasure(levelProperty, costFn, extraUpdateFn) {
    const cost = costFn(player[levelProperty]);
    if (!$gteBig(player.treasure, cost)) {
        showResourceShortageModal('天材地宝', cost, player.treasure);
        return;
    }
    player.treasure = $subBig(player.treasure, String(cost));
    player[levelProperty] += 1;
    updateEquipmentUI();
    updateStatusUI();
    if (extraUpdateFn) extraUpdateFn();
    saveGameData();
}

// 通用天材地宝一键最高级：使用等比数列求和公式一步到位
// 参数：levelProperty-等级属性名, baseCost-基础消耗, ratio-公比, extraUpdateFn-额外更新函数
function upgradeWithTreasureAutoMax(levelProperty, baseCost, ratio, extraUpdateFn, silent = false) {
    if (!silent) closeModal();
    const currentLevel = player[levelProperty];
    const treasure = player.treasure;
    
    const { maxLevel, totalCost } = findMaxUpgradeLevelAndCost(currentLevel, treasure, baseCost, ratio);
    
    if (maxLevel <= currentLevel) {
        return;
    }
    
    player.treasure = $subBig(player.treasure, totalCost);
    player[levelProperty] = maxLevel;
    
    updateEquipmentUI();
    updateStatusUI();
    if (extraUpdateFn) extraUpdateFn();
    saveGameData();
}

