// 计算强化成功率
function getEnhanceSuccessRate(level) {
    return $pow(0.7943282347242816, level);
}

// 强化位格

// 通用武器属性强化：检查天材地宝→扣除→属性+1→更新
function enhanceWeaponStat(statKey, extraCallback) {
    if (player.weapon[statKey] === undefined) {
        player.weapon[statKey] = 0;
    }
    const cost = getTreasureCost(player.weapon[statKey]);
    if (!$gteBig(player.treasure, String(cost))) return;
    player.treasure = $subBig(player.treasure, String(cost));
    player.weapon[statKey] += 1;
    if (extraCallback) extraCallback();
    calculateCultivationStats();
    player.hp = player.maxHp;
    updateWeaponUI();
    updateStatusUI();
}

// 通用武器属性自动强化：根据模式选择升级方式
function enhanceWeaponStatAuto(statKey, extraCallback) {
    if (player.weapon[statKey] === undefined) {
        player.weapon[statKey] = 0;
    }
    
    if (player.treasureAutoMax === 'instant') {
        // 直接升满模式：一次性计算
        const currentLevel = player.weapon[statKey];
        const { maxLevel, totalCost } = findMaxUpgradeLevelAndCost(currentLevel, player.treasure, 100, 1.25);
        
        if (maxLevel <= currentLevel) return;
        
        player.treasure = $subBig(player.treasure, totalCost);
        player.weapon[statKey] = maxLevel;
        if (extraCallback) {
            const upgradeCount = maxLevel - currentLevel;
            for (let i = 0; i < upgradeCount; i++) {
                extraCallback();
            }
        }
        calculateCultivationStats();
        player.hp = player.maxHp;
        updateWeaponUI();
        updateStatusUI();
    } else if (player.treasureAutoMax === 'gradual') {
        // 逐渐升级模式：循环升级
        const cost = getTreasureCost(player.weapon[statKey]);
        if (!$gteBig(player.treasure, String(cost))) return;
        player.treasure = $subBig(player.treasure, String(cost));
        player.weapon[statKey] += 1;
        if (extraCallback) extraCallback();
        calculateCultivationStats();
        player.hp = player.maxHp;
        updateWeaponUI();
        updateStatusUI();
        setTimeout(() => enhanceWeaponStatAuto(statKey, extraCallback), 10);
    } else {
        // 关闭模式：单次升级
        const cost = getTreasureCost(player.weapon[statKey]);
        if (!$gteBig(player.treasure, String(cost))) return;
        player.treasure = $subBig(player.treasure, String(cost));
        player.weapon[statKey] += 1;
        if (extraCallback) extraCallback();
        calculateCultivationStats();
        player.hp = player.maxHp;
        updateWeaponUI();
        updateStatusUI();
    }
}

// 强化武器威力等级，同时增加powerBonus（委托enhanceWeaponStat）
function enhancePower(count) {
    if (count === undefined) count = player.lastEnhanceCount;
    player.lastEnhanceCount = count;
    enhanceWeaponStat('powerLevel', () => { player.weapon.powerBonus += 0.01; });
}

// 强化法则
function enhanceLaw(lawKey, count) {
    if (count === undefined) count = player.lastEnhanceCount;
    player.lastEnhanceCount = count;
    const cost = getTreasureCost(player.weapon.lawLevels[lawKey]);
    const totalCost = cost * count;
    if (!$gteBig(player.treasure, String(totalCost))) return;
    player.treasure = $subBig(player.treasure, String(totalCost));
    player.weapon.lawLevels[lawKey] += 1;
    calculateCultivationStats();
    player.hp = player.maxHp;
    updateWeaponUI();
    updateStatusUI();
}

// 强化武器攻击
function enhanceWeaponAttack() {
    enhanceWeaponStat('attackLevel');
}

// 强化武器暴击伤害
function enhanceWeaponCritDamage() {
    enhanceWeaponStat('critDamageLevel');
}

// 强化武器暴击率
function enhanceWeaponCritRate() {
    enhanceWeaponStat('critRateLevel');
}

// 强化武器飞剑随行
function enhanceWeaponJianzhen() {
    enhanceWeaponStat('jianzhenLevel');
}

// 切换天材地宝自动升级开关：off -> instant -> gradual -> off
function toggleTreasureAutoMax() {
    if (player.treasureAutoMax === 'off') {
        player.treasureAutoMax = 'instant';
    } else if (player.treasureAutoMax === 'instant') {
        player.treasureAutoMax = 'gradual';
    } else {
        player.treasureAutoMax = 'off';
    }
    updateWeaponUI();
}

// 显示法宝自动加点选择弹窗
function showTreasureAutoAddPointsModal() {
    const treasureOptions = [
        { key: 'power', name: '位格', desc: '位格+0.01/级', func: 'enhancePowerAuto' },
        { key: 'life', name: '生命法则', desc: '法则领悟+0.1%/级', func: 'enhanceLawAuto("life")' },
        { key: 'strength', name: '力量法则', desc: '法则领悟+0.1%/级', func: 'enhanceLawAuto("strength")' },
        { key: 'order', name: '秩序法则', desc: '法则领悟+0.1%/级', func: 'enhanceLawAuto("order")' },
        { key: 'fate', name: '命运法则', desc: '法则领悟+0.1%/级', func: 'enhanceLawAuto("fate")' },
        { key: 'destruction', name: '毁灭法则', desc: '法则领悟+0.1%/级', func: 'enhanceLawAuto("destruction")' },
        { key: 'attack', name: '攻击强化', desc: '攻击+1/级', func: 'enhanceWeaponAttackAuto' },
        { key: 'critDamage', name: '暴伤强化', desc: '暴伤+10%/级', func: 'enhanceWeaponCritDamageAuto' },
        { key: 'critRate', name: '暴率强化', desc: '暴率+0.2%/级', func: 'enhanceWeaponCritRateAuto' },
        { key: 'jianzhen', name: '飞剑随行', desc: '神通强化', func: 'enhanceWeaponJianzhenAuto' },
        { key: 'daozhi', name: '道滞领域', desc: '神通强化', func: 'enhanceDaozhiAuto' }
    ];
    
    let checkboxesHtml = '';
    for (const opt of treasureOptions) {
        const checked = player.treasureAutoAddPointsList.includes(opt.key) ? 'checked' : '';
        checkboxesHtml += `
            <div style="display:flex;align-items:center;margin:8px 0;">
                <input type="checkbox" id="treasureAuto_${opt.key}" ${checked} style="width:18px;height:18px;cursor:pointer;">
                <label for="treasureAuto_${opt.key}" style="margin-left:8px;cursor:pointer;flex:1;">
                    <span style="color:#ff0;">${opt.name}</span>
                    <span style="color:#888;font-size:12px;">(${opt.desc})</span>
                </label>
            </div>
        `;
    }
    
    const modalHtml = `
        <div style="color:#ff0;font-size:16px;margin-bottom:15px;">法宝自动加点设置</div>
        <div style="color:#888;font-size:12px;margin-bottom:10px;">选择要自动加点的法宝属性，每3秒随机选择一个进行升级</div>
        ${checkboxesHtml}
        <div style="margin-top:20px;display:flex;gap:10px;justify-content:center;">
            <button onclick="saveTreasureAutoAddPointsSettings()" class="sbtn" style="padding:8px 20px;">确定</button>
            <button onclick="closeModal()" class="sbtn" style="padding:8px 20px;">取消</button>
        </div>
    `;
    
    showModal(modalHtml, true);
}

// 保存法宝自动加点设置
function saveTreasureAutoAddPointsSettings() {
    const treasureKeys = ['power', 'life', 'strength', 'order', 'fate', 'destruction', 'attack', 'critDamage', 'critRate', 'jianzhen', 'daozhi'];
    player.treasureAutoAddPointsList = [];
    
    for (const key of treasureKeys) {
        const checkbox = document.getElementById(`treasureAuto_${key}`);
        if (checkbox && checkbox.checked) {
            player.treasureAutoAddPointsList.push(key);
        }
    }
    
    player.treasureAutoAddPoints = player.treasureAutoAddPointsList.length > 0;
    closeModal();
    updateWeaponUI();
    saveGameData();
}

// 执行法宝自动加点（每10秒调用一次）
function executeTreasureAutoAddPoints() {
    if (!player.treasureAutoAddPoints || player.treasureAutoAddPointsList.length === 0) return;
    
    const list = player.treasureAutoAddPointsList;
    const randomIndex = Math.floor(Math.random() * list.length);
    const selectedKey = list[randomIndex];
    
    switch (selectedKey) {
        case 'power':
            enhancePowerAuto();
            break;
        case 'life':
            enhanceLawAuto('life');
            break;
        case 'strength':
            enhanceLawAuto('strength');
            break;
        case 'order':
            enhanceLawAuto('order');
            break;
        case 'fate':
            enhanceLawAuto('fate');
            break;
        case 'destruction':
            enhanceLawAuto('destruction');
            break;
        case 'attack':
            enhanceWeaponAttackAuto();
            break;
        case 'critDamage':
            enhanceWeaponCritDamageAuto();
            break;
        case 'critRate':
            enhanceWeaponCritRateAuto();
            break;
        case 'jianzhen':
            enhanceWeaponJianzhenAuto();
            break;
        case 'daozhi':
            enhanceDaozhiAuto();
            break;
    }
}

