// 显示飞剑随行详情
function showJianzhenInfo() {
    const jianzhenLevel = player.weapon.jianzhenLevel || 0;
    let jianzhenCoefficient = 0;
    if (jianzhenLevel > 0) {
        const logLevel = $log10(String(jianzhenLevel + 1));
        const logBase = $log10('1.5');
        jianzhenCoefficient = parseFloat($evalBig(`${logLevel} / ${logBase} / 10`));
    }
    const description = '飞剑随行：首次攻击召唤飞剑构成剑阵（不造成伤害），后续每次攻击飞剑助阵，伤害逐剑线性递增。';
    let effectText = '未强化';
    if (jianzhenLevel > 0) {
        const c = jianzhenCoefficient;
        const c2 = formatNumber(c * 1);
        const c3 = formatNumber(c * 2);
        const c4 = formatNumber(c * 3);
        effectText = `系数: ${formatNumber(c)}（第2剑${c2}，第3剑${c3}，第4剑${c4}...）`;
    }
    showModal(`<span style="color:#ff0;">【 飞剑随行 】</span><br>
        <br>等级: ${jianzhenLevel}级
        <br><br>${description}
        <br><br>${effectText}
        <br><br>
        <button onclick="closeModal()" class="sbtn">关闭</button>
    `, true);
}

