function generateVoidMonsterName() {
    const g1 = voidMonsterGroup1;
    const g2 = voidMonsterGroup2;
    const g3 = voidMonsterGroup3;
    const name = g1[Math.floor(Math.randomNeutral() * g1.length)] + g2[Math.floor(Math.randomNeutral() * g2.length)] + g3[Math.floor(Math.randomNeutral() * g3.length)];
    return name;
}

/**
 * 更新无尽虚空界面
 * 显示当前深度、怪物信息和操作按钮
 */
// 更新虚空界面显示（层数、怪物信息、自动模式状态）
function updateVoidUI() {
    const voidContent = document.querySelector('#void-content');
    if (!voidContent) return;
    
    // 获取当前深入深度
    const depth = player.voidDepth || 0;
    // 怪物等级 = 基础等级500 + 深度
    const monsterLevel = 500 + depth;
    const displayLevel = monsterLevel - 500;
    const autoBattle = player.voidAutoBattle;
    const autoBtnText = autoBattle === 'deepen' ? '自动深入中' : (autoBattle === 'instakill' ? '自动秒杀中' : '自动深入');
    const autoBtnBg = autoBattle === 'deepen' ? '#2a2' : (autoBattle === 'instakill' ? '#a2a' : '#333');
    
    const randomMonster = generateVoidMonsterName();
    
    // 构建界面HTML
    let html = `
        <div class="text-line">${box.top}</div>
        <div class="text-line">${box.line} 深入等级: ${depth} ${box.line}</div>
        <div class="text-line">${box.line} 区域等级: ${displayLevel} ${box.line}</div>
        <div class="text-line"></div>
        <div class="text-line">${box.line} 当前怪物: ${randomMonster} ${box.line}</div>
        <div class="text-line">${box.line} 等级: ${monsterLevel} ${box.line}</div>
        <div class="text-line"></div>
        <div class="text-line">${box.line} 
            <button onclick="goDeeper()" class="sbtn-510">深入</button>
            <button onclick="goBack()" class="sbtn-510">回退</button>
            <button onclick="toggleVoidAuto()" style="background:${autoBtnBg};color:var(--text-color,#fff);border:1px solid #666;padding:5px 10px;cursor:pointer;">${autoBtnText}</button>
        ${box.line}</div>
        <div class="text-line"></div>
        <div class="text-line">${box.line} <button onclick="voidFight()" style="background:rgba(136,51,51,var(--terminal-opacity));color:var(--text-color,#fff);border:1px solid #666;padding:8px 20px;cursor:pointer;">挑战</button> ${box.line}</div>
        <div class="text-line">${box.bottom}</div>
    `;
    
    voidContent.innerHTML = html;
}

/**
 * 深入虚空
 * 增加深入等级，怪物等级随之提升
 */
// 深入虚空下一层，提升怪物等级和奖励
function goDeeper() {
    player.voidDepth++;
    battleState.inBattle = false;
    if (battleState.attackScheduler) {
        clearTimeout(battleState.attackScheduler);
        battleState.attackScheduler = null;
    }
    updateVoidUI();
    saveGameData();
}

/**
 * 回退虚空
 * 减少深入等级（最低为0）
 */
// 返回虚空上一层，降低怪物等级
function goBack() {
    if (player.voidDepth > 0) {
        player.voidDepth--;
        battleState.inBattle = false;
        if (battleState.attackScheduler) {
            clearTimeout(battleState.attackScheduler);
            battleState.attackScheduler = null;
        }
        updateVoidUI();
        saveGameData();
    }
}

/**
 * 开始虚空战斗
 * 设置当前地图为虚空（-1），跳转到战斗界面
 */
// 虚空战斗，与当前层怪物交战
function voidFight() {
    const depth = player.voidDepth || 0;
    const monsterLevel = 500 + depth;
    const monsterName = generateVoidMonsterName();
    
    // 设置当前地图为虚空（-1表示虚空）
    player.currentMap = -1;
    player.currentMonsterLevel = monsterLevel;
    player.currentMonsterName = monsterName;
    
    // 切换到战斗标签页
    document.querySelectorAll('.tab').forEach(t => t.classList.remove('active'));
    document.querySelectorAll('.tab-content').forEach(t => t.classList.remove('active'));
    document.querySelector('[data-tab="battle"]').classList.add('active');
    document.getElementById('tab-battle').classList.add('active');
    updateBattleUI();
}

