    const herbNames = ['灵心草', '幽兰', '朱血藤', '银莲', '金果', '玉髓', '星尘花', '太初叶', '混元枝', '虚无根',
                       '虚无空冥草', '先天一炁芝', '鸿蒙初形花', '混元真质蕊', '两仪混沌莲'];
    let benYuanGain = 0;
    if (herbNames.includes(item.name) && item.grade >= 1) {
        const benYuanRates = [0, 0.05, 0.07, 0.1, 0.14, 0.2, 0.3, 0.45, 0.65, 1];
        const rate = item.grade >= 9 ? 1 : (benYuanRates[item.grade] || 0);
        benYuanGain = useCount * rate;
        if (benYuanGain > 0) {
            addFirstCharacterBenYuan(benYuanGain);
            player.benYuan = getFirstCharacterBenYuan();
            calculateCultivationStats();
        }
    }
    
    item.count = $subBig(item.count, String(useCount));
    
    if ($lteBig(item.count, '0')) {
        player.bag.splice(slotIndex, 1);
    }
    
