function showAttributeInfo() {
    const html = `<div style="background:rgba(0,0,0,${getModalOpacity()});border:2px solid #fff;padding:20px;color:var(--text-color,#fff);font-family:monospace;width:90vw;max-width:400px;border-radius:4px;font-size:13px;">
<div style="font-size:16px;color:#ff0;margin-bottom:12px;text-align:center;">【 属性计算说明 】</div>
<div style="line-height:1.8;">
<b style="color:#0ff;">基础属性</b><br>
生命 = 100 + 内部等级×10 + 丹药加成<br>
攻击 = 10 + 内部等级×1 + 武器攻击等级×1 + 丹药加成<br>
防御 = 5 + 内部等级×0.5 + 丹药加成<br>
攻速 = 10 + 内部等级×1 (上限100)<br>
<br>
<b style="color:#0ff;">最终属性公式</b><br>
设 x = 位格 + 法则领悟度/10<br>
倍率 = 100^(x-7.94) 当x≥28.79<br>
倍率 = max(1.2^x, (0.5x)^(1.25x)) 当x&lt;28.79<br>
最终属性 = floor(基础值 × 倍率) × 内天地加成<br>
<br>
<b style="color:#0ff;">暴击公式</b><br>
暴击率 = 命运法则×lg(命运法则)/2 + 丹药 + 武器暴击率×0.2<br>
暴伤 = 毁灭法则×lg(毁灭法则)×20 + 武器暴伤×10 + 丹药<br>
</div>
<div style="margin-top:15px;text-align:center;"><button onclick="closeModal()" class="sbtn-lg">关闭</button></div>
</div>`;
    showModal(html, true);
}

