// 检查并执行自动备份，防止存档丢失
function checkAndAutoBackup() {
    const now = new Date();
    const today = now.getFullYear() + '-' + String(now.getMonth() + 1).padStart(2, '0') + '-' + String(now.getDate()).padStart(2, '0');
    const lastBackupDate = localStorage.getItem('wenziguaji_last_backup');
    
    if (lastBackupDate !== today) {
        const charList = getCharacterList();
        const allCharData = [];

        for (const char of charList) {
            if (!char) continue;
            const saveKey = getCharacterSaveKey(char.id);
            const charDataStr = localStorage.getItem(saveKey);
            if (charDataStr) {
                try {
                    const charData = JSON.parse(charDataStr);
                    allCharData.push({
                        id: char.id,
                        name: char.name,
                        data: charData
                    });
                } catch (e) {}
            }
        }

        if (allCharData.length > 0) {
            try {
                const exportData = {
                    version: 1,
                    characters: allCharData,
                    exportTime: Date.now()
                };
                const saveData = JSON.stringify(exportData);
                const base64Data = utf8ToBase64(saveData);
                const fileName = '修仙挂机存档/修仙挂机_' + today + '.txt';
                
                if (typeof AndroidInterface !== 'undefined' && AndroidInterface.downloadFile) {
                    try {
                        AndroidInterface.downloadFile(base64Data, fileName, 'text/plain');
                    } catch (androidError) {
                        console.warn('Android接口调用失败:', androidError);
                        const blob = new Blob([base64Data], { type: 'text/plain' });
                        const url = URL.createObjectURL(blob);
                        const a = document.createElement('a');
                        a.href = url;
                        a.download = fileName;
                        document.body.appendChild(a);
                        a.click();
                        document.body.removeChild(a);
                        URL.revokeObjectURL(url);
                    }
                } else {
                    const blob = new Blob([base64Data], { type: 'text/plain' });
                    const url = URL.createObjectURL(blob);
                    const a = document.createElement('a');
                    a.href = url;
                    a.download = fileName;
                    document.body.appendChild(a);
                    a.click();
                    document.body.removeChild(a);
                    URL.revokeObjectURL(url);
                }
                
                localStorage.setItem('wenziguaji_last_backup', today);
            } catch (error) {
                console.error('每日存档备份失败:', error);
            }
        }
    }
}

/**
 * 键盘快捷键处理
 * 数字键1-5对应不同的存档操作
 */
document.addEventListener('keydown', function(e) {
    // 如果在输入框中，不处理快捷键
    if (e.target.tagName === 'INPUT' || e.target.tagName === 'TEXTAREA') return;
    
    switch(e.key) {
        case '1': // 快速存档
            saveGameData();
            showModal(`<span style="color:#ff0;">【 系统提示 】</span><br><br>
                <span style="color:#afa;">存档成功！</span>
                <br><br>
                <button onclick="closeModal()" class="sbtn">确定</button>
            `, true);
            break;
        case '2': // 快速读档
            player = loadGameData();
            calculateCultivationStats();
            updateplayernameUI();
            updateStatusUI();
            updateBattleUI();
            updateCultivationUI();
            updateWeaponUI();
            updateEquipmentUI();
            updateBagUI();
            showModal(`<span style="color:#ff0;">【 系统提示 】</span><br><br>
                <span style="color:#afa;">读档成功！</span>
                <br><br>
                <button onclick="closeModal()" class="sbtn">确定</button>
            `, true);
            break;
        case '3': // 导出存档
            exportSaveData();
            break;
        case '4': // 导入存档
            importSaveData();
            break;
        case '5': // 清除存档
            clearSaveData();
            break;
        case '6': // 背景图片设置
            showBackgroundImageModal();
            break;
    }
});

