function getFirstCharacterMaxVoidVictoryLevel() {
    const charList = getCharacterList();
    const mainChar = charList[0];
    if (!mainChar) return 1;
    const firstCharId = mainChar.id;
    const saveKey = getCharacterSaveKey(firstCharId);
    const charDataStr = localStorage.getItem(saveKey);
    if (!charDataStr) return 1;
    try {
        const charData = JSON.parse(charDataStr);
        return charData.maxVoidVictoryLevel || 1;
    } catch (e) {
        return 1;
    }
}

// 获取本源攻击加成
/**
 * 获取本源属性加成倍率
 * 用于计算内天地对生命、攻击、防御的加成
 * 公式: 1.05^floor(log10(基础值 × 本源数量))
 * 基础值 = 6 × (1.147 + lg(本源等级-1)/375)^(本源等级-1)
 * 本源等级 = 世界核心等级 + 500
 * @returns {string} 属性加成倍率字符串
 */
function getBenYuanPower() {
    const benYuanCount = getFirstCharacterBenYuan();
    if (!benYuanCount || $lteBig(String(benYuanCount), '0')) return '1';
    const voidLevel = player.maxVoidVictoryLevel || 0;
    if (voidLevel === 0) return '1';
    const level = voidLevel + 500;
    const count = benYuanCount;
    const lgVal = $log10(String(level - 1));
    const base = $evalBig(`6 * (1.147 + ${lgVal} / 375) ^ ${level - 1}`);
    const totalBase = $evalBig(String(base) + '*' + String(count));
    const logVal = $floor($log10(totalBase));
    const exponent = $evalBig(`${logVal} * ${Math.log10(1.05)}`);
    return $evalBig(`10^${exponent}`);
}

// 获取本源生命加成
/**
 * 获取本源生命加成倍率
 * 与getBenYuanPower计算逻辑相同
 * @returns {string} 生命加成倍率字符串
 */
function getBenYuanHpPower() {
    const benYuanCount = getFirstCharacterBenYuan();
    if (!benYuanCount || $lteBig(String(benYuanCount), '0')) return '1';
    const voidLevel = player.maxVoidVictoryLevel || 0;
    if (voidLevel === 0) return '1';
    const level = voidLevel + 500;
    const count = benYuanCount;
    const lgVal = $log10(String(level - 1));
    const base = $evalBig(`6 * (1.147 + ${lgVal} / 375) ^ ${level - 1}`);
    const totalBase = $evalBig(String(base) + '*' + String(count));
    const logVal = $floor($log10(totalBase));
    const exponent = $evalBig(`${logVal} * ${Math.log10(1.05)}`);
    return $evalBig(`10^${exponent}`);
}

// 获取本源防御加成
/**
 * 获取本源防御加成倍率
 * 与getBenYuanPower计算逻辑相同
 * @returns {string} 防御加成倍率字符串
 */
function getBenYuanDefPower() {
    const benYuanCount = getFirstCharacterBenYuan();
    if (!benYuanCount || $lteBig(String(benYuanCount), '0')) return '1';
    const voidLevel = player.maxVoidVictoryLevel || 0;
    if (voidLevel === 0) return '1';
    const level = voidLevel + 500;
    const count = benYuanCount;
    const lgVal = $log10(String(level - 1));
    const base = $evalBig(`6 * (1.147 + ${lgVal} / 375) ^ ${level - 1}`);
    const totalBase = $evalBig(String(base) + '*' + String(count));
    const logVal = $floor($log10(totalBase));
    const exponent = $evalBig(`${logVal} * ${Math.log10(1.05)}`);
    return $evalBig(`10^${exponent}`);
}

// 计算内天地收益（每60秒）
/**
 * 计算内天地收益（每60秒执行一次）
 * 化神后（realmIndex >= 4）才能获得收益
 * 收益包括：灵石、仙石、天材地宝、法则碎片、灵药、生灵
 * 收益倍率 = (log10(本源数量+10))^3 / 3.3333
 */
function calculateNeitiandiIncome() {
    const benYuanCount = getFirstCharacterBenYuan();
    if (!benYuanCount || $lteBig(String(benYuanCount), '0')) return;
    if (player.realmIndex < 4) return;

    const monsterLevel = player.maxVoidVictoryLevel + 500;
    const count = String(benYuanCount);

    // 使用高精度计算
    const lgVal = $log10($addBig(count, '10'));
    const lgCubed = $pow(lgVal, '3');
    const multiplier = $evalBig(`${lgCubed} / 3.3333`);
    const stoneBase = calcStoneBase(monsterLevel);
    const probSpirit = getQiYunProbability(0.01);
    const probImmortal = getQiYunProbability(0.0002);
    const probLaw = getQiYunProbability(0.05);
    const probHerb = getQiYunProbability(0.01);

    const spiritStoneIncome = $floor($evalBig(`${stoneBase} * ${probSpirit} * ${multiplier}`));
    const immortalStoneIncome = $floor($evalBig(`${stoneBase} * ${probImmortal} * ${multiplier}`));
    const treasureIncome = $floor($evalBig(`${$pow(1.0339, monsterLevel)} * 10 * ${multiplier}`));
    const lawFragmentsIncome = $floor($evalBig(`${$pow(1.0339, monsterLevel)} * 5 * ${probLaw} * ${multiplier}`));

    player.neitiandiPending.spiritStone = $addBig(player.neitiandiPending.spiritStone, spiritStoneIncome);
    player.neitiandiPending.immortalStone = $addBig(player.neitiandiPending.immortalStone, immortalStoneIncome);
    player.neitiandiPending.treasure = $addBig(player.neitiandiPending.treasure, treasureIncome);
    player.neitiandiPending.lawFragments = $addBig(player.neitiandiPending.lawFragments, lawFragmentsIncome);

    const herbCount = $floor($evalBig(`${multiplier} * ${probHerb}`));
    
    // herbCount 转为数字用于数组长度，但需要限制最大值
    let herbCountNum = Number(herbCount);
    if (!Number.isFinite(herbCountNum) || herbCountNum > 1000000) {
        herbCountNum = 1000000;
    }

    if (herbCountNum > 0) {
        const herbGrades = calcHerbGrades(monsterLevel, herbCountNum, 2);
        const immortalHerbs = ['虚无空冥草', '先天一炁芝', '鸿蒙初形花', '混元真质蕊', '两仪混沌莲'];
        const herbNames = Array.from({ length: herbCountNum }, () => immortalHerbs[Math.floor(Math.randomNeutral() * immortalHerbs.length)]);

        Object.entries(herbGrades).forEach(([grade, cnt]) => {
            const gradeNum = Number(grade);
            for (let i = 0; i < cnt; i++) {
                const herbName = herbNames.pop();
                const existingItem = player.neitiandiPending.herbs.find(item => item.name === herbName && item.grade === gradeNum);
                if (existingItem) {
                    existingItem.count = $addBig(existingItem.count, '1');
                } else {
                    player.neitiandiPending.herbs.push({ name: herbName, grade: gradeNum, count: '1' });
                }
            }
        });
    }

    const now = Date.now();
    const lastTime = player.shengLingLastCollectTime || now;
    const elapsedMinutes = Math.max(0, (now - lastTime) / 60000);
    const shengLingIncome = $evalBig(`${count} / 1440 * ${elapsedMinutes}`);
    if ($gtBig(shengLingIncome, '0')) {
        player.shengLing = $min(String(benYuanCount), $addBig(String(player.shengLing), String(shengLingIncome)));
        player.shengLingLastCollectTime = now;
    }
}

// 收获内天地物资
/**
 * 收获内天地物资
 * 显示待收获物资列表，确认后领取
 * 物资包括：灵石、仙石、天材地宝、法则碎片、灵药
 */
function collectNeitiandiRewards() {
    const pending = player.neitiandiPending;
    const hasRewards = $gtBig(pending.spiritStone, '0') || $gtBig(pending.immortalStone, '0') ||
                       $gtBig(pending.treasure, '0') || $gtBig(pending.lawFragments, '0') ||
                       (pending.herbs && pending.herbs.length > 0);

    if (!hasRewards) {
        showModal('<span style="color:#ff0;">【 内天地收获 】</span><br><br><span style="color:var(--text-color-dim,#888);">暂无可收获的物资</span><br><br><button onclick="closeModal()" class="sbtn">确定</button>', true);
        return;
    }

    let items = [];
    if ($gtBig(pending.spiritStone, '0')) items.push(`灵石 x${formatPrecision(pending.spiritStone)}`);
    if ($gtBig(pending.immortalStone, '0')) items.push(`仙石 x${formatPrecision(pending.immortalStone)}`);
    if ($gtBig(pending.treasure, '0')) items.push(`天材地宝 x${formatPrecision(pending.treasure)}`);
    if ($gtBig(pending.lawFragments, '0')) items.push(`法则碎片 x${formatPrecision(pending.lawFragments)}`);
    if (pending.herbs && pending.herbs.length > 0) {
        pending.herbs.forEach(herb => {
            items.push(`${herb.name}${herb.grade}阶 x${formatPrecision(herb.count)}`);
        });
    }

    showModal('<span style="color:#ff0;">【 内天地收获 】</span><br><br>' +
        '<button onclick="confirmNeitiandiCollect()" class="sbtn-gr">确认收获</button><br><br>' +
        '<span style="color:var(--text-color-dim,#888);">确认收获以下物资：</span><br><br>' + items.join('<br>'), true);
}

// 确认领取内天地收益，发放累计资源
/**
 * 确认领取内天地收益
 * 将待收获物资转移到玩家背包/资源中
 * 清空待收获列表，更新收获时间
 */
function confirmNeitiandiCollect() {
    try {
        const pending = player.neitiandiPending;
        if (!pending) {
            console.error('confirmNeitiandiCollect: pending is undefined');
            return;
        }

        let rewards = [];
        if ($gtBig(pending.spiritStone, '0')) {
            player.spiritStone = $addBig(player.spiritStone, pending.spiritStone);
            rewards.push(`灵石 x${formatPrecision(pending.spiritStone)}`);
            pending.spiritStone = '0';
        }
        if ($gtBig(pending.immortalStone, '0')) {
            player.immortalStone = $addBig(player.immortalStone, pending.immortalStone);
            rewards.push(`仙石 x${formatPrecision(pending.immortalStone)}`);
            pending.immortalStone = '0';
        }
        if ($gtBig(pending.treasure, '0')) {
            player.treasure = $addBig(player.treasure, pending.treasure);
            rewards.push(`天材地宝 x${formatPrecision(pending.treasure)}`);
            pending.treasure = '0';
        }
        if ($gtBig(pending.lawFragments, '0')) {
            player.lawFragments = $addBig(player.lawFragments, pending.lawFragments);
            rewards.push(`法则碎片 x${formatPrecision(pending.lawFragments)}`);
            pending.lawFragments = '0';
        }
        if (pending.herbs && pending.herbs.length > 0) {
            pending.herbs.forEach(herb => {
                const existingItem = player.bag.find(item => item.name === herb.name && item.grade === herb.grade);
                if (existingItem) {
                    existingItem.count = $addBig(existingItem.count, herb.count);
                } else {
                    player.bag.push({ name: herb.name, grade: herb.grade, count: herb.count });
                }
                if (herb.grade > player.highestHerbGrade) {
                    player.highestHerbGrade = herb.grade;
                }
                rewards.push(`${herb.name}${herb.grade}阶 x${formatPrecision(herb.count)}`);
            });
            pending.herbs = [];
        }

        pending.lastCollectTime = Date.now();
        saveGameData();

        closeModal();
        
        const pendingContent = document.getElementById('neitiandiPendingContent');
        if (pendingContent) {
            pendingContent.innerHTML = '<span style="color:var(--text-color-dim,#888);">暂无可收获的物资</span>';
        }
    } catch (e) {
        console.error('confirmNeitiandiCollect error:', e);
    }
}

// 静默领取内天地收益（不显示弹窗）
// 将待收获物资转移到玩家背包/资源中
function collectNeitiandiSilent() {
    try {
        const pending = player.neitiandiPending;
        if (!pending) return;

        // 检查是否有可收获的物资
        const hasRewards = $gtBig(pending.spiritStone, '0') || $gtBig(pending.immortalStone, '0') ||
                           $gtBig(pending.treasure, '0') || $gtBig(pending.lawFragments, '0') ||
                           (pending.herbs && pending.herbs.length > 0);

        if (!hasRewards) return;

        // 领取灵石
        if ($gtBig(pending.spiritStone, '0')) {
            player.spiritStone = $addBig(player.spiritStone, pending.spiritStone);
            pending.spiritStone = '0';
        }

        // 领取仙石
        if ($gtBig(pending.immortalStone, '0')) {
            player.immortalStone = $addBig(player.immortalStone, pending.immortalStone);
            pending.immortalStone = '0';
        }

        // 领取天材地宝
        if ($gtBig(pending.treasure, '0')) {
            player.treasure = $addBig(player.treasure, pending.treasure);
            pending.treasure = '0';
        }

        // 领取法则碎片
        if ($gtBig(pending.lawFragments, '0')) {
            player.lawFragments = $addBig(player.lawFragments, pending.lawFragments);
            pending.lawFragments = '0';
        }

        // 领取灵药
        if (pending.herbs && pending.herbs.length > 0) {
            pending.herbs.forEach(herb => {
                const existingItem = player.bag.find(item => item.name === herb.name && item.grade === herb.grade);
                if (existingItem) {
                    existingItem.count = $addBig(existingItem.count, herb.count);
                } else {
                    player.bag.push({ name: herb.name, grade: herb.grade, count: herb.count });
                }
                if (herb.grade > player.highestHerbGrade) {
                    player.highestHerbGrade = herb.grade;
                }
            });
            pending.herbs = [];
        }

        pending.lastCollectTime = Date.now();
        saveGameData();
    } catch (e) {
        console.error('collectNeitiandiSilent error:', e);
    }
}

// 启动内天地收益定时器
let neitiandiIncomeTimer = null;
// 启动内天地收益计时器，定时累计收益
/**
 * 启动内天地收益定时器
 * 每60秒执行一次calculateNeitiandiIncome计算收益
 */
function startNeitiandiIncomeTimer() {
    Scheduler.remove('neitiandiIncome');
    setTimeout(() => {
        Scheduler.add('neitiandiIncome', calculateNeitiandiIncome, 60000);
        neitiandiIncomeTimer = true;
    }, 5000);
}

// ========================================
// 内天地系统
// ========================================

// 显示内天地详情弹窗（圣灵、世界核心、收益信息）
/**
 * 显示内天地详情弹窗
 * 显示内容：世界核心等级、本源数量、本质、属性加成、修炼速度加成
 * 化神后额外显示：生灵信息、收益预览、待收获物资
 * 未获得本源时显示简化提示
 */
function showNeitiandiModal() {
    const benYuanCount = Number($floor(getFirstCharacterBenYuan() || 0));
    
    if (benYuanCount <= 0) {
        showModal('<span style="color:#ff0;">【 内天地 】</span><br><br><span style="color:var(--text-color-dim,#888);">本源达到1后初步开启</span><br><br><button onclick="closeModal()" class="sbtn">确定</button>', true);
        return;
    }
    
    const lgBonus = $addBig('1', $log10($addBig(String(benYuanCount), '1')));

    if (player.realmIndex < 4) {
        const html = `<div style="background:rgba(0,0,0,${getModalOpacity()});border:2px solid #fff;padding:25px;color:var(--text-color,#fff);font-family:monospace;width:90vw;max-width:500px;border-radius:4px;">
<div style="font-size:18px;color:#ff0;margin-bottom:15px;text-align:center;">【 内天地 】</div>
<div class="mod-box-2" style="padding:15px;margin-bottom:10px;text-align:center;">
<div style="cursor:pointer;" onclick="showNeitiandiPreFormula()">世界本源: ${formatLawLevel(benYuanCount)}</div>
<div style="margin-top:10px;cursor:pointer;" onclick="showNeitiandiPreFormula()">修炼速度加成: x${formatNumber(lgBonus)}</div>
</div>
<div style="color:#f66;text-align:center;font-size:12px;">※ 化神后内天地完全形成</div>
<div style="margin-top:20px;text-align:center;"><button onclick="closeModal()" class="sbtn-lg">关闭</button></div></div>`;
        const modal = document.createElement('div');
        modal.className = 'customModal';
        modalZIndexCounter += 2;
        modal.style.cssText = 'position:fixed;top:0;left:0;width:100%;height:100%;background:rgba(0,0,0,' + getModalOpacity() + ');display:flex;justify-content:center;align-items:center;z-index:' + modalZIndexCounter + ';backdrop-filter:blur(4px);-webkit-backdrop-filter:blur(4px);';
        modal.onclick = function(e) { if (e.target === modal) closeModal(); };
        modal.innerHTML = html;
        document.body.appendChild(modal);
        return;
    }
    
    const level = player.maxVoidVictoryLevel + 500;
    const count = benYuanCount;
    const lgVal = $log10(String(level - 1));
    const base = $evalBig(`6 * (1.147 + ${lgVal} / 375) ^ ${level - 1}`);
    const totalBase = $evalBig(String(base) + '*' + String(count));
    const logVal = $floor($log10(totalBase));
    const powerValStr = $pow('1.05', String(logVal));
    const power = formatLawLevel(powerValStr);
    
    const speed = 100;
    const attackInterval = 500;
    
    let benYuanHtml = '';
    let bonusHtml = '';
    let speedBonusHtml = '';
    const benZhi = String(player.benZhi || '0');
    const benZhiAdjusted = $evalBig(`${benZhi} ^ 0.8`);
    const lgBenZhi = $log10($addBig(benZhiAdjusted, '1'));
    const benZhiBonus = $evalBig(`(1 + ${lgBenZhi} / (375 * 1.147)) ^ ${player.maxVoidVictoryLevel}`);
    if ($lteBig(String(count), '0')) {
        benYuanHtml = '<span style="cursor:pointer;" onclick="showNeitiandiWorldCoreModal()">暂无本源</span><br><span style="cursor:pointer;" onclick="showNeitiandiBenZhiModal()">本质: ' + formatLawLevel(benZhi) + '</span>';
        bonusHtml = '生命加成: x' + formatNumber(benZhiBonus) + '<br>攻击加成: x' + formatNumber(benZhiBonus) + '<br>防御加成: x' + formatNumber(benZhiBonus);
        speedBonusHtml = '修炼速度: x1';
    } else {
        benYuanHtml = '<span style="cursor:pointer;" onclick="showNeitiandiBenYuanModal()">本源: ' + formatLawLevel(count) + '</span><br><span style="cursor:pointer;" onclick="showNeitiandiBenZhiModal()">本质: ' + formatLawLevel(benZhi) + '</span>';
        const totalPower = $evalBig(`${power} * ${benZhiBonus}`);
        bonusHtml = '生命加成: x' + formatNumber(totalPower) + '<br>攻击加成: x' + formatNumber(totalPower) + '<br>防御加成: x' + formatNumber(totalPower);

        // 修炼速度加成计算
        // 任何时候：1 + lg(本源 + 1)
        // 化神后：额外加上生灵加成
        const shengLingCount = Number($floor(player.shengLing || 0));
        let speedBonus = lgBonus;
        if (player.realmIndex >= 4 && shengLingCount > 0) {
            const boundHerb = getFirstCharacterBoundHerb();
            const boundHerbGrade = boundHerb?.grade || 0;
            const exponent = calcNeitiandiLevel(boundHerbGrade);
            const logBase = $log10('500');
            const logArg = $evalBig(`500 + ${shengLingCount}`);
            const logValue = $evalBig(`${$log10(logArg)} / ${logBase}`);
            const logPower = $evalBig(`${logValue} ^ 11`);
            const denominator = $addBig(logPower, '1');
            const fraction = $evalBig(`1 / ${denominator}`);
            const oneMinus = $subBig('1', fraction);
            const multiplied = $evalBig(`0.0135039 * ${oneMinus}`);
            const baseBonus = $addBig('1', multiplied);
            const complexBonus = $pow(baseBonus, String(exponent));
            speedBonus = $addBig(lgBonus, complexBonus);
        }
        speedBonusHtml = '修炼速度: x' + formatNumber(speedBonus);
    }

    let incomeHtml = '';
    if (count > 0) {
        const monsterLevel = player.maxVoidVictoryLevel + 500;
        const countStr = String(count);
        const lgVal = $log10($addBig(countStr, '10'));
        const lgCubed = $pow(lgVal, '3');
        const multiplier = $evalBig(`${lgCubed} / 3.3333`);
        const stoneBase = calcStoneBase(monsterLevel);
        const probSpirit = getQiYunProbability(0.01);
        const probImmortal = getQiYunProbability(0.0002);
        const probLaw = getQiYunProbability(0.05);

        const spiritStoneIncome = formatPrecision($floor($evalBig(`${stoneBase} * ${probSpirit} * ${multiplier}`)));
        const immortalStoneIncome = formatPrecision($floor($evalBig(`${stoneBase} * ${probImmortal} * ${multiplier}`)));
        const treasureIncome = formatPrecision($floor($evalBig(`${$pow(1.0339, monsterLevel)} * 10 * ${multiplier}`)));
        const lawFragmentsIncome = formatPrecision($floor($evalBig(`${$pow(1.0339, monsterLevel)} * 5 * ${probLaw} * ${multiplier}`)));
        const shengLingIncome = formatPrecision($evalBig(`${count} / 1440`));

        incomeHtml = '<div class="mod-box-2" style="padding:10px;"><div style="color:#ff0;margin-bottom:5px;cursor:pointer;" onclick="showNeitiandiIncomeFormula();">收益预览 (每60秒)</div>' +
            `灵石: ${spiritStoneIncome}<br>` +
            `仙石: ${immortalStoneIncome}<br>` +
            `天材地宝: ${treasureIncome}<br>` +
            `法则碎片: ${lawFragmentsIncome}<br>` +
            `生灵: ${shengLingIncome}/分</div>`;
    }

    const shengLingLevel = player.maxVoidVictoryLevel + 500;
    const lgMonsterVal = $log10(String(shengLingLevel - 1));
    const shengLingHp = formatPrecision($floor($evalBig(`100 * (1.147 + ${lgMonsterVal} / 375) ^ ${shengLingLevel - 1}`)));
    const shengLingAtk = formatPrecision($floor($evalBig(`6 * (1.147 + ${lgMonsterVal} / 375) ^ ${shengLingLevel - 1}`)));
    const shengLingDef = formatPrecision($floor($evalBig(`3 * (1.147 + ${lgMonsterVal} / 375) ^ ${shengLingLevel - 1}`)));
    const shengLingSpeed = '100';
    const shengLingCount = formatPrecision($floor(player.shengLing || '0'));
    const groupName = player.shengLingGroupName || '灵族';
    
    const talentHtml = '<div style="margin-top:8px;border-top:1px solid #444;padding-top:5px;"><div style="color:#ff0;font-size:11px;">天赋:</div><div style="color:#ff0;font-size:10px;">◆ 传承</div><div style="color:#888;font-size:9px;margin-left:8px;">牺牲时20%概率传承技能给队友</div></div>';
    
    const skillsList = [
        {name: '玄元护体诀', desc: '入场我方全体血量×2'},
        {name: '灵泉润枯法', desc: '每回合恢复血量最低队友'},
        {name: '清冥守心盾', desc: '每回合给队友加护盾，受击减半伤害'},
        {name: '碎虚绝魂击', desc: '目标血量低时秒杀'},
        {name: '蚀血噬魂打', desc: '造成目标当前血量伤害'},
        {name: '千影连星刺', desc: '连续多次攻击'},
        {name: '戮绝残血式', desc: '额外攻击血量最低敌人'},
        {name: '血元反哺术', desc: '攻击后恢复自身血量'},
        {name: '万域镇魔波', desc: '攻击时波及全场敌人'},
        {name: '锁妖追命印', desc: '标记敌方最强单位集火'},
        {name: '寒骨封脉击', desc: '降低目标攻击速度'},
        {name: '御灵反滞诀', desc: '受击降低攻击者速度'},
        {name: '幽墟幻折身', desc: '受击反弹伤害给敌方全体'},
        {name: '焚魂同寂咒', desc: '自身损失部分生命，目标即死或损失50%生命'},
        {name: '疾风御体诀', desc: '入场提升全体攻击速度'},
        {name: '骁勇锻体术', desc: '每回合永久提升随机友方攻击'},
        {name: '玄罡护生界', desc: '在场时限制我方受到的伤害上限'}
    ];
    const skillsHtml = skillsList.map(s => `<div style="color:#0ff;font-size:9px;">◆ ${s.name}</div><div style="color:var(--text-color-dim,#888);font-size:8px;margin-left:6px;">${s.desc}</div>`).join('');
    
    const shengLingHtml = '<div class="mod-box-2" style="padding:10px;"><div style="color:#ff0;margin-bottom:5px;cursor:pointer;" onclick="showShengLingTalentSkillsModal()">生灵·<span onclick="event.stopPropagation();showShengLingNameEditor()">' + groupName + '</span></div>数量: ' + shengLingCount + '<br>Lv.' + shengLingLevel + '<br>生命: ' + shengLingHp + '<br>攻击: ' + shengLingAtk + '<br>防御: ' + shengLingDef + '<br>速度: ' + shengLingSpeed + '<div style="color:var(--text-color-dim,#888);font-size:10px;margin-top:5px;cursor:pointer;" onclick="showShengLingTalentSkillsModal()">点击查看天赋与技能详情 ▼</div></div>';

    const pending = player.neitiandiPending;
    let pendingHtml = '';
    const hasPending = $gtBig(pending.spiritStone, '0') || $gtBig(pending.immortalStone, '0') || 
                       $gtBig(pending.treasure, '0') || $gtBig(pending.lawFragments, '0') ||
                       (pending.herbs && pending.herbs.length > 0);
    if (hasPending) {
        let items = [];
        if ($gtBig(pending.spiritStone, '0')) items.push(`灵石 x${formatPrecision(pending.spiritStone)}`);
        if ($gtBig(pending.immortalStone, '0')) items.push(`仙石 x${formatPrecision(pending.immortalStone)}`);
        if ($gtBig(pending.treasure, '0')) items.push(`天材地宝 x${formatPrecision(pending.treasure)}`);
        if ($gtBig(pending.lawFragments, '0')) items.push(`法则碎片 x${formatPrecision(pending.lawFragments)}`);
        if (pending.herbs && pending.herbs.length > 0) {
            pending.herbs.forEach(herb => {
                items.push(`${herb.name}${herb.grade}阶 x${formatPrecision(herb.count)}`);
            });
        }
        pendingHtml = '<div class="mod-box-2" style="padding:10px;"><div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:5px;"><span style="color:#ff0;cursor:pointer;" onclick="toggleNeitiandiPending()">待收获物资 <span id="neitiandiArrow" style="color:var(--text-color,#fff);">▲</span></span><button onclick="collectNeitiandiRewards();" class="sbtn-gr">收获</button></div><div id="neitiandiPendingContent" style="display:block;">' + items.join('<br>') + '</div></div>';
    }

    const bonusHtml2 = '<div class="mod-box-2" style="padding:10px;"><div style="color:#ff0;margin-bottom:5px;cursor:pointer;" onclick="showNeitiandiFormula();">增益效果</div>' + bonusHtml + '<div style="color:var(--text-color,#fff);margin-top:5px;">' + speedBonusHtml + '</div></div>';

    const heDaoUnits = player.heDaoUnits || [];
    const heDaoSubstitutes = player.heDaoSubstitutes || [];
    let heDaoLeftHtml = '<div style="flex:1;"><div style="color:#ff0;margin-bottom:5px;font-size:12px;cursor:pointer;" onclick="showHeDaoBonusInfo()">合道</div>';
    for (let i = 0; i < 5; i++) {
        const unit = heDaoUnits[i];
        if (unit) {
            heDaoLeftHtml += `<div id="heDaoUnitName_${i}_false" style="color:#0ff;cursor:pointer;font-size:11px;margin:2px 0;" onclick="showHeDaoUnitDetail(${i})">◆ ${unit.name}</div>`;
        } else {
            heDaoLeftHtml += `<div style="color:var(--text-color-dim,#888);font-size:11px;margin:2px 0;">○ 空位</div>`;
        }
    }
    heDaoLeftHtml += '</div>';
    
    let heDaoRightHtml = '<div style="flex:1;border-left:1px solid #444;padding-left:8px;"><div style="color:#888;margin-bottom:5px;font-size:12px;">替补</div>';
    for (let i = 0; i < 5; i++) {
        const unit = heDaoSubstitutes[i];
        if (unit) {
            heDaoRightHtml += `<div id="heDaoUnitName_${i}_true" style="color:#0ff;cursor:pointer;font-size:11px;margin:2px 0;" onclick="showHeDaoSubstituteDetail(${i})">◆ ${unit.name}</div>`;
        } else {
            heDaoRightHtml += `<div style="color:var(--text-color-dim,#555);font-size:11px;margin:2px 0;">○ 空位</div>`;
        }
    }
    heDaoRightHtml += '</div>';
    
    let heDaoHtml = '<div class="mod-box-2" style="padding:10px;flex:1;"><div style="display:flex;gap:8px;">' + heDaoLeftHtml + heDaoRightHtml + '</div></div>';

    let gridItems = bonusHtml2 + shengLingHtml;
    if (incomeHtml) gridItems += incomeHtml;
    if (pendingHtml) gridItems += pendingHtml;

    const html = '<div style="background:rgba(0,0,0,' + getModalOpacity() + ');border:2px solid #fff;padding:20px;color:var(--text-color,#fff);font-family:monospace;width:95vw;max-width:600px;max-height:80vh;overflow-y:auto;display:flex;flex-direction:column;border-radius:4px;"><div id="neitiandiWorldName" style="font-size:18px;color:#ff0;margin-bottom:15px;text-align:center;cursor:pointer;" onclick="showWorldNameInput()">' + player.worldName + '</div><div style="display:flex;gap:10px;margin-bottom:10px;flex-shrink:0;"><div class="mod-box-2" style="padding:10px;flex:1;"><span style="cursor:pointer;" onclick="showNeitiandiWorldCoreModal()">世界核心: ' + formatLawLevel(player.maxVoidVictoryLevel) + '级</span><br>' + benYuanHtml + '</div>' + heDaoHtml + '</div><div style="display:grid;grid-template-columns:1fr 1fr;gap:10px;min-width:0;">' + gridItems + '</div><div style="margin-top:15px;text-align:center;"><button onclick="closeModal()" class="sbtn-lg">关闭</button></div></div>';

    const modal = document.createElement('div');
    modal.className = 'customModal';
    modalZIndexCounter += 2;
    modal.style.cssText = 'position:fixed;top:0;left:0;width:100%;height:100%;background:rgba(0,0,0,' + getModalOpacity() + ');display:flex;justify-content:center;align-items:center;z-index:' + modalZIndexCounter + ';backdrop-filter:blur(4px);-webkit-backdrop-filter:blur(4px);';
    modal.onclick = function(e) { if (e.target === modal) closeModal(); };
    modal.innerHTML = html;
    document.body.appendChild(modal);
}

// 切换内天地收益待领取状态
/**
 * 切换内天地待收获物资的显示/隐藏状态
 */
function toggleNeitiandiPending() {
    const content = document.getElementById('neitiandiPendingContent');
    const arrow = document.getElementById('neitiandiArrow');
    if (content.style.display === 'none') {
        content.style.display = 'block';
        arrow.textContent = '▲';
    } else {
        content.style.display = 'none';
        arrow.textContent = '▼';
    }
}

function showNeitiandiWorldCoreModal() {
    const maxDepth = player.maxVoidVictoryLevel || 0;
    const html = `<div style="background:rgba(0,0,0,${getModalOpacity()});padding:20px;color:var(--text-color,#fff);font-family:monospace;border-radius:4px;min-width:200px;max-width:300px;text-align:center;">
        <div style="color:#ff0;margin-bottom:10px;font-size:16px;">【 世界核心 】</div>
        <div style="color:var(--text-color,#fff);font-size:13px;">相当于无尽虚空最大战胜深度</div>
        <div style="margin-top:15px;"><button onclick="closeModal()" class="sbtn">关闭</button></div>
    </div>`;
    showModal(html, true);
}

function showNeitiandiBenYuanModal() {
    const herbs = player.herbs || [];
    const usableHerbs = herbs.filter(h => h.count > 0);
    
    let herbsHtml = '';
    usableHerbs.forEach((herb, idx) => {
        herbsHtml += `<div style="display:flex;justify-content:space-between;align-items:center;padding:6px;border:1px solid #444;margin:4px 0;border-radius:4px;">
            <div><span style="color:#0ff;">${herb.name}</span> <span style="color:#ff0;">${herb.grade}阶</span> x${formatNumber(herb.count)}</div>
            <button onclick="useHerbForBenYuan(${idx})" class="sbtn-gr" style="padding:2px 6px;font-size:10px;">使用</button>
        </div>`;
    });
    
    const html = `<div style="background:rgba(0,0,0,${getModalOpacity()});padding:15px;color:var(--text-color,#fff);font-family:monospace;border-radius:4px;min-width:250px;max-width:350px;">
        <div style="color:#ff0;margin-bottom:8px;font-size:14px;text-align:center;">【 本源 】</div>
        <div style="color:var(--text-color,#fff);font-size:12px;margin-bottom:8px;text-align:center;">服用灵药增加</div>
        <div style="max-height:150px;overflow-y:auto;">${herbsHtml}</div>
        <div style="margin-top:10px;text-align:center;"><button onclick="closeModal()" class="sbtn">关闭</button></div>
    </div>`;
    showModal(html, true);
}

function useHerbForBenYuan(herbIdx) {
    const herbs = player.herbs || [];
    const herb = herbs[herbIdx];
    if (!herb || herb.count <= 0) {
        showModal('<span style="color:#f66;">灵药不足</span><br><br><button onclick="closeModal()" class="sbtn">确定</button>', true);
        return;
    }
    
    const grade = herb.grade || 1;
    const benYuanGain = $pow('10', String(grade));
    
    herb.count--;
    if (herb.count <= 0) {
        herbs.splice(herbIdx, 1);
    }
    
    const currentBenYuan = getFirstCharacterBenYuan() || '0';
    const newBenYuan = $addBig(String(currentBenYuan), benYuanGain);
    setFirstCharacterBenYuan(newBenYuan);
    
    saveGameData();
    
    showModal(`<div style="text-align:center;">
        <div style="color:#0ff;">使用 ${herb.name}${grade}阶</div>
        <div style="color:#ff0;margin:10px 0;">获得本源 +${formatLawLevel(benYuanGain)}</div>
    </div><br><button onclick="closeModal();showNeitiandiBenYuanModal();" class="sbtn">确定</button>`, true);
}

function showNeitiandiBenZhiModal() {
    const clones = player.cloneCharacters || [];
    const absorbableClones = clones.filter(c => c && c.id);
    
    let clonesHtml = '';
    absorbableClones.forEach(clone => {
        clonesHtml += `<div style="display:flex;justify-content:space-between;align-items:center;padding:6px;border:1px solid #444;margin:4px 0;border-radius:4px;">
            <div><span style="color:#0ff;">${clone.name || '化身'}</span></div>
            <button onclick="absorbCloneForBenZhi('${clone.id}')" class="sbtn-rd" style="padding:2px 6px;font-size:10px;">吸收</button>
        </div>`;
    });
    
    const html = `<div style="background:rgba(0,0,0,${getModalOpacity()});padding:15px;color:var(--text-color,#fff);font-family:monospace;border-radius:4px;min-width:250px;max-width:350px;">
        <div style="color:#ff0;margin-bottom:8px;font-size:14px;text-align:center;">【 本质 】</div>
        <div style="color:var(--text-color,#fff);font-size:12px;margin-bottom:8px;text-align:center;">吸收化身增加</div>
        <div style="max-height:150px;overflow-y:auto;">${clonesHtml}</div>
        <div style="margin-top:10px;text-align:center;"><button onclick="closeModal()" class="sbtn">关闭</button></div>
    </div>`;
    showModal(html, true);
}

function absorbCloneForBenZhi(cloneId) {
    const clones = player.cloneCharacters || [];
    const cloneIdx = clones.findIndex(c => c && c.id === cloneId);
    if (cloneIdx === -1) {
        showModal('<span style="color:#f66;">化身不存在</span><br><br><button onclick="closeModal()" class="sbtn">确定</button>', true);
        return;
    }
    
    const clone = clones[cloneIdx];
    const cloneName = clone.name || '化身';
    
    clones.splice(cloneIdx, 1);
    
    const currentBenZhi = String(player.benZhi || '0');
    const newBenZhi = $addBig(currentBenZhi, '1');
    player.benZhi = newBenZhi;
    
    saveGameData();
    
    showModal(`<div style="text-align:center;">
        <div style="color:#0ff;">吸收化身 ${cloneName}</div>
        <div style="color:#ff0;margin:10px 0;">本质 +1</div>
    </div><br><button onclick="closeModal();showNeitiandiBenZhiModal();" class="sbtn">确定</button>`, true);
}

function showHeDaoBonusInfo() {
    const benYuanCount = getFirstCharacterBenYuan() || '0';
    let multiplier = '1';
    
    if ($gtBig(String(benYuanCount), '0')) {
        const lgBenYuan = $log10(String(benYuanCount));
        multiplier = $pow('2', lgBenYuan);
    }
    
    const html = `<div style="background:rgba(0,0,0,${getModalOpacity()});border:2px solid #fff;padding:20px;color:var(--text-color,#fff);font-family:monospace;border-radius:4px;min-width:200px;max-width:300px;">
        <div style="color:#ff0;margin-bottom:10px;">加成倍率: 2^lg10(本源)</div>
        <div style="color:#0f0;font-size:16px;">= ${formatNumber(multiplier)}倍</div>
        <div style="margin-top:10px;color:var(--text-color-dim,#888);font-size:11px;">合道单位生命、攻击受此倍率加成</div>
        <div style="margin-top:15px;text-align:center;">
            <button onclick="closeModal()" class="sbtn">关闭</button>
        </div>
    </div>`;
    showModal(html, true);
}

function showHeDaoUnitDetail(index) {
    const heDaoUnits = player.heDaoUnits || [];
    const unit = heDaoUnits[index];
    if (!unit) {
        showModal('<span style="color:#ff0;">【 合道单位 】</span><br><br><span style="color:var(--text-color-dim,#888);">该位置暂无合道单位</span><br><br><button onclick="closeModal()" class="sbtn">确定</button>', true);
        return;
    }
    
    const monsterLevel = player.maxVoidVictoryLevel + 500;
    const lgVal = $log10(String(monsterLevel - 1));
    let hp = $floor($evalBig(`100 * (1.147 + ${lgVal} / 375) ^ ${monsterLevel - 1}`));
    let atk = $floor($evalBig(`6 * (1.147 + ${lgVal} / 375) ^ ${monsterLevel - 1}`));
    const def = 0;
    const speed = 100;
    
    const benYuanCount = getFirstCharacterBenYuan() || '0';
    if ($gtBig(String(benYuanCount), '0')) {
        const lgBenYuan = $log10(String(benYuanCount));
        const benYuanMultiplier = $pow('2', lgBenYuan);
        hp = $floor($mulBig(String(hp), benYuanMultiplier));
        atk = $floor($mulBig(String(atk), benYuanMultiplier));
    }
    
    let skillsHtml = '';
    if (unit.skills && unit.skills.length > 0) {
        skillsHtml = '<div style="margin-top:10px;border-top:1px solid #444;padding-top:10px;text-align:left;"><div style="color:#ff0;margin-bottom:5px;">技能:</div>';
        unit.skills.forEach(skill => {
            const skillKey = Object.keys(worldExpSkills).find(k => worldExpSkills[k].name === skill.name);
            const originalSkill = skillKey ? worldExpSkills[skillKey] : null;
            const desc = originalSkill?.desc || '';
            const effect = originalSkill?.effect || '';
            
            skillsHtml += `<div style="color:#0ff;font-size:12px;margin-bottom:3px;">◆ ${skill.name}</div>`;
            if (desc) {
                skillsHtml += `<div style="color:var(--text-color-dim,#888);font-size:11px;margin-left:10px;">${desc}</div>`;
            }
            if (effect) {
                skillsHtml += `<div style="color:#0f0;font-size:11px;margin-left:10px;margin-bottom:5px;">实际效果: ${effect}</div>`;
            }
            if (skill.fixedValues) {
                const fv = skill.fixedValues;
                let valueStr = '';
                if (fv.healPercent !== undefined) valueStr = `数值: ${fv.healPercent}%`;
                else if (fv.damagePercent !== undefined) valueStr = `数值: ${fv.damagePercent}%`;
                else if (fv.thresholdPercent !== undefined) valueStr = `数值: ${fv.thresholdPercent}%`;
                else if (fv.hitCount !== undefined) valueStr = `数值: ${fv.hitCount}次`;
                else if (fv.reducePercent !== undefined) valueStr = `伤害: ${100 - fv.reducePercent}%`;
                else if (fv.speedReduce !== undefined) valueStr = `数值: ${fv.speedReduce}点`;
                else if (fv.reflectPercent !== undefined) valueStr = `数值: ${fv.reflectPercent}%`;
                else if (fv.speedBoost !== undefined) valueStr = `速度: +${fv.speedBoost}`;
                else if (fv.atkBoostPercent !== undefined) valueStr = `攻击: +${fv.atkBoostPercent}%`;
                else if (fv.selfDamagePercent !== undefined) valueStr = `自身损失: ${fv.selfDamagePercent}%生命`;
                else if (fv.damageLimitPercent !== undefined) valueStr = `伤害上限: ${fv.damageLimitPercent}%最大生命`;
                if (valueStr) skillsHtml += `<div style="color:#ff0;font-size:11px;margin-left:10px;">${valueStr}</div>`;
            }
        });
        skillsHtml += '</div>';
    }
    
    const html = `<div style="background:rgba(0,0,0,${getModalOpacity()});border:2px solid #fff;padding:20px;color:var(--text-color,#fff);font-family:monospace;border-radius:4px;min-width:250px;max-width:350px;">
        <div id="heDaoDetailName_${index}_false" style="color:#0ff;font-size:18px;margin-bottom:15px;text-align:center;cursor:pointer;" onclick="showRenameHeDaoUnitModal(${index},false)">${unit.name}</div>
        <div style="line-height:2;text-align:left;">
            <div>生命: ${formatNumber(hp)}</div>
            <div>攻击: ${formatNumber(atk)}</div>
            <div>速度: ${speed}</div>
        </div>
        ${skillsHtml}
        <div style="margin-top:15px;text-align:center;">
            <button onclick="removeHeDaoUnit(${index})" class="sbtn-rd" style="margin-right:10px;">解除合道</button>
            <button onclick="closeModal()" class="sbtn">关闭</button>
        </div>
    </div>`;
    
    showModal(html, true);
}

function removeHeDaoUnit(index) {
    const heDaoUnits = player.heDaoUnits || [];
    const heDaoSubstitutes = player.heDaoSubstitutes || [];
    const unit = heDaoUnits[index];
    if (!unit) return;
    
    if (heDaoSubstitutes.length >= 5) {
        const existingSubModal = document.getElementById('heDaoSubConfirmModal');
        if (existingSubModal) existingSubModal.remove();
        
        const subModal = document.createElement('div');
        subModal.id = 'heDaoSubConfirmModal';
        subModal.style.cssText = 'position:fixed;top:0;left:0;width:100%;height:100%;background:rgba(0,0,0,0.5);display:flex;justify-content:center;align-items:center;z-index:10003;';
        subModal.innerHTML = `<div style="background:rgba(0,0,0,${getModalOpacity()});border:2px solid #fff;padding:20px;color:var(--text-color,#fff);font-family:monospace;border-radius:4px;min-width:250px;max-width:350px;">
            <div style="color:#ff0;font-size:16px;margin-bottom:15px;text-align:center;">替补已满</div>
            <div style="color:var(--text-color,#fff);margin-bottom:15px;text-align:center;">替补位置已满(5/5)，是否删除【${unit.name}】？</div>
            <div style="text-align:center;">
                <button onclick="confirmRemoveHeDaoUnit(${index},true)" class="sbtn-rd" style="margin-right:10px;">确认删除</button>
                <button onclick="document.getElementById('heDaoSubConfirmModal').remove()" class="sbtn">取消</button>
            </div>
        </div>`;
        subModal.onclick = function(e) { if (e.target === subModal) subModal.remove(); };
        document.body.appendChild(subModal);
        return;
    }
    
    heDaoUnits.splice(index, 1);
    heDaoSubstitutes.push(unit);
    player.heDaoUnits = heDaoUnits;
    player.heDaoSubstitutes = heDaoSubstitutes;
    saveGameData();
    closeModal();
    refreshHeDaoListUI();
}

function refreshHeDaoListUI() {
    const heDaoUnits = player.heDaoUnits || [];
    const heDaoSubstitutes = player.heDaoSubstitutes || [];
    
    for (let i = 0; i < 5; i++) {
        const nameEl = document.getElementById(`heDaoUnitName_${i}_false`);
        if (nameEl) {
            const unit = heDaoUnits[i];
            if (unit) {
                nameEl.outerHTML = `<div id="heDaoUnitName_${i}_false" style="color:#0ff;cursor:pointer;font-size:11px;margin:2px 0;" onclick="showHeDaoUnitDetail(${i})">◆ ${unit.name}</div>`;
            } else {
                nameEl.outerHTML = `<div style="color:var(--text-color-dim,#888);font-size:11px;margin:2px 0;">○ 空位</div>`;
            }
        }
        
        const subNameEl = document.getElementById(`heDaoUnitName_${i}_true`);
        if (subNameEl) {
            const unit = heDaoSubstitutes[i];
            if (unit) {
                subNameEl.outerHTML = `<div id="heDaoUnitName_${i}_true" style="color:#0ff;cursor:pointer;font-size:11px;margin:2px 0;" onclick="showHeDaoSubstituteDetail(${i})">◆ ${unit.name}</div>`;
            } else {
                subNameEl.outerHTML = `<div style="color:var(--text-color-dim,#555);font-size:11px;margin:2px 0;">○ 空位</div>`;
            }
        }
    }
}

function confirmRemoveHeDaoUnit(index, deleteUnit) {
    const heDaoUnits = player.heDaoUnits || [];
    if (deleteUnit && heDaoUnits[index]) {
        heDaoUnits.splice(index, 1);
        player.heDaoUnits = heDaoUnits;
        saveGameData();
    }
    closeModal();
    refreshHeDaoListUI();
}

function showRenameHeDaoUnitModal(index, isSubstitute) {
    const units = isSubstitute ? (player.heDaoSubstitutes || []) : (player.heDaoUnits || []);
    const unit = units[index];
    if (!unit) return;
    
    const existingSubModal = document.getElementById('heDaoRenameModal');
    if (existingSubModal) existingSubModal.remove();
    
    modalZIndexCounter += 2;
    const subModal = document.createElement('div');
    subModal.id = 'heDaoRenameModal';
    subModal.style.cssText = 'position:fixed;top:0;left:0;width:100%;height:100%;background:rgba(0,0,0,0.5);display:flex;justify-content:center;align-items:center;z-index:' + modalZIndexCounter + ';';
    subModal.innerHTML = `<div style="background:rgba(0,0,0,${getModalOpacity()});border:2px solid #fff;padding:20px;color:var(--text-color,#fff);font-family:monospace;border-radius:4px;min-width:250px;max-width:350px;">
        <div style="font-size:16px;color:#ff0;margin-bottom:15px;text-align:center;">修改名称</div>
        <input id="renameHeDaoInput" type="text" value="${unit.name}" maxlength="8" style="width:100%;padding:8px;margin-bottom:15px;background:#222;color:var(--text-color,#fff);border:1px solid #444;font-family:monospace;border-radius:5px;" />
        <div style="text-align:center;">
            <button onclick="confirmRenameHeDaoUnit(${index},${isSubstitute})" class="sbtn-gr" style="margin-right:10px;">确定</button>
            <button onclick="closeHeDaoRenameModal()" class="sbtn">取消</button>
        </div>
    </div>`;
    subModal.onclick = function(e) { if (e.target === subModal) closeHeDaoRenameModal(); };
    document.body.appendChild(subModal);
}

function closeHeDaoRenameModal() {
    const modal = document.getElementById('heDaoRenameModal');
    if (modal) modal.remove();
    modalZIndexCounter -= 2;
}

function confirmRenameHeDaoUnit(index, isSubstitute) {
    const input = document.getElementById('renameHeDaoInput');
    if (!input) return;
    const newName = input.value.trim();
    if (!newName) {
        const existingError = document.getElementById('heDaoRenameError');
        if (existingError) existingError.remove();
        modalZIndexCounter += 2;
        const errorModal = document.createElement('div');
        errorModal.id = 'heDaoRenameError';
        errorModal.style.cssText = 'position:fixed;top:0;left:0;width:100%;height:100%;background:rgba(0,0,0,0.5);display:flex;justify-content:center;align-items:center;z-index:' + modalZIndexCounter + ';';
        errorModal.innerHTML = `<div style="background:rgba(0,0,0,${getModalOpacity()});border:2px solid #fff;padding:20px;color:var(--text-color,#fff);font-family:monospace;border-radius:4px;min-width:200px;">
            <div style="color:#f66;text-align:center;">名称不能为空</div>
            <div style="text-align:center;margin-top:15px;"><button onclick="document.getElementById('heDaoRenameError').remove();modalZIndexCounter-=2;" class="sbtn">确定</button></div>
        </div>`;
        errorModal.onclick = function(e) { if (e.target === errorModal) { errorModal.remove(); modalZIndexCounter -= 2; } };
        document.body.appendChild(errorModal);
        return;
    }
    
    if (isSubstitute) {
        const heDaoSubstitutes = player.heDaoSubstitutes || [];
        if (heDaoSubstitutes[index]) {
            heDaoSubstitutes[index].name = newName;
            player.heDaoSubstitutes = heDaoSubstitutes;
            saveGameData();
        }
    } else {
        const heDaoUnits = player.heDaoUnits || [];
        if (heDaoUnits[index]) {
            heDaoUnits[index].name = newName;
            player.heDaoUnits = heDaoUnits;
            saveGameData();
        }
    }
    
    const renameModal = document.getElementById('heDaoRenameModal');
    if (renameModal) closeHeDaoRenameModal();
    
    const nameEl = document.getElementById(`heDaoUnitName_${index}_${isSubstitute}`);
    if (nameEl) {
        nameEl.textContent = '◆ ' + newName;
    }
    
    const detailNameEl = document.getElementById(`heDaoDetailName_${index}_${isSubstitute}`);
    if (detailNameEl) {
        detailNameEl.textContent = newName;
    }
}

