// 显示内天地收益公式说明弹窗
/**
 * 显示内天地增益公式说明弹窗
 * 详细展示：本源属性加成公式、本质额外加成公式、修炼速度加成公式
 * 包含当前各项数值的具体计算结果
 */
function showNeitiandiFormula() {
    const level = player.maxVoidVictoryLevel + 500;
    const shengLingCount = Number($floor(player.shengLing || 0));
    const benYuanCount = Number($floor(getFirstCharacterBenYuan() || 0));
    const benZhi = String(player.benZhi || '0');
    const benZhiAdjusted = $evalBig(`${benZhi} ^ 0.8`);
    const lgBenZhi = $log10($addBig(benZhiAdjusted, '1'));
    const benZhiBonus = $evalBig(`(1 + ${lgBenZhi} / (375 * 1.147)) ^ ${player.maxVoidVictoryLevel}`);
    const lgVal = $log10(String(level - 1));
    const base = $evalBig(`6 * (1.147 + ${lgVal} / 375) ^ ${level - 1}`);
    const totalBase = $evalBig(String(base) + '*' + String(shengLingCount));
    const logVal = $floor($log10(totalBase));
    const log10Val = String(Math.log10(1.05));
    const log10Power = $evalBig(`${String(logVal)} * ${log10Val}`);
    const power = $pow('10', String(log10Power));
    const displayPower = formatNumber(power);

    const lgBonus = $addBig('1', $log10($addBig(String(benYuanCount), '1')));
    let speedBonusDisplay = formatNumber(lgBonus);
    if (player.realmIndex >= 4 && shengLingCount > 0) {
        const boundHerb = getFirstCharacterBoundHerb();
        const boundHerbGrade = boundHerb?.grade || 0;
        const exponent = calcNeitiandiLevel(boundHerbGrade);
        const logBase = $log10('500');
        const logArg = $evalBig(`500 + ${shengLingCount}`);
        const logValue = $evalBig(`${$log10(logArg)} / ${logBase}`);
        const logPower = $evalBig(`${logValue} ^ 11`);
        const denominator = $addBig(logPower, '1');
        const fraction = $evalBig(`1 / ${denominator}`);
        const oneMinus = $subBig('1', fraction);
        const multiplied = $evalBig(`0.0135039 * ${oneMinus}`);
        const baseBonus = $addBig('1', multiplied);
        const complexBonus = $pow(baseBonus, String(exponent));
        const totalBonus = $addBig(lgBonus, complexBonus);
        speedBonusDisplay = `${formatNumber(lgBonus)} + ${formatNumber(complexBonus)} = ${formatNumber(totalBonus)}`;
    }

    const formula = `<div style="background:rgba(0,0,0,${getModalOpacity()});border:2px solid #fff;padding:20px;color:var(--text-color,#fff);font-family:monospace;width:90vw;max-width:600px;max-height:80vh;overflow-y:auto;border-radius:4px;">
<div style="font-size:16px;color:#ff0;margin-bottom:12px;text-align:center;">【 内天地增益公式 】</div>
<div style="line-height:1.8;color:var(--text-color,#fff);font-size:12px;">
<div style="color:#0ff;">【本源属性加成】</div>
<div>属性加成 = 1.05^floor(log10(基础值 × 生灵数量))</div>
<div>基础值 = 6 × (1.147 + LG(10,本源等级-1) ÷ 375)^(本源等级-1)</div>
<div>本源等级 = 世界核心等级 + 500 = ${player.maxVoidVictoryLevel} + 500 = ${level}</div>
<div style="color:#ff0;">当前属性加成: x${displayPower}</div>
<br>
<div style="color:#0ff;">【本质额外加成】</div>
<div>本质加成 = (1 + lg(本质等级^0.8+1) ÷ 430.125)^世界核心等级</div>
<div>本质等级 = ${formatLawLevel(benZhi)}，世界核心等级 = ${formatLawLevel(player.maxVoidVictoryLevel)}</div>
<div style="color:#ff0;">当前本质加成: x${formatNumber(benZhiBonus)}</div>
<br>
<div style="color:#0ff;">【修炼速度加成】</div>
<div>基础加成 = 1 + lg(本源 + 1)</div>
<div style="color:#f66;">化神后额外加成 = 基础加成系数^((本命灵根等阶 - 10) × 66.932)</div>
<div style="color:#ff0;">当前修炼速度: x${speedBonusDisplay}</div>
</div>
<div style="margin-top:15px;text-align:center;"><button onclick="closeModal();showNeitiandiModal();" class="sbtn-lg">返回</button></div></div>`;

    const modal = document.createElement('div');
    modal.className = 'customModal';
    modalZIndexCounter += 2;
    modal.style.cssText = 'position:fixed;top:0;left:0;width:100%;height:100%;background:rgba(0,0,0,' + getModalOpacity() + ');display:flex;justify-content:center;align-items:center;z-index:' + modalZIndexCounter + ';backdrop-filter:blur(4px);-webkit-backdrop-filter:blur(4px);';
    modal.onclick = function(e) { if (e.target === modal) { closeModal(); showNeitiandiModal(); } };
    modal.innerHTML = formula;
    document.body.appendChild(modal);
}

// 显示内天地修炼速度公式说明弹窗（化神前简化版）
/**
 * 显示内天地修炼速度公式说明弹窗（化神前简化版）
 * 仅展示基础修炼速度加成：1 + lg(本源 + 1)
 */
