// 显示内天地修炼速度公式说明弹窗
function showNeitiandiSpeedFormula() {
    const benYuanCount = Number($floor(getFirstCharacterBenYuan() || 0));
    const shengLingCount = Number($floor(player.shengLing || 0));
    const boundHerb = getFirstCharacterBoundHerb();
    const boundHerbGrade = boundHerb?.grade || 0;
    const exponent = calcNeitiandiLevel(boundHerbGrade);

    const lgBonus = $addBig('1', $log10($addBig(String(benYuanCount), '1')));
    let formulaHtml = '';

    if (benYuanCount <= 0 && shengLingCount <= 0) {
        formulaHtml = `<div style="color:var(--text-color-dim,#888);">暂无本源/生灵，修炼速度加成为 x1</div>`;
    } else {
        let totalBonus;
        let lgPart = '';
        let complexPart = '';

        if (benYuanCount > 0) {
            lgPart = `<div style="color:#0ff;">基础加成 = 1 + lg(${benYuanCount}+1) = ${formatNumber(lgBonus)}</div>`;
        }

        if (player.realmIndex >= 4 && shengLingCount > 0) {
            const logArg = $evalBig(`500 + ${shengLingCount}`);
            const logValue = $evalBig(`${$log10(logArg)} / ${$log10('500')}`);
            const baseBonus = $addBig('1', $evalBig(`0.0135039 * (1 - 1 / (${logValue} ^ 11 + 1))`));
            const complexBonus = $pow(baseBonus, String(exponent));
            complexPart = `<div style="color:#0ff;">生灵加成(基于生灵数量 ${shengLingCount})：</div>
<div style="color:#0ff;">设 x = log_500(500 + ${shengLingCount}) = ${formatNumber(logValue)}</div>
<div style="color:#0ff;">基础系数 = 1 + 0.0135039 × (1 - 1/(x^11 + 1)) = ${formatNumber(baseBonus)}</div>
<div style="color:#0ff;">生灵加成 = ${formatNumber(baseBonus)}^((本命灵根等阶 - 10) × 66.932) = ${formatNumber(complexBonus)}</div>
<div style="color:#888;">本命灵根等阶: ${boundHerbGrade}，内天地等级: ${exponent.toFixed(2)}</div>`;
            totalBonus = $addBig(lgBonus, complexBonus);
        } else {
            totalBonus = lgBonus;
            if (shengLingCount > 0) {
                complexPart = `<div style="color:#f66;">（化神后额外获得生灵加成，生灵数量: ${shengLingCount}）</div>`;
            }
        }

        formulaHtml = `<div style="line-height:2;color:var(--text-color,#fff);">
<div>本源数量: ${formatLawLevel(benYuanCount)}</div>
<div>生灵数量: ${formatLawLevel(shengLingCount)}</div>
<div>本命灵根等阶: ${boundHerbGrade}</div>
<br>
${lgPart}
${complexPart}
<br>
<div style="color:#ff0;font-size:16px;">修炼速度加成 = ${formatNumber(totalBonus)}</div>
</div>`;
    }

    const formula = `<div style="background:rgba(0,0,0,${getModalOpacity()});border:2px solid #fff;padding:25px;color:var(--text-color,#fff);font-family:monospace;width:90vw;max-width:500px;border-radius:4px;">
<div style="font-size:18px;color:#ff0;margin-bottom:15px;text-align:center;">【 内天地修炼速度加成 】</div>
${formulaHtml}
<div style="margin-top:20px;text-align:center;"><button onclick="closeModal();showNeitiandiModal();" class="sbtn-lg">返回</button></div></div>`;

    const modal = document.createElement('div');
    modal.className = 'customModal';
    modalZIndexCounter += 2;
    modal.style.cssText = 'position:fixed;top:0;left:0;width:100%;height:100%;background:rgba(0,0,0,' + getModalOpacity() + ');display:flex;justify-content:center;align-items:center;z-index:' + modalZIndexCounter + ';backdrop-filter:blur(4px);-webkit-backdrop-filter:blur(4px);';
    modal.onclick = function(e) { if (e.target === modal) { closeModal(); showNeitiandiModal(); } };
    modal.innerHTML = formula;
    document.body.appendChild(modal);
}

// 显示内天地收益计算公式说明弹窗
/**
 * 显示内天地收益计算公式说明弹窗
 * 详细展示各类资源的收益计算公式
 * 包括：灵石、仙石、天材地宝、法则碎片、灵药
 * 收益倍率 = (log10(生灵数量+10))^3 / 3.3333
 */
function showNeitiandiIncomeFormula() {
    const monsterLevel = player.maxVoidVictoryLevel + 500;
    const count = $floor(player.shengLing || 0);
    const countStr = String(count);
    const lgVal = $log10($addBig(countStr, '10'));
    const lgCubed = $pow(lgVal, '3');
    const multiplier = $evalBig(`${lgCubed} / 3.3333`);
    
    // 用于显示的数值
    const multiplierNum = Number(multiplier);
    const lgValNum = Number(lgVal);
    const multiplierDisplay = Number.isFinite(multiplierNum) ? multiplierNum.toFixed(4) : '极大';
    const lgValDisplay = Number.isFinite(lgValNum) ? lgValNum.toFixed(6) : '极大';

    const spiritStoneFormula = `1.03^${monsterLevel} / min(128, 1.03^${monsterLevel}/1.02^${monsterLevel}) × 0.01 × ${multiplierDisplay}`;
    const immortalStoneFormula = `1.03^${monsterLevel} / min(128, 1.03^${monsterLevel}/1.02^${monsterLevel}) × 0.0002 × ${multiplierDisplay}`;
    const treasureFormula = `1.0339^${monsterLevel} × 10 × ${multiplierDisplay}`;
    const lawFragmentsFormula = `1.0339^${monsterLevel} × 5 × 0.05 × ${multiplierDisplay}`;

    const formula = `<div style="background:rgba(0,0,0,${getModalOpacity()});border:2px solid #fff;padding:25px;color:var(--text-color,#fff);font-family:monospace;width:90vw;max-width:500px;border-radius:4px;">
<div style="font-size:18px;color:#ff0;margin-bottom:15px;text-align:center;">【 内天地收益公式 】</div>
<div style="line-height:2;color:var(--text-color,#fff);">
<div>怪物等级 = 世界核心等级 + 500</div>
<div>= ${player.maxVoidVictoryLevel} + 500 = ${monsterLevel}</div>
<br>
<div>收益倍率 = (log10(灵族数量+10))^3 / 3.3333</div>
<div>= (log10(${count}+10))^3 / 3.3333</div>
<div>= (${lgValDisplay})^3 / 3.3333</div>
<div>= ${multiplierDisplay}</div>
<br>
<div>灵石 = ${spiritStoneFormula}</div>
<div>仙石 = ${immortalStoneFormula}</div>
<div>天材地宝 = ${treasureFormula}</div>
<div>法则碎片 = ${lawFragmentsFormula}</div>
<br>
<div style="color:var(--text-color-dim,#888);">灵药：阶数概率 = 10 × 1.035^怪物等级 / 10^阶数</div>
<div style="color:var(--text-color-dim,#888);">概率范围0.000001~0.01，概率>0.01不掉落</div>
</div>
<div style="margin-top:20px;text-align:center;"><button onclick="closeModal();showNeitiandiModal();" class="sbtn-lg">返回</button></div></div>`;

    const modal = document.createElement('div');
    modal.className = 'customModal';
    modalZIndexCounter += 2;
    modal.style.cssText = 'position:fixed;top:0;left:0;width:100%;height:100%;background:rgba(0,0,0,' + getModalOpacity() + ');display:flex;justify-content:center;align-items:center;z-index:' + modalZIndexCounter + ';backdrop-filter:blur(4px);-webkit-backdrop-filter:blur(4px);';
    modal.onclick = function(e) { if (e.target === modal) { closeModal(); showNeitiandiModal(); } };
    modal.innerHTML = formula;
    document.body.appendChild(modal);
}

// 显示道兵详细属性弹窗（等级、生命、攻击、防御、速度、攻击间隔）
function showDaoBingDetail2(level, hp, atk, def, speed, attackInterval) {
    const html = '<div style="background:rgba(0,0,0,' + getModalOpacity() + ');border:2px solid #fff;padding:25px;color:var(--text-color,#fff);font-family:monospace;width:90vw;max-width:500px;border-radius:4px;"><div style="font-size:18px;color:#ff0;margin-bottom:15px;text-align:center;">【 ' + formatNumber(level) + '级本源 】</div><div style="line-height:2;"><div>生命: <span style="color:var(--text-color,#fff);">' + formatNumber(hp) + '</span></div><div>攻击: <span style="color:var(--text-color,#fff);">' + formatNumber(atk) + '</span></div><div>防御: <span style="color:var(--text-color,#fff);">' + formatNumber(def) + '</span></div><div>攻速: <span style="color:var(--text-color,#fff);">' + speed.toFixed(1) + '</span> <span style="color:var(--text-color-dim,#888);">(间隔' + attackInterval + 'ms)</span></div><div>暴击率: <span style="color:var(--text-color,#fff);">5%</span></div><div>暴击伤害: <span style="color:var(--text-color,#fff);">200%</span></div><div style="color:var(--text-color-dim,#888);margin-top:8px;">无技能</div></div><div style="margin-top:20px;text-align:center;"><button onclick="closeModal()" class="sbtn-lg">返回</button></div></div>';
    
    const modal = document.createElement('div');
    modal.className = 'customModal';
    modalZIndexCounter += 2;
    modal.style.cssText = 'position:fixed;top:0;left:0;width:100%;height:100%;background:rgba(0,0,0,' + getModalOpacity() + ');display:flex;justify-content:center;align-items:center;z-index:' + modalZIndexCounter + ';backdrop-filter:blur(4px);-webkit-backdrop-filter:blur(4px);';
    modal.onclick = function(e) { if (e.target === modal) closeModal(); };
    modal.innerHTML = html;
    document.body.appendChild(modal);
}
